/**
 * Unit tests for queueProcessor.ts
 *
 * Tests exported helper functions: getQueueProcessorConfig,
 * isQueueProcessorRunning, pauseQueueProcessor, removeInFlightTask,
 * and resetBackoff.
 */

import { describe, it, beforeEach } from 'node:test';
import assert from 'node:assert/strict';

// Dynamically reload the module for test isolation — module-level state
// (yieldBackoffMs, yieldUntil, fileBackoffTasks, inFlightTasks, pollTimeoutId)
// is reset on each import.
let qpMod: typeof import('../../src/server/services/queueProcessor.js');

async function reloadModule(): Promise<typeof import('../../src/server/services/queueProcessor.js')> {
  const url = `../../src/server/services/queueProcessor.js?t=${Date.now()}_${Math.random().toString(36).slice(2)}`;
  return await import(url);
}

describe('queueProcessor', () => {
  beforeEach(async () => {
    qpMod = await reloadModule();
  });

  // ==============================
  // getQueueProcessorConfig
  // ==============================
  describe('getQueueProcessorConfig', () => {
    it('should return an object with expected keys', () => {
      const config = qpMod.getQueueProcessorConfig();
      assert.ok(typeof config === 'object');
      assert.ok('enabled' in config);
      assert.ok('pollInterval' in config);
      assert.ok('maxConcurrent' in config);
      assert.ok('isRunning' in config);
    });

    it('should return boolean for enabled', () => {
      const config = qpMod.getQueueProcessorConfig();
      assert.equal(typeof config.enabled, 'boolean');
    });

    it('should return number for pollInterval', () => {
      const config = qpMod.getQueueProcessorConfig();
      assert.equal(typeof config.pollInterval, 'number');
      assert.ok(config.pollInterval > 0, `Expected pollInterval > 0, got ${config.pollInterval}`);
    });

    it('should return number for maxConcurrent', () => {
      const config = qpMod.getQueueProcessorConfig();
      assert.equal(typeof config.maxConcurrent, 'number');
      assert.ok(config.maxConcurrent > 0, `Expected maxConcurrent > 0, got ${config.maxConcurrent}`);
    });

    it('should return false for isRunning when not started', () => {
      const config = qpMod.getQueueProcessorConfig();
      assert.equal(config.isRunning, false);
    });
  });

  // ==============================
  // isQueueProcessorRunning
  // ==============================
  describe('isQueueProcessorRunning', () => {
    it('should return false before startQueueProcessor is called', () => {
      assert.equal(qpMod.isQueueProcessorRunning(), false);
    });

    it('should return a boolean', () => {
      const result = qpMod.isQueueProcessorRunning();
      assert.equal(typeof result, 'boolean');
    });
  });

  // ==============================
  // pauseQueueProcessor
  // ==============================
  describe('pauseQueueProcessor', () => {
    it('should not throw when called (even without prior start)', () => {
      assert.doesNotThrow(() => qpMod.pauseQueueProcessor());
    });

    it('should leave isRunning as false after pause', () => {
      qpMod.pauseQueueProcessor();
      assert.equal(qpMod.isQueueProcessorRunning(), false);
    });
  });

  // ==============================
  // removeInFlightTask
  // ==============================
  describe('removeInFlightTask', () => {
    it('should not throw when removing a non-existent task', () => {
      assert.doesNotThrow(() => qpMod.removeInFlightTask('t-nonexistent'));
    });

    it('should be callable with any task ID string', () => {
      assert.doesNotThrow(() => qpMod.removeInFlightTask('t-1'));
      assert.doesNotThrow(() => qpMod.removeInFlightTask(''));
      assert.doesNotThrow(() => qpMod.removeInFlightTask('some-random-id'));
    });

    it('should be idempotent (multiple calls with same ID)', () => {
      assert.doesNotThrow(() => {
        qpMod.removeInFlightTask('t-abc');
        qpMod.removeInFlightTask('t-abc');
        qpMod.removeInFlightTask('t-abc');
      });
    });
  });

  // ==============================
  // resetBackoff
  // ==============================
  describe('resetBackoff', () => {
    it('should not throw when resetting a task that was never in backoff', () => {
      assert.doesNotThrow(() => qpMod.resetBackoff('t-unknown'));
    });

    it('should be callable with various task ID formats', () => {
      assert.doesNotThrow(() => qpMod.resetBackoff('t-1'));
      assert.doesNotThrow(() => qpMod.resetBackoff('task-xyz'));
      assert.doesNotThrow(() => qpMod.resetBackoff(''));
    });

    it('should be idempotent (multiple calls with same ID)', () => {
      assert.doesNotThrow(() => {
        qpMod.resetBackoff('t-idempotent');
        qpMod.resetBackoff('t-idempotent');
      });
    });
  });

  // ==============================
  // wakeQueueProcessor
  // ==============================
  describe('wakeQueueProcessor', () => {
    it('should not throw when called', () => {
      // With QUEUE_ENABLED='false' (default in test env), it should no-op.
      // Even with QUEUE_ENABLED, it should not throw.
      assert.doesNotThrow(() => qpMod.wakeQueueProcessor());
    });
  });

  // ==============================
  // Integration: pause + config state
  // ==============================
  describe('state consistency', () => {
    it('should report not running after pause', () => {
      qpMod.pauseQueueProcessor();
      assert.equal(qpMod.isQueueProcessorRunning(), false);
      const config = qpMod.getQueueProcessorConfig();
      assert.equal(config.isRunning, false);
    });
  });

  // ==============================
  // start/stop lifecycle (safe: stop/noop operations)
  // ==============================
  describe('start/stop lifecycle', () => {
    it('stopQueueProcessor should be safe to call without prior start', () => {
      assert.doesNotThrow(() => qpMod.stopQueueProcessor());
    });

    it('pause followed by stop should not throw', () => {
      assert.doesNotThrow(() => {
        qpMod.pauseQueueProcessor();
        qpMod.stopQueueProcessor();
      });
    });

    it('isQueueProcessorRunning returns boolean throughout lifecycle', () => {
      assert.equal(typeof qpMod.isQueueProcessorRunning(), 'boolean');
      qpMod.pauseQueueProcessor();
      assert.equal(typeof qpMod.isQueueProcessorRunning(), 'boolean');
    });
  });
});

import { getQueuedTasks, getAllTasks, getTask, getRunningTasksCount, updateTask } from './store.js';
import { executeFullWorkflow, executeQuickTask, executeGoalWorkflow, executeFromDeclare, isWorkflowRunning } from './workflow.js';
import { isAgentRunning } from './runner.js';
import { wouldConflict } from './leaseManager.js';
import { internalEvents, TASK_COMPLETED, LEASE_RELEASED } from './internalEvents.js';
import { prioritizeQueue } from './prioritizer.js';
import { engineConfig, refreshEngineConfig } from './engineConfig.js';
import type { Task } from '../../types/index.js';

const QUEUE_ENABLED = process.env.QUEUE_ENABLED !== 'false';

const YIELD_BACKOFF_INITIAL_MS = 2000;
const YIELD_BACKOFF_MULTIPLIER = 2;
const YIELD_BACKOFF_MAX_MS = 60_000;

/** Per-task exponential backoff delay (ms) for the next retry after a lease conflict */
const yieldBackoffMs = new Map<string, number>();
/** Per-task earliest timestamp (ms) at which the task may be retried */
const yieldUntil = new Map<string, number>();
/** Maps filePath → Set<taskId> of tasks currently in backoff waiting for that file.
 *  Populated when a task yields with `lease-conflict:<filePath>`. Cleared when the
 *  file is released (via handleLeaseReleased) or the task is dispatched. */
const fileBackoffTasks = new Map<string, Set<string>>();
/** Persistent set of task IDs dispatched in any poll cycle whose workflow has not yet
 * committed to a non-queued status. Prevents cross-cycle re-admission during the async
 * setup window between dispatch and the first status transition. */
const inFlightTasks = new Set<string>();

let pollTimeoutId: ReturnType<typeof setTimeout> | null = null;
let isProcessing = false;

/**
 * Check if we can process another task (concurrency limit check)
 */
async function canProcessTask(): Promise<boolean> {
  const runningCount = await getRunningTasksCount();
  return runningCount < engineConfig.maxConcurrentTasks;
}

/**
 * Process the queue - check for tasks and start execution if slots available.
 * Loops through queued tasks, skipping those that have exceeded maxYieldCount.
 */
async function processQueue(): Promise<void> {
  // Prevent concurrent processing
  if (isProcessing) {
    return;
  }

  isProcessing = true;

  try {
    await refreshEngineConfig();

    // Check if we can process more tasks
    if (!(await canProcessTask())) {
      return;
    }

    // Check if any agent is already running (legacy check for maxConcurrentTasks=1)
    if (engineConfig.maxConcurrentTasks <= 1 && isAgentRunning()) {
      return;
    }

    // Get all queued tasks
    const queuedTasks = await getQueuedTasks();
    if (queuedTasks.length === 0) {
      return;
    }

    // Dependency-aware re-prioritization: elevate tasks on the critical path
    const allTasks = await getAllTasks();
    const prioritizedTasks = prioritizeQueue(queuedTasks, allTasks);

    // Try each queued task until we find one we can start or run out of tasks
    for (const nextTask of prioritizedTasks) {
      // Re-check capacity before each task, including in-flight starts from this and prior cycles
      const runningCount = await getRunningTasksCount();
      if (runningCount + inFlightTasks.size >= engineConfig.maxConcurrentTasks) {
        break;
      }

      // Skip if workflow already running
      if (isWorkflowRunning(nextTask.id)) {
        continue;
      }

      // Skip if already dispatched in a prior poll cycle (cross-cycle re-admission guard)
      if (inFlightTasks.has(nextTask.id)) {
        continue;
      }

      // Skip tasks that are within their exponential backoff window
      if (Date.now() < (yieldUntil.get(nextTask.id) ?? 0)) {
        continue;
      }

      // Check yield count - transition tasks that have yielded too many times to todo
      // so they are visible on the board instead of silently starving in the queue.
      if (nextTask.yieldCount && nextTask.yieldCount >= engineConfig.maxYieldCount) {
        console.warn(`[QueueProcessor] Task ${nextTask.id} exceeded max yield count (${engineConfig.maxYieldCount}), transitioning to todo`);
        try {
          await updateTask(nextTask.id, {
            status: 'todo',
            yieldReason: 'cap-exceeded:max-yield-count',
          });
        } catch (err) {
          console.warn('[QueueProcessor] Failed to transition cap-exceeded task:', err instanceof Error ? err.message : 'Unknown error');
        }
        inFlightTasks.delete(nextTask.id);
        continue;
      }

      // Check retry count - transition tasks that have failed too many times to todo
      if ((nextTask.retryCount ?? 0) >= engineConfig.maxExecutionRetries) {
        console.warn(`[QueueProcessor] Task ${nextTask.id} exceeded max execution retries (${engineConfig.maxExecutionRetries}), transitioning to todo`);
        try {
          await updateTask(nextTask.id, {
            status: 'todo',
            yieldReason: 'cap-exceeded:max-execution-retries',
          });
        } catch (err) {
          console.warn('[QueueProcessor] Failed to transition cap-exceeded task:', err instanceof Error ? err.message : 'Unknown error');
        }
        inFlightTasks.delete(nextTask.id);
        continue;
      }

      // Detect the first exclusive file currently held by another task
      const exclusiveFiles = nextTask.declaredFiles?.exclusive ?? [];
      let conflictingFile: string | null = null;
      for (const filePath of exclusiveFiles) {
        if (wouldConflict(filePath, nextTask.id)) {
          conflictingFile = filePath;
          break;
        }
      }

      if (conflictingFile !== null) {
        // Compute and record exponential backoff
        const prevBackoff = yieldBackoffMs.get(nextTask.id) ?? (YIELD_BACKOFF_INITIAL_MS / YIELD_BACKOFF_MULTIPLIER);
        const nextBackoff = Math.min(prevBackoff * YIELD_BACKOFF_MULTIPLIER, YIELD_BACKOFF_MAX_MS);
        yieldBackoffMs.set(nextTask.id, nextBackoff);
        yieldUntil.set(nextTask.id, Date.now() + nextBackoff);

        // Track file→backoff mapping for targeted reset on LEASE_RELEASED
        const fileSet = fileBackoffTasks.get(conflictingFile) ?? new Set<string>();
        fileSet.add(nextTask.id);
        fileBackoffTasks.set(conflictingFile, fileSet);

        // Set firstBlockedAt fairness timestamp if not already set for this contention
        const now = new Date().toISOString();
        const updates: Record<string, unknown> = { yieldReason: `lease-conflict:${conflictingFile}` };
        if (!nextTask.firstBlockedAt) {
          updates.firstBlockedAt = now;
        }

        const reason = `lease-conflict:${conflictingFile}`;
        console.log(`[QueueProcessor] Task ${nextTask.id} yielding — ${reason} (backoff ${nextBackoff}ms)`);
        try {
          await updateTask(nextTask.id, updates);
        } catch (err) {
          console.warn('[QueueProcessor] Failed to persist yieldReason:', err instanceof Error ? err.message : 'Unknown error');
        }
        // Continue scanning — do not wait for next poll cycle
        continue;
      }

      console.log(`[QueueProcessor] Starting task ${nextTask.id}: ${nextTask.title}`);

      // Clear any stale backoff state for this task before dispatching
      clearTaskBackoff(nextTask.id);

      // Mark as in-flight synchronously before any await so the cross-cycle guard
      // is effective during the async setup window between dispatch and the first
      // non-queued status transition.
      inFlightTasks.add(nextTask.id);

      // Reload the task from the board immediately before routing so that
      // resumeFromStep reflects the persisted state, not the snapshot loaded
      // at the start of the poll cycle (which may be stale).
      const freshTask = await getTask(nextTask.id);

      // Check task type and execute appropriate workflow
      if (nextTask.type === 'quick') {
        console.log(`[QueueProcessor] Task ${nextTask.id} is a quick task - skipping brief/plan stages`);
        await executeQuickTask(nextTask.id);
      } else if (nextTask.type === 'goal') {
        console.log(`[QueueProcessor] Task ${nextTask.id} is a goal task - running architect decomposition`);
        await executeGoalWorkflow(nextTask.id);
      } else if (freshTask?.resumeFromStep === 'declare' || freshTask?.resumeFromStep === 'execute') {
        console.log(`[QueueProcessor] Task ${nextTask.id} resuming from ${freshTask.resumeFromStep} step (skipping brief/plan)`);
        await executeFromDeclare(nextTask.id);
      } else {
        await executeFullWorkflow(nextTask.id);
      }

      // For single-task mode, only start one task per poll cycle
      if (engineConfig.maxConcurrentTasks <= 1) {
        break;
      }
    }

  } catch (error) {
    const err = error as Error;
    console.error('[QueueProcessor] Error processing queue:', err.message);
  } finally {
    isProcessing = false;
  }
}

/**
 * Wake the queue processor immediately — bypasses the polling interval.
 * Called when a task completes or leases are released so queued tasks
 * can proceed without waiting for the next poll tick.
 */
export function wakeQueueProcessor(): void {
  if (!QUEUE_ENABLED || isProcessing) {
    return;
  }
  console.log('[QueueProcessor] Woken by event');
  void processQueue();
}

/**
 * Clear all in-memory backoff state for a single task. Called when the task
 * is dispatched (lease acquired) or when its backoff is reset via LEASE_RELEASED.
 */
function clearTaskBackoff(taskId: string): void {
  yieldBackoffMs.delete(taskId);
  yieldUntil.delete(taskId);

  // Remove from all fileBackoffTasks entries
  for (const [filePath, taskSet] of fileBackoffTasks.entries()) {
    taskSet.delete(taskId);
    if (taskSet.size === 0) {
      fileBackoffTasks.delete(filePath);
    }
  }

  // Clear firstBlockedAt on the persisted task so it doesn't carry over
  // to the next contention. Fire-and-forget — best-effort.
  updateTask(taskId, { firstBlockedAt: null }).catch(err =>
    console.warn('[QueueProcessor] Failed to clear firstBlockedAt:', err instanceof Error ? err.message : 'Unknown error')
  );
}

/**
 * Reset all backoff state for a task — exported for external callers (e.g.,
 * manual re-queue) that need to clear in-memory backoff in addition to the
 * persisted counters reset by store.queueTask().
 */
export function resetBackoff(taskId: string): void {
  clearTaskBackoff(taskId);
}

/**
 * Handle LEASE_RELEASED events: for each released file, clear the backoff
 * window of any task that was waiting on it, so the next poll/wake cycle
 * can immediately attempt re-dispatch instead of skipping the waiter due to
 * an unexpired yieldUntil.
 */
function handleLeaseReleased(_releasingTaskId: string, releasedFiles: string[]): void {
  if (!releasedFiles || releasedFiles.length === 0) return;

  let cleared = 0;
  for (const filePath of releasedFiles) {
    const waitingTasks = fileBackoffTasks.get(filePath);
    if (!waitingTasks || waitingTasks.size === 0) continue;

    for (const taskId of waitingTasks) {
      clearTaskBackoff(taskId);
      cleared++;
    }
    fileBackoffTasks.delete(filePath);
  }

  if (cleared > 0) {
    console.log(`[QueueProcessor] LEASE_RELEASED: cleared backoff for ${cleared} task(s) across ${releasedFiles.length} file(s)`);
  }

  // Wake the queue processor after clearing backoffs so blocked tasks get a chance
  wakeQueueProcessor();
}

function schedulePoll(): void {
  pollTimeoutId = setTimeout(async () => {
    await processQueue();
    if (pollTimeoutId !== null) {
      schedulePoll();
    }
  }, engineConfig.queuePollIntervalMs);
}

/**
 * Start the queue processor polling loop
 */
export function startQueueProcessor(): void {
  if (!QUEUE_ENABLED) {
    console.log('[QueueProcessor] Queue processing is disabled (QUEUE_ENABLED=false)');
    return;
  }

  if (pollTimeoutId !== null) {
    console.log('[QueueProcessor] Queue processor already running');
    return;
  }

  console.log(`[QueueProcessor] Starting queue processor (poll: ${engineConfig.queuePollIntervalMs}ms, max concurrent: ${engineConfig.maxConcurrentTasks})`);

  // Subscribe to internal wake events
  internalEvents.on(TASK_COMPLETED, wakeQueueProcessor);
  internalEvents.on(LEASE_RELEASED, handleLeaseReleased);

  // Run immediately on start
  processQueue();

  // Set up recursive polling
  schedulePoll();
}

/**
 * Stop the queue processor polling loop
 */
export function stopQueueProcessor(): void {
  if (pollTimeoutId !== null) {
    clearTimeout(pollTimeoutId);
    pollTimeoutId = null;

    // Unsubscribe internal wake event listeners
    internalEvents.off(TASK_COMPLETED, wakeQueueProcessor);
    internalEvents.off(LEASE_RELEASED, handleLeaseReleased);

    console.log('[QueueProcessor] Queue processor stopped');
  }
}

/**
 * Pause the queue processor (called by the kill switch after max retries).
 */
export function pauseQueueProcessor(): void {
  stopQueueProcessor();
  console.log('[QueueProcessor] Queue paused by kill switch');
}

/**
 * Check if queue processor is running
 */
export function isQueueProcessorRunning(): boolean {
  return pollTimeoutId !== null;
}

/**
 * Remove a task from the inFlightTasks set once its workflow has committed to a
 * non-queued status. Called by workflow.ts on every status-transition exit path
 * (including yield-back-to-queued, error, success, and stop) so no entries leak.
 */
export function removeInFlightTask(taskId: string): void {
  inFlightTasks.delete(taskId);
}

/**
 * Get queue processor configuration
 */
export function getQueueProcessorConfig(): {
  enabled: boolean;
  pollInterval: number;
  maxConcurrent: number;
  isRunning: boolean;
} {
  return {
    enabled: QUEUE_ENABLED,
    pollInterval: engineConfig.queuePollIntervalMs,
    maxConcurrent: engineConfig.maxConcurrentTasks,
    isRunning: isQueueProcessorRunning(),
  };
}

/**
 * Get the position of a task in the queue (1-indexed)
 * Returns 0 if the task is not in the queue
 */
export async function getQueuePosition(taskId: string): Promise<number> {
  const queuedTasks = await getQueuedTasks();
  const index = queuedTasks.findIndex(t => t.id === taskId);
  return index === -1 ? 0 : index + 1;
}

import { readFile, writeFile, mkdir, rename, copyFile } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import type { Board, Task, TaskStatus, TaskPriority, CreateTaskInput, UpdateTaskInput, WorkflowStep } from '../../types/index.js';
import { getWorkspacePath, getFormicDir, getBoardPath } from '../utils/paths.js';
import { createTaskDocsFolder, deleteTaskDocsFolder } from './taskDocs.js';
import {
  checkBootstrapRequired,
  createBootstrapTask,
  BOOTSTRAP_TASK_ID,
  BOOTSTRAP_TASK_SLUG,
} from './bootstrap.js';
import { copySkillsToWorkspace } from './skills.js';
import { calculateTaskProgress, loadSubtasks, getCompletionStats } from './subtasks.js';
import { releaseLeases } from './leaseManager.js';
import { broadcastDependencyResolved, broadcastToTask } from './boardNotifier.js';
import { internalEvents, TASK_CREATED, TASK_QUEUED, BOARD_UPDATE, TASK_UPDATED, TASK_STAGE_CHANGED } from './internalEvents.js';

/** Async write mutex — serializes all saveBoard() calls to prevent concurrent write corruption */
let saveLock: Promise<void> = Promise.resolve();

/**
 * Get project name from workspace folder name
 */
function getProjectNameFromWorkspace(): string {
  const workspacePath = getWorkspacePath();
  return path.basename(workspacePath) || 'My Project';
}

/**
 * Create a default board structure
 */
function createDefaultBoard(): Board {
  return {
    meta: {
      projectName: getProjectNameFromWorkspace(),
      repoPath: getWorkspacePath(),
      createdAt: new Date().toISOString(),
    },
    tasks: [],
  };
}

/**
 * Ensure the .formic directory exists in workspace
 */
async function ensureFormicDir(): Promise<void> {
  const formicDir = getFormicDir();
  if (!existsSync(formicDir)) {
    await mkdir(formicDir, { recursive: true });
  }
}

/** All valid TaskStatus values for runtime validation (mirrors the TaskStatus union type) */
export const VALID_TASK_STATUSES: string[] = [
  'todo', 'queued', 'briefing', 'planning', 'declaring', 'running',
  'architecting', 'verifying', 'review', 'done', 'blocked',
];

/** All valid TaskPriority values for runtime validation (mirrors the TaskPriority union type) */
export const VALID_TASK_PRIORITIES: string[] = ['low', 'medium', 'high'];

/**
 * Runtime type guard that validates the structural integrity of a parsed Board object.
 * Follows the validateToolManifest() pattern from tools.ts.
 */
export function validateBoard(board: unknown): board is Board {
  if (typeof board !== 'object' || board === null) return false;
  const b = board as Record<string, unknown>;

  // Validate meta
  if (typeof b.meta !== 'object' || b.meta === null) return false;
  const meta = b.meta as Record<string, unknown>;
  if (typeof meta.projectName !== 'string') return false;
  if (typeof meta.repoPath !== 'string') return false;
  if (typeof meta.createdAt !== 'string') return false;

  // Validate tasks array
  if (!Array.isArray(b.tasks)) return false;

  // Validate each task entry
  for (const task of b.tasks) {
    if (typeof task !== 'object' || task === null) return false;
    const t = task as Record<string, unknown>;
    if (typeof t.id !== 'string' || t.id.length === 0) return false;
    if (typeof t.title !== 'string' || t.title.length === 0) return false;
    if (typeof t.status !== 'string' || !VALID_TASK_STATUSES.includes(t.status)) return false;
    if (typeof t.priority !== 'string' || !VALID_TASK_PRIORITIES.includes(t.priority)) return false;
    if (typeof t.context !== 'string') return false;
    if (typeof t.docsPath !== 'string') return false;
    if (!Array.isArray(t.agentLogs)) return false;
  }

  return true;
}

/**
 * Load the board from workspace/.formic/board.json
 *
 * If board.json is corrupted or fails validation:
 * 1. Archives the corrupted file to .formic/board.json.corrupted.{timestamp}
 * 2. Attempts restoration from .formic/board.json.backup
 * 3. Falls back to a fresh default board if no valid backup exists
 */
export async function loadBoard(): Promise<Board> {
  await ensureFormicDir();

  const boardPath = getBoardPath();

  if (!existsSync(boardPath)) {
    const defaultBoard = createDefaultBoard();
    await saveBoard(defaultBoard);
    return defaultBoard;
  }

  const data = await readFile(boardPath, 'utf-8');

  try {
    const parsed: unknown = JSON.parse(data);

    if (!validateBoard(parsed)) {
      throw new Error('Board validation failed — structural integrity check did not pass');
    }

    return parsed;
  } catch (error) {
    const errMsg = error instanceof Error ? error.message : 'Unknown error';
    const timestamp = new Date().toISOString().replace(/:/g, '-');
    const archivePath = path.join(getFormicDir(), `board.json.corrupted.${timestamp}`);

    // Archive the corrupted file for debugging
    try {
      await copyFile(boardPath, archivePath);
    } catch (archiveErr) {
      console.error(`[Store] Failed to archive corrupted board.json: ${archiveErr instanceof Error ? archiveErr.message : 'Unknown error'}`);
    }

    console.error(`[Store] board.json is corrupted (${errMsg}), archived to ${path.basename(archivePath)}`);

    // Attempt backup restoration
    const backupPath = path.join(getFormicDir(), 'board.json.backup');
    if (existsSync(backupPath)) {
      try {
        const backupData = await readFile(backupPath, 'utf-8');
        const backupParsed: unknown = JSON.parse(backupData);

        if (validateBoard(backupParsed)) {
          console.warn('[Store] board.json corrupted — restored from backup');
          await saveBoard(backupParsed);
          return backupParsed;
        }

        console.warn('[Store] board.json.backup exists but failed validation');
      } catch (backupErr) {
        console.warn(`[Store] board.json.backup is also corrupted: ${backupErr instanceof Error ? backupErr.message : 'Unknown error'}`);
      }
    }

    // Last resort: create fresh default board
    console.warn(`[Store] board.json corrupted — archived to board.json.corrupted.${timestamp}, created fresh board`);
    const defaultBoard = createDefaultBoard();
    await saveBoard(defaultBoard);
    return defaultBoard;
  }
}

/**
 * Get the board with bootstrap status and auto-create bootstrap task if needed
 * Also copies bundled skills to workspace on first access
 */
export async function getBoardWithBootstrap(): Promise<Board> {
  const board = await loadBoard();

  // Step 1: Copy skills to workspace (if not already present)
  // This happens BEFORE bootstrap check so skills are available for all tasks
  await copySkillsToWorkspace();

  // Step 2: Check bootstrap status
  const bootstrapStatus = checkBootstrapRequired();

  // Check if bootstrap task already exists
  const hasBootstrapTask = board.tasks.some(t => t.id === BOOTSTRAP_TASK_ID);

  // If bootstrap is required and no bootstrap task exists, create one
  if (bootstrapStatus.required && !hasBootstrapTask) {
    const bootstrapTask = await createBootstrapTask();

    // Create the documentation folder for bootstrap task
    await createTaskDocsFolder(BOOTSTRAP_TASK_ID, bootstrapTask.title, bootstrapTask.context);

    board.tasks.unshift(bootstrapTask); // Add to beginning of tasks
    await saveBoard(board);
  }

  // Step 3: Enrich tasks with calculated progress and manual subtask info
  const tasksWithProgress = await Promise.all(
    board.tasks.map(async (task) => {
      const enriched: typeof task & { hasManualSubtasks?: boolean } = {
        ...task,
        progress: await calculateTaskProgress(task),
        // Normalize self-healing fields for backward compatibility with tasks stored before these fields existed
        safePointCommit: task.safePointCommit ?? null,
        retryCount: task.retryCount ?? null,
        fixForTaskId: task.fixForTaskId ?? null,
      };

      // Check if task has subtasks requiring manual action (pending or skipped)
      const subtasks = await loadSubtasks(task.docsPath);
      if (subtasks) {
        const stats = getCompletionStats(subtasks);
        if (stats.pending > 0 || stats.skipped > 0) {
          enriched.hasManualSubtasks = true;
        }
      }

      return enriched;
    })
  );

  // Return board with bootstrap status and enriched tasks
  return {
    ...board,
    tasks: tasksWithProgress,
    bootstrapRequired: bootstrapStatus.required,
    guidelinesPath: bootstrapStatus.guidelinesPath,
  };
}

/**
 * Save the board to workspace/.formic/board.json
 * Uses atomic temp-file+rename, rolling backup, and async mutex.
 */
export async function saveBoard(board: Board): Promise<void> {
  // Validate before any disk I/O
  if (!validateBoard(board)) {
    console.error('[Store] Rejected invalid board write');
    throw new Error('[Store] Rejected invalid board write');
  }

  // Chain onto the mutex to serialize concurrent calls
  const resultPromise = saveLock.then(
    () => saveBoardInternal(board),
    () => saveBoardInternal(board)  // proceed even if previous save failed
  );
  // Keep chain alive regardless of success/failure so future saves aren't blocked
  saveLock = resultPromise.catch(() => {});

  return resultPromise;
}

async function saveBoardInternal(board: Board): Promise<void> {
  await ensureFormicDir();
  const boardPath = getBoardPath();
  const tmpPath = boardPath + '.tmp';
  const backupPath = boardPath + '.backup';

  // Rolling backup: copy current board.json → board.json.backup
  try {
    await copyFile(boardPath, backupPath);
  } catch (err) {
    console.warn('[Store] Could not create backup (may not exist yet):', err instanceof Error ? err.message : 'Unknown error');
  }

  // Atomic write: write to .tmp then rename
  try {
    await writeFile(tmpPath, JSON.stringify(board, null, 2), 'utf-8');
    await rename(tmpPath, boardPath);
    internalEvents.emit(BOARD_UPDATE, { board });
  } catch (error) {
    const err = error as Error;
    console.error('[Store] Failed to save board:', err.message);
    throw new Error(`[Store] Failed to save board: ${err.message}`);
  }
}

