/**
 * Load declared files from the task's declared-files.json
 */
async function loadDeclaredFiles(docsPath: string): Promise<{ exclusive: string[]; shared: string[] } | null> {
  const filePath = path.join(getWorkspacePath(), docsPath, 'declared-files.json');
  try {
    if (!existsSync(filePath)) {
      return null;
    }
    const content = await readFile(filePath, 'utf-8');
    const parsed = JSON.parse(content) as { exclusive?: string[]; shared?: string[] };
    return {
      exclusive: parsed.exclusive || [],
      shared: parsed.shared || [],
    };
  } catch (error) {
    console.warn('[Workflow] Failed to load declared-files.json:', error);
    return null;
  }
}

/**
 * Execute the declare step: run declare skill, parse output, acquire leases
 * Returns true if leases were acquired successfully, false if task should yield
 */
async function executeDeclareAndAcquireLeases(taskId: string, task: Task): Promise<boolean> {
  // Run the declare skill
  await updateTaskStatus(taskId, 'declaring', undefined, 'workflow.executeDeclareAndAcquireLeases');
  await updateWorkflowStep(taskId, 'declare');

  broadcastToTask(taskId, {
    type: 'stdout',
    data: `\n========== Starting DECLARE step ==========\n`,
    timestamp: new Date().toISOString(),
  });

  let declareSuccess: boolean;

  // Skip re-running the declare agent if declared-files.json already exists (e.g. on resume)
  const existingDeclared = await loadDeclaredFiles(task.docsPath);
  if (existingDeclared) {
    console.log(`[Workflow] declared-files.json already exists for task ${taskId}, skipping declare agent`);
    declareSuccess = true;
  } else {
    try {
      const skillResult = await loadSkillPrompt('declare', task);
      if (!skillResult.success) {
        console.log('[Workflow] Declare skill not found, skipping declaration');
        declareSuccess = true;
      } else {
        let pidPromise: Promise<void> | undefined;
        const resultPromise = new Promise<boolean>((resolve) => {
          const { child, pidPersisted } = runWorkflowStep(taskId, 'declare', skillResult.content, (success) => {
            resolve(success);
          });
          pidPromise = pidPersisted;

          if (child.pid) {
            activeWorkflows.set(taskId, { process: child, currentStep: 'declare' });
          }
        });
        // Await PID persistence so board.json has the correct PID while the process runs
        if (pidPromise) await pidPromise;
        declareSuccess = await resultPromise;
      }
    } catch {
      declareSuccess = true; // Skip on error — backwards compatible
    }
  }

  activeWorkflows.delete(taskId);

  if (!declareSuccess) {
    console.log(`[Workflow] Declare step failed for task ${taskId}`);
    return false;
  }

  // Parse declared-files.json
  const declaredFiles = await loadDeclaredFiles(task.docsPath);
  if (declaredFiles) {
    // Store declared files on the task
    const board = await loadBoard();
    const boardTask = board.tasks.find(t => t.id === taskId);
    if (boardTask) {
      boardTask.declaredFiles = declaredFiles;
      await saveBoard(board);
    }

    // Record file hashes for shared files (optimistic concurrency)
    if (declaredFiles.shared.length > 0) {
      await recordFileHashes(taskId, declaredFiles.shared, getWorkspacePath());
    }

    // Attempt to acquire leases
    const leaseResult = acquireLeases({
      taskId,
      exclusiveFiles: declaredFiles.exclusive,
      sharedFiles: declaredFiles.shared,
    });

    if (!leaseResult.granted) {
      console.log(`[Workflow] Lease acquisition failed for task ${taskId}, yielding`);
      broadcastToTask(taskId, {
        type: 'stdout',
        data: `\n[YIELD] Cannot acquire file leases - conflicts on: ${leaseResult.conflictingFiles.join(', ')}\n`,
        timestamp: new Date().toISOString(),
      });
      if (leaseResult.conflictingFiles.length > 0) {
        const blockedOnFile = leaseResult.conflictingFiles[0];
        recordWait(taskId, blockedOnFile);
        await preemptLease(taskId, blockedOnFile);
      }
      return false;
    }

    clearWait(taskId);
    broadcastToTask(taskId, {
      type: 'stdout',
      data: `\n[LEASES] Acquired ${leaseResult.leases.length} file lease(s)\n`,
      timestamp: new Date().toISOString(),
    });
  } else {
    console.log(`[Workflow] No declared-files.json found for task ${taskId}, proceeding without leases`);
  }

  return true;
}

/**
 * Run a single workflow step.
 *
 * Returns the child process and a `pidPersisted` promise that resolves once the
 * child's PID has been written to board.json via `updateTaskStatus`.  Callers
 * should `await pidPersisted` before proceeding so the PID is visible in the
 * API and cannot be lost to a concurrent board write.
 */
function runWorkflowStep(
  taskId: string,
  step: string,
  prompt: string,
  onComplete: (success: boolean) => void
): { child: ChildProcess; pidPersisted: Promise<void> } {
  console.log(`[Workflow] Starting ${step} step for task ${taskId}`);

  // Use agent adapter for CLI invocation
  const agentCommand = getAgentCommand();
  const agentArgs = buildAgentArgs(prompt);

  const child = spawn(agentCommand, agentArgs, {
    cwd: getWorkspacePath(),
    env: { ...process.env },
    stdio: ['ignore', 'pipe', 'pipe'],
  });

  // Persist child.pid to board.json so the OS process is identifiable for running tasks.
  // We read the task's current status and re-write it together with the PID in a single
  // updateTaskStatus call so the PID is set atomically with the status field.
  // Callers must `await pidPersisted` before proceeding to ensure the PID write completes
  // before any competing board writes.
  const pidPersisted: Promise<void> = (async () => {
    if (!child.pid) return;
    try {
      const currentTask = await getTask(taskId);
      if (currentTask) {
        await updateTaskStatus(taskId, currentTask.status, child.pid, 'workflow.process_spawned');
      }
    } catch (err) {
      console.warn(`[Workflow] Failed to persist PID ${child.pid} for task ${taskId}:`, err);
    }
  })();

  const logBuffer: string[] = [];
  let hasCompleted = false;

  // Set up timeout to kill hanging processes
  const timeout = setTimeout(() => {
    if (!hasCompleted) {
      console.log(`[Workflow] ${step} step timed out after ${engineConfig.stepTimeoutMs}ms, killing process`);
      broadcastToTask(taskId, {
        type: 'error',
        data: `[${step.toUpperCase()}] Step timed out after ${engineConfig.stepTimeoutMs / 1000}s`,
        timestamp: new Date().toISOString(),
      });
      child.kill('SIGTERM');
      setTimeout(() => {
        if (!hasCompleted) {
          child.kill('SIGKILL');
        }
      }, 5000);
    }
  }, engineConfig.stepTimeoutMs);

  child.on('error', async (err: NodeJS.ErrnoException) => {
    hasCompleted = true;
    clearTimeout(timeout);
    activeWorkflows.delete(taskId);

    const agentName = getAgentDisplayName();
    let errorMessage = err.message;
    if (err.code === 'ENOENT') {
      errorMessage = `Command '${agentCommand}' not found. Please ensure ${agentName} is installed.`;
    }

    console.log(`[Workflow] ${step} step error: ${errorMessage}`);
    await appendWorkflowLogs(taskId, step, [`Error: ${errorMessage}`]);

    broadcastToTask(taskId, {
      type: 'error',
      data: `[${step.toUpperCase()}] ${errorMessage}`,
      timestamp: new Date().toISOString(),
    });

    onComplete(false);
  });

  child.stdout?.on('data', (data: Buffer) => {
    const text = data.toString();
    const lines = text.split('\n').filter(line => line.length > 0);
    logBuffer.push(...lines);

    // Send raw text without per-chunk prefix - the step context is shown in the UI header
    broadcastToTask(taskId, {
      type: 'stdout',
      data: text,
      timestamp: new Date().toISOString(),
    });
  });

  child.stderr?.on('data', (data: Buffer) => {
    const text = data.toString();
    const lines = text.split('\n').filter(line => line.length > 0);
    logBuffer.push(...lines);

    // Send raw text without per-chunk prefix - the step context is shown in the UI header
    broadcastToTask(taskId, {
      type: 'stderr',
      data: text,
      timestamp: new Date().toISOString(),
    });
  });

  child.on('close', async (code) => {
    hasCompleted = true;
    clearTimeout(timeout);

    console.log(`[Workflow] ${step} step completed with code ${code}`);
    await appendWorkflowLogs(taskId, step, logBuffer);

    broadcastToTask(taskId, {
      type: 'exit',
      data: `[${step.toUpperCase()}] Step completed with code ${code}`,
      timestamp: new Date().toISOString(),
    });

    onComplete(code === 0);
  });

  return { child, pidPersisted };
}

/**
 * Run a single iteration of the execute step and return success status
 */
async function runExecuteIteration(
  taskId: string,
  prompt: string
): Promise<boolean> {
  let pidPromise: Promise<void> | undefined;
  const resultPromise = new Promise<boolean>((resolve) => {
    const { child, pidPersisted } = runWorkflowStep(taskId, 'execute', prompt, (success) => {
      resolve(success);
    });
    pidPromise = pidPersisted;

    if (child.pid) {
      activeWorkflows.set(taskId, { process: child, currentStep: 'execute' });
    }
  });

  // Await PID persistence so board.json has the correct PID before the process completes
  if (pidPromise) {
    await pidPromise;
  }

  return resultPromise;
}

/**
 * Execute with iterative completion checking (Ralph Wiggum style)
 * Continues running until all subtasks are complete, max iterations reached,
 * or progress has stalled (no new subtasks completed for consecutive iterations)
 */
async function executeWithIterativeLoop(
  taskId: string,
  task: Task
): Promise<{ success: boolean; iterations: number; allComplete: boolean }> {
  console.log(`[Workflow] Starting iterative execution for task ${taskId}`);
  const guidelines = await loadProjectGuidelines();
  let iteration = 1;
  let allComplete = false;
  let previousCompletedCount = 0;
  let stalledIterations = 0;
  const STALL_THRESHOLD = 2; // Stop after 2 iterations with no progress

  // Broadcast start of iterative execution
  broadcastToTask(taskId, {
    type: 'stdout',
    data: `\n========== Starting EXECUTE step (iterative mode, max ${engineConfig.maxExecuteIterations} iterations) ==========\n`,
    timestamp: new Date().toISOString(),
  });

  try {

  while (iteration <= engineConfig.maxExecuteIterations && !allComplete) {
    console.log(`[Workflow] Execute iteration ${iteration}/${engineConfig.maxExecuteIterations} for task ${taskId}`);

    // Broadcast iteration start
    broadcastToTask(taskId, {
      type: 'stdout',
      data: `\n----- Execute Iteration ${iteration}/${engineConfig.maxExecuteIterations} -----\n`,
      timestamp: new Date().toISOString(),
    });

    // Build prompt based on iteration
    let prompt: string;
    if (iteration === 1) {
      // First iteration uses standard execute prompt
      prompt = buildExecutePrompt(task, guidelines, `http://localhost:${getBoundPort()}`);
    } else {
      // Subsequent iterations include feedback about incomplete subtasks
      const subtasks = await loadSubtasks(task.docsPath);
      const incompleteInfo = subtasks
        ? formatIncompleteSubtasksForPrompt(subtasks)
        : 'Unable to load subtasks.json - please check the file exists and is valid JSON.';
      prompt = buildIterativeExecutePrompt(task, guidelines, iteration, incompleteInfo, `http://localhost:${getBoundPort()}`);
    }

    // Run this iteration
    const success = await runExecuteIteration(taskId, prompt);
    activeWorkflows.delete(taskId);

    if (!success) {
      // Iteration failed - stop the loop
      console.log(`[Workflow] Execute iteration ${iteration} failed`);
      return { success: false, iterations: iteration, allComplete: false };
    }

    // Small delay to ensure file system has flushed
    await new Promise(resolve => setTimeout(resolve, 500));

    // Check subtasks completion after this iteration
    console.log(`[Workflow] Checking subtasks for task ${taskId}, docsPath: ${task.docsPath}`);
    const subtasks = await loadSubtasks(task.docsPath);
    if (subtasks) {
      const stats = getCompletionStats(subtasks);
      allComplete = isAllComplete(subtasks);

      // Log detailed status for debugging
      const statusCounts = subtasks.subtasks.reduce((acc, s) => {
        acc[s.status] = (acc[s.status] || 0) + 1;
        return acc;
      }, {} as Record<string, number>);
      console.log(`[Workflow] Subtask statuses: ${JSON.stringify(statusCounts)}`);

      // Broadcast completion status
      broadcastToTask(taskId, {
        type: 'stdout',
        data: `\n[Subtasks] Completion: ${stats.completed}/${stats.total} (${stats.percentage}%)\n`,
        timestamp: new Date().toISOString(),
      });

      console.log(`[Workflow] Subtask completion after iteration ${iteration}: ${stats.completed}/${stats.total} (${stats.percentage}%), allComplete=${allComplete}`);

      // Stall detection: check if progress was made this iteration
      if (stats.completed === previousCompletedCount && iteration > 1) {
        stalledIterations++;
        console.log(`[Workflow] No progress made in iteration ${iteration}. Stalled iterations: ${stalledIterations}/${STALL_THRESHOLD}`);

        if (stalledIterations >= STALL_THRESHOLD) {
          // Progress has stalled - likely manual testing subtasks remaining
          broadcastToTask(taskId, {
            type: 'stdout',
            data: `\n[INFO] No progress for ${STALL_THRESHOLD} iterations. Remaining subtasks likely require manual verification.\n`,
            timestamp: new Date().toISOString(),
          });
          broadcastToTask(taskId, {
            type: 'stdout',
            data: `[INFO] Moving to review. Please verify remaining subtasks manually.\n`,
            timestamp: new Date().toISOString(),
          });
          console.log(`[Workflow] Stall detected - stopping execution loop. Remaining subtasks need manual verification.`);
          break;
        }
      } else {
        // Progress was made, reset stall counter
        stalledIterations = 0;
      }
      previousCompletedCount = stats.completed;

      if (allComplete) {
        broadcastToTask(taskId, {
          type: 'stdout',
          data: `\n[SUCCESS] All subtasks complete! Task ready for review.\n`,
          timestamp: new Date().toISOString(),
        });
      }
    } else {
      // No subtasks.json found - treat as complete (backwards compatibility)
      console.log(`[Workflow] No subtasks.json found for task ${taskId}, treating as complete`);
      allComplete = true;
    }

    iteration++;
  }

  if (!allComplete && stalledIterations >= STALL_THRESHOLD) {
    // Stalled - this is expected for manual testing subtasks
    console.log(`[Workflow] Execution stalled after ${iteration - 1} iterations, moving to review for manual verification`);
  } else if (!allComplete && iteration > engineConfig.maxExecuteIterations) {
    broadcastToTask(taskId, {
      type: 'stdout',
      data: `\n[WARNING] Max iterations (${engineConfig.maxExecuteIterations}) reached. Some subtasks may be incomplete.\n`,
      timestamp: new Date().toISOString(),
    });
    console.log(`[Workflow] Max iterations reached, some subtasks incomplete`);
  }

  console.log(`[Workflow] Iterative execution completed for task ${taskId}: iterations=${iteration - 1}, allComplete=${allComplete}, stalled=${stalledIterations >= STALL_THRESHOLD}`);
  return { success: true, iterations: iteration - 1, allComplete };

  } finally {
    // No-op finally — lease renewal is now managed by the outer scope
    // (executeFullWorkflow / executeFromDeclare) which covers the full
    // lease-holding lifetime including verify and critic retries.
  }
}

/**
 * Runs all plugin-registered verifiers sequentially against the given task.
 * Each verifier is wrapped in its own try/catch for error isolation.
 * Returns aggregated pass/fail and any failure messages.
 */
async function executePluginVerifiers(taskId: string): Promise<{ allPassed: boolean; stderrLines: string[] }> {
  const results = await runVerifiers(taskId);
  const stderrLines: string[] = [];
  let allPassed = true;

  for (const result of results) {
    if (!result.passed) {
      allPassed = false;
      const msg = result.message ?? `Verifier '${result.verifierId}' failed`;
      stderrLines.push(`[Plugin Verifier '${result.verifierId}'] ${msg}`);
      console.warn(`[Workflow] Plugin verifier '${result.verifierId}' FAILED for task ${taskId}: ${msg}`);
    } else {
      console.warn(`[Workflow] Plugin verifier '${result.verifierId}' passed for task ${taskId}`);
    }
  }

  return { allPassed, stderrLines };
}

/**
 * Run the verification command against the workspace.
 * Always refreshes engineConfig first to pick up any changes made during execution.
 * Returns { success: true } immediately when skipVerify is true or verifyCommand is unset.
 */
async function executeVerifyStep(taskId: string): Promise<{ success: boolean; stderrLines: string[] }> {
  await refreshEngineConfig();

  if (engineConfig.skipVerify) {
    console.log('[Verifier] Skipping verification — toggle is OFF');
    const pluginResult = await executePluginVerifiers(taskId);
    return { success: pluginResult.allPassed, stderrLines: pluginResult.stderrLines };
  }

  if (!engineConfig.verifyCommand) {
    console.warn('[Verifier] Skipping verification — toggle is ON but verifyCommand is not configured. Set a verify command in Settings.');
    const pluginResult = await executePluginVerifiers(taskId);
    return { success: pluginResult.allPassed, stderrLines: pluginResult.stderrLines };
  }

  await updateTaskStatus(taskId, 'verifying', undefined, 'workflow.executeVerifyStep');
  await updateWorkflowStep(taskId, 'verify');

  broadcastToTask(taskId, {
    type: 'stdout',
    data: '\n========== Starting VERIFY step ==========\n',
    timestamp: new Date().toISOString(),
  });

  const parts = engineConfig.verifyCommand.split(' ');
  const cmd = parts[0];
  const args = parts.slice(1);
  const logBuffer: string[] = [];
  const stderrLines: string[] = [];

  let child: ReturnType<typeof spawn>;
  try {
    child = spawn(cmd, args, {
      cwd: getWorkspacePath(),
      env: { ...process.env },
      stdio: ['ignore', 'pipe', 'pipe'],
    });
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Unknown error';
    console.log(`[Verifier] Failed to spawn verification command: ${message}`);
    return { success: false, stderrLines: [message] };
  }

  // Persist verifier PID to board.json using updateTaskStatus for atomic status+PID writes.
  if (child.pid) {
    const currentTask = await getTask(taskId);
    if (currentTask) {
      await updateTaskStatus(taskId, currentTask.status, child.pid, 'workflow.executeVerifyStep.process_spawned').catch((err) => {
        console.warn(`[Verifier] Failed to persist PID ${child.pid} for task ${taskId}:`, err);
      });
    }
  }

  return new Promise((resolve) => {
    child.on('error', (err: NodeJS.ErrnoException) => {
      const message = err.message;
      console.log(`[Verifier] Failed to spawn verification command: ${message}`);
      resolve({ success: false, stderrLines: [message] });
    });

    child.stdout?.on('data', (data: Buffer) => {
      const text = data.toString();
      logBuffer.push(...text.split('\n').filter(l => l.length > 0));
      broadcastToTask(taskId, { type: 'stdout', data: text, timestamp: new Date().toISOString() });
    });

    child.stderr?.on('data', (data: Buffer) => {
      const text = data.toString();
      const lines = text.split('\n').filter(l => l.length > 0);
      logBuffer.push(...lines);
      stderrLines.push(...lines);
      broadcastToTask(taskId, { type: 'stderr', data: text, timestamp: new Date().toISOString() });
    });

    child.on('close', async (code) => {
      await appendWorkflowLogs(taskId, 'verify', logBuffer);

      broadcastToTask(taskId, {
        type: 'exit',
        data: `[VERIFY] Step completed with code ${code}`,
        timestamp: new Date().toISOString(),
      });

      const builtinPassed = code === 0;
      if (builtinPassed) {
        console.log('[Verifier] Verification PASSED');
      } else {
        console.log(`[Verifier] Verification FAILED (exit code ${code})`);
      }

      const pluginResult = await executePluginVerifiers(taskId);
      const allStderr = [...(builtinPassed ? [] : stderrLines), ...pluginResult.stderrLines];
      resolve({ success: builtinPassed && pluginResult.allPassed, stderrLines: allStderr });
    });
  });
}

/**
 * Execute a generic pipeline stage (primarily for plugin-contributed stages).
 * Sets task status, loads skill prompt, spawns agent or calls custom handler.
 * Returns true on success, false on failure.
 */
async function executeStage(taskId: string, stage: StageDescriptor): Promise<boolean> {
  const task = await getTask(taskId);
  if (!task) return false;

  await updateTaskStatus(taskId, stage.taskStatus, undefined, `workflow.executeStage.${stage.name}`);
  await updateWorkflowStep(taskId, stage.workflowStep as WorkflowStep);

  broadcastToTask(taskId, {
    type: 'stdout',
    data: `\n========== Starting ${stage.displayName} step ==========\n`,
    timestamp: new Date().toISOString(),
  });

  // Check for custom handler registered by a plugin
  const customHandler = getStageHandler(stage.name);
  if (customHandler) {
    try {
      await customHandler(taskId);
      return true;
    } catch (err) {
      console.warn(`[Workflow] Custom handler for stage '${stage.name}' failed:`, err instanceof Error ? err.message : 'Unknown error');
      await appendWorkflowLogs(taskId, stage.name, [`Error: ${err instanceof Error ? err.message : 'Unknown error'}`]);
      return false;
    }
  }

  // Default: load skill prompt and spawn agent
  const skillResult = await loadSkillPrompt(stage.skillName, task);
  if (!skillResult.success) {
    console.warn(`[Workflow] Skill '${stage.skillName}' not found for stage '${stage.name}', skipping`);
    return true;
  }

  let pidPromise: Promise<void> | undefined;
  const resultPromise = new Promise<boolean>((resolve) => {
    const { child, pidPersisted } = runWorkflowStep(taskId, stage.name, skillResult.content, (success) => {
      resolve(success);
    });
    pidPromise = pidPersisted;
    if (child.pid) {
      activeWorkflows.set(taskId, { process: child, currentStep: stage.workflowStep as WorkflowStep });
    }
  });

  if (pidPromise) await pidPromise;
  const success = await resultPromise;
  activeWorkflows.delete(taskId);
  return success;
}

/**
 * On verify failure: increment retryCount; create a Fix task or engage kill switch after 3 failures.
 */
async function executeCriticAndRetry(taskId: string, stderrLines: string[]): Promise<void> {
  const board = await loadBoard();
  const task = board.tasks.find(t => t.id === taskId);
  if (!task) return;

  const newRetryCount = (task.retryCount ?? 0) + 1;
  task.retryCount = newRetryCount;
  await saveBoard(board);
  console.log(`[Critic] Task ${taskId} retry count: ${newRetryCount}`);

  if (newRetryCount >= 3) {
    console.log(`[Critic] Kill switch activated for task ${taskId} after ${newRetryCount} failed verifications`);

    if (task.safePointCommit) {
      try {
        await execFileAsync('git', ['reset', '--hard', task.safePointCommit], { cwd: getWorkspacePath() });
        console.log(`[Critic] Workspace reverted to safe point ${task.safePointCommit}`);
      } catch (err) {
        console.warn('[Critic] Failed to revert to safe point:', err instanceof Error ? err.message : 'Unknown error');
      }
    } else {
      console.warn(`[Critic] No safePointCommit on task ${taskId}, skipping git reset`);
    }

    stopQueueProcessor();
    console.log('[Critic] Queue processor stopped by kill switch');

    broadcastKillSwitch(taskId);

    try {
      await broadcastToWorkspace(getWorkspacePath(), {
        chatId: '',
        text: `🚨 *Kill Switch Activated*\n\nTask \`${taskId}\` has failed verification 3 times.\nQueue paused. Workspace reverted to safe point.`,
        parseMode: 'markdown',
      });
    } catch (err) {
      console.warn('[Critic] Failed to send kill switch messaging notification:', err instanceof Error ? err.message : 'Unknown error');
    }

    await updateTaskStatus(taskId, 'todo', null, 'workflow.executeCriticAndRetry.kill_switch');
    return;
  }

  const errorSnippet = stderrLines.slice(-100).join('\n');
  const fixContext = `Auto-fix for task ${taskId}: ${task.title}\n\nVerification failed with the following error:\n\`\`\`\n${errorSnippet}\n\`\`\`\n\nPlease fix the code so that the verification command passes.\n\nOriginal task context:\n${task.context}`;

  const fixTask = await createTask({
    title: `Fix: ${task.title}`,
    context: fixContext,
    priority: 'high',
    type: 'quick',
    fixForTaskId: taskId,
  });
  await queueTask(fixTask.id);
  await updateTaskStatus(taskId, 'todo', null, 'workflow.executeCriticAndRetry.retry');
  broadcastBoardUpdate();
  console.log(`[Critic] Created fix task ${fixTask.id} for task ${taskId} (retry ${newRetryCount}/3)`);
}

// ==================== Reflection Step ====================

interface ReflectionEntry {
  type: 'pattern' | 'pitfall' | 'preference';
  content: string;
  relevance_tags: string[];
}

function isReflectionEntry(val: unknown): val is ReflectionEntry {
  if (typeof val !== 'object' || val === null) return false;
  const obj = val as Record<string, unknown>;
  return (
    (obj['type'] === 'pattern' || obj['type'] === 'pitfall' || obj['type'] === 'preference') &&
    typeof obj['content'] === 'string' &&
    Array.isArray(obj['relevance_tags']) &&
    (obj['relevance_tags'] as unknown[]).every((t) => typeof t === 'string')
  );
}

function parseReflectionOutput(output: string): ReflectionEntry[] {
  const match = output.match(/\[[\s\S]*\]/);
  if (!match) return [];
  try {
    const parsed = JSON.parse(match[0]) as unknown;
    if (!Array.isArray(parsed)) return [];
    return parsed.filter(isReflectionEntry);
  } catch {
    return [];
  }
}

/** Spawn the agent with a one-shot prompt and collect all output as a string. */
function runAgentForOutput(prompt: string): Promise<string> {
  return new Promise((resolve) => {
    const agentCommand = getAgentCommand();
    const agentArgs = buildAgentArgs(prompt);

    const child = spawn(agentCommand, agentArgs, {
      cwd: getWorkspacePath(),
      env: { ...process.env },
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    const chunks: string[] = [];

    child.stdout?.on('data', (data: Buffer) => {
      chunks.push(data.toString());
    });

    child.stderr?.on('data', (data: Buffer) => {
      chunks.push(data.toString());
    });

    const timeout = setTimeout(() => {
      child.kill('SIGTERM');
    }, 3 * 60 * 1000); // 3-minute timeout for reflection

    child.on('error', () => {
      clearTimeout(timeout);
      resolve(chunks.join(''));
    });

    child.on('close', () => {
      clearTimeout(timeout);
      resolve(chunks.join(''));
    });
  });
}

/**
 * Fire-and-forget reflection step: runs after a task transitions to 'review'.
 * Prompts the agent to extract learnings and pitfalls, saves them as memory entries,
 * and links the generated IDs back to the task via reflectionMemories.
 * All errors are swallowed so this never blocks task completion.
 */
async function runReflectionStep(taskId: string): Promise<void> {
  try {
    const task = await getTask(taskId);
    if (!task) return;

    const prompt = `You have just completed task "${task.title}".

Reflect on what was done and produce a JSON array of memory entries for future reference.
Each entry must have: type ('pattern'|'pitfall'|'preference'), content (string), relevance_tags (string array of file paths or keywords).

Output ONLY a valid JSON array, no markdown fences.
Example:
[
  { "type": "pattern", "content": "Always use writeFile with { recursive: true } when creating nested dirs", "relevance_tags": ["node:fs", "file-system"] },
  { "type": "pitfall", "content": "ESM imports require .js extension even for .ts source files", "relevance_tags": ["typescript", "esm", "imports"] }
]`;

    const output = await runAgentForOutput(prompt);
    const entries = parseReflectionOutput(output);

    const memoryIds: string[] = [];
    for (const entry of entries) {
      const memEntry = await addMemory({
        type: entry.type,
        content: entry.content,
        source_task: taskId,
        relevance_tags: entry.relevance_tags,
      });
      memoryIds.push(memEntry.id);
    }

    if (memoryIds.length > 0) {
      await updateTask(taskId, { reflectionMemories: memoryIds });
      broadcastBoardUpdate();
      console.log(`[Workflow] Reflection step saved ${memoryIds.length} memory entries for task ${taskId}`);
    }
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    console.warn(`[Workflow] Reflection step failed for task ${taskId}:`, message);
  }
}

/**
 * Fire-and-forget tool forge step: runs after a task transitions to 'review'.
 * Prompts the agent to identify reusable shell commands and registers them via addTool().
 * All errors are swallowed so this never blocks task completion.
 */
async function triggerToolForge(taskId: string): Promise<void> {
  try {
    const task = await getTask(taskId);
    if (!task) return;

    const prompt = `You have just completed task "${task.title}".

Review the work done and identify any shell commands that would be generically reusable across future tasks (e.g. test runners, linters, build scripts, deploy commands).

Output ONLY a valid JSON array of tool objects, no markdown fences. Each object must have: name (lowercase alphanumeric + hyphens only), description (string), command (string), created_by (string — use the task title).

If no reusable commands were identified, output an empty array: []

Example:
[
  { "name": "run-tests", "description": "Run the full test suite", "command": "npm test", "created_by": "${task.title}" }
]`;

    const output = await runAgentForOutput(prompt);
    const rawEntries = parseToolForgeOutput(output);
    const entries = rawEntries.filter((item): item is ToolForgeEntry => {
      if (isToolForgeEntry(item)) return true;
      console.warn('[Workflow] Skipped tool forge entry:', JSON.stringify(item));
      return false;
    });

    let forged = 0;
    for (const entry of entries) {
      try {
        await addTool(entry);
        forged++;
      } catch (err) {
        const msg = err instanceof Error ? err.message : 'Unknown error';
        console.warn(`[Workflow] Skipping tool '${entry.name}' for task ${taskId}: ${msg}`);
      }
    }

    if (forged > 0) {
      console.log(`[Workflow] Tool forge step registered ${forged} tool(s) for task ${taskId}`);
    }
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    console.warn(`[Workflow] Tool forge step failed for task ${taskId}:`, message);
  }
}

interface ToolForgeEntry {
  name: string;
  description: string;
  command: string;
  created_by: string;
}

function isToolForgeEntry(obj: unknown): obj is ToolForgeEntry {
  if (typeof obj !== 'object' || obj === null) return false;
  const o = obj as Record<string, unknown>;
  return (
    typeof o['name'] === 'string' &&
    typeof o['description'] === 'string' &&
    typeof o['command'] === 'string' &&
    typeof o['created_by'] === 'string'
  );
}

/**
 * Scan `text` for all top-level JSON arrays, correctly handling nested arrays
 * and string literals so bracket counting is not confused by their contents.
 */
function extractJsonArrays(text: string): string[] {
  const arrays: string[] = [];
  let i = 0;
  while (i < text.length) {
    if (text[i] === '[') {
      let depth = 0;
      let j = i;
      let inString = false;
      let escape = false;
      while (j < text.length) {
        const ch = text[j];
        if (escape) {
          escape = false;
        } else if (inString) {
          if (ch === '\\') escape = true;
          else if (ch === '"') inString = false;
        } else {
          if (ch === '"') inString = true;
          else if (ch === '[') depth++;
          else if (ch === ']') {
            depth--;
            if (depth === 0) {
              arrays.push(text.slice(i, j + 1));
              i = j + 1;
              break;
            }
          }
        }
        j++;
      }
      if (depth !== 0) {
        // Unbalanced bracket — skip past this opening bracket
        i++;
      }
    } else {
      i++;
    }
  }
  return arrays;
}

function parseToolForgeOutput(output: string): unknown[] {
  const candidates = extractJsonArrays(output);
  const results: unknown[] = [];
  for (const candidate of candidates) {
    try {
      const parsed = JSON.parse(candidate) as unknown;
      if (!Array.isArray(parsed)) {
        console.warn('[Workflow] Failed to parse tool forge array: not an array');
        continue;
      }
      results.push(...parsed);
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Unknown error';
      console.warn(`[Workflow] Failed to parse tool forge array: ${msg}`);
    }
  }
  return results;
}

/**
 * Execute a quick task (skips brief/plan stages, runs execute directly)
 * Quick tasks use task.context directly as the execution prompt
 */
/**
 * Execute a quick task: iterates over the active pipeline for quick tasks.
 * Quick tasks skip brief/plan stages and execute directly.
 */
export async function executeQuickTask(taskId: string): Promise<{ pid: number }> {
  const task = await getTask(taskId);
  if (!task) {
    throw new Error(`Task ${taskId} not found`);
  }
  await refreshEngineConfig();

  // Retrieve the active pipeline for quick tasks
  const pipeline = getActivePipeline('quick');
  console.warn(`[Workflow] Pipeline for quick task ${taskId}: ${pipeline.map((s: StageDescriptor) => s.name).join(' → ')}`);

  // Check if a workflow is already running
  if (activeWorkflows.has(taskId)) {
    throw new Error('A workflow is already running for this task');
  }
  stoppedWorkflows.delete(taskId); // Clear any stale stop flag from a previous workflow

  console.log(`[Workflow] Starting quick task execution for ${taskId}`);

  // Create a git safe-point commit before execution for rollback support
  await createSafePoint(taskId);

  // Load project guidelines
  const guidelines = await loadProjectGuidelines();

  // Build the quick execute prompt
  const prompt = buildQuickExecutePrompt(task, guidelines);

  // Update task status to first pipeline stage
  const firstStage = pipeline[0];
  if (firstStage) {
    await updateTaskStatus(taskId, firstStage.taskStatus, undefined, 'workflow.executeQuickTask.start');
    await updateWorkflowStep(taskId, firstStage.workflowStep as WorkflowStep);
  }

  // Broadcast start
  broadcastToTask(taskId, {
    type: 'stdout',
    data: `\n========== Starting QUICK TASK execution (no brief/plan) ==========\n`,
    timestamp: new Date().toISOString(),
  });

  const startPid = process.pid;

  // Iterate over pipeline stages
  (async () => {
    try {
      for (const stage of pipeline) {
        // Abort if stop was requested between stages
        if (stoppedWorkflows.has(taskId)) {
          stoppedWorkflows.delete(taskId);
          return;
        }

        switch (stage.name) {
          // ---- EXECUTE stage: run agent with quick prompt ----
          case 'execute': {
            let pidPromise: Promise<void> | undefined;
            const resultPromise = new Promise<boolean>((resolve) => {
              const { child, pidPersisted } = runWorkflowStep(taskId, 'execute', prompt, (success) => {
                resolve(success);
              });
              pidPromise = pidPersisted;

              if (child.pid) {
                activeWorkflows.set(taskId, { process: child, currentStep: 'execute' });
              }
            });

            // Await PID persistence before proceeding
            if (pidPromise) await pidPromise;

            const success = await resultPromise;

            activeWorkflows.delete(taskId);

            // Release any leases held by this task
            releaseLeases(taskId);

            if (!success) {
              await incrementRetryCount(taskId, 'workflow.executeQuickTask.failed');
              await updateTaskStatus(taskId, 'todo', null, 'workflow.executeQuickTask.failed');
              broadcastToTask(taskId, {
                type: 'error',
                data: `\n[FAILED] Quick task execution failed.\n`,
                timestamp: new Date().toISOString(),
              });
              return;
            }
            break;
          }

          // ---- VERIFY stage: run verify command, critic/retry on failure ----
          case 'verify': {
            const verifyResult = await executeVerifyStep(taskId);
            if (!verifyResult.success) {
              await executeCriticAndRetry(taskId, verifyResult.stderrLines);
              return;
            }
            break;
          }

          // ---- Plugin or unknown stage: use generic executeStage helper ----
          default: {
            const stageSuccess = await executeStage(taskId, stage);
            if (!stageSuccess) {
              await incrementRetryCount(taskId, `workflow.executeQuickTask.${stage.name}_failed`);
              await updateTaskStatus(taskId, 'todo', null, `workflow.executeQuickTask.${stage.name}_failed`);
              return;
            }
            break;
          }
        }
      }

      // All pipeline stages completed successfully — move to review
      await updateWorkflowStep(taskId, 'complete');
      await updateTaskStatus(taskId, 'review', null, 'workflow.executeQuickTask.success');
      broadcastTaskCompleted(taskId);
      { const completedTask = await getTask(taskId); internalEvents.emit(TASK_COMPLETED, { task: completedTask ? structuredClone(completedTask) : { id: taskId } }); }
      void runReflectionStep(taskId);
      void triggerToolForge(taskId);
      broadcastToTask(taskId, {
        type: 'stdout',
        data: `\n[SUCCESS] Quick task completed. Ready for review.\n`,
        timestamp: new Date().toISOString(),
      });
    } finally {
      removeInFlightTask(taskId);
    }
  })();

  return { pid: startPid };
}

/**
 * Execute a single workflow step (for manual step execution)
 */
export async function executeSingleStep(
  taskId: string,
  step: 'brief' | 'plan' | 'execute'
): Promise<{ success: boolean; pid: number }> {
  const task = await getTask(taskId);
  if (!task) {
    throw new Error(`Task ${taskId} not found`);
  }

  // Check if a workflow is already running
  if (activeWorkflows.has(taskId)) {
    throw new Error('A workflow step is already running for this task');
  }
  stoppedWorkflows.delete(taskId); // Clear any stale stop flag from a previous workflow

  // Build prompt based on step - try skill file first, fallback to hardcoded
  let prompt: string;
  let status: 'briefing' | 'planning' | 'running';

  switch (step) {
    case 'brief': {
      // Try loading from skill file first
      const skillResult = await loadSkillPrompt('brief', task);
      if (skillResult.success) {
        prompt = skillResult.content;
        console.log('[Workflow] Using skill file for brief step');
      } else {
        // Fallback to hardcoded prompt
        const guidelines = await loadProjectGuidelines();
        prompt = buildBriefPromptFallback(task, guidelines);
        console.log('[Workflow] Using fallback prompt for brief step');
      }
      status = 'briefing';
      break;
    }
    case 'plan': {
      // Try loading from skill file first
      const skillResult = await loadSkillPrompt('plan', task);
      if (skillResult.success) {
        prompt = skillResult.content;
        console.log('[Workflow] Using skill file for plan step');
      } else {
        // Fallback to hardcoded prompt
        const guidelines = await loadProjectGuidelines();
        prompt = buildPlanPromptFallback(task, guidelines);
        console.log('[Workflow] Using fallback prompt for plan step');
      }
      status = 'planning';
      break;
    }
    case 'execute': {
      // Execute step uses iterative loop with subtask completion checking
      console.log(`[Workflow] Starting execute step for task ${taskId}`);
      await updateTaskStatus(taskId, 'running', undefined, 'workflow.executeSingleStep.execute_start');
      await updateWorkflowStep(taskId, 'execute');

      // Abort if stop was requested before execute begins
      if (stoppedWorkflows.has(taskId)) {
        stoppedWorkflows.delete(taskId);
        return { success: false, pid: 0 };
      }

      let result: { success: boolean; allComplete: boolean; iterations: number };
      try {
        result = await executeWithIterativeLoop(taskId, task);
        console.log(`[Workflow] Execute step finished for task ${taskId}: success=${result.success}, allComplete=${result.allComplete}, iterations=${result.iterations}`);

        if (result.success && result.allComplete) {
          // All subtasks complete - move to review
          console.log(`[Workflow] All subtasks complete, transitioning task ${taskId} to review`);
          await updateWorkflowStep(taskId, 'complete');
          await updateTaskStatus(taskId, 'review', null, 'workflow.executeSingleStep.all_complete');
          broadcastTaskCompleted(taskId);
          { const completedTask = await getTask(taskId); internalEvents.emit(TASK_COMPLETED, { task: completedTask ? structuredClone(completedTask) : { id: taskId } }); }
          void runReflectionStep(taskId);
          void triggerToolForge(taskId);
        } else if (result.success && !result.allComplete) {
          // Max iterations reached but not all complete - still move to review with warning
          console.log(`[Workflow] Max iterations reached, transitioning task ${taskId} to review with incomplete subtasks`);
          await updateWorkflowStep(taskId, 'complete');
          await updateTaskStatus(taskId, 'review', null, 'workflow.executeSingleStep.max_iterations');
          broadcastTaskCompleted(taskId);
          { const completedTask = await getTask(taskId); internalEvents.emit(TASK_COMPLETED, { task: completedTask ? structuredClone(completedTask) : { id: taskId } }); }
          void runReflectionStep(taskId);
          void triggerToolForge(taskId);
        } else {
          // Execution failed
          console.log(`[Workflow] Execute step failed for task ${taskId}, reverting to todo`);
          await incrementRetryCount(taskId, 'workflow.executeSingleStep.execute_failed');
          await updateTaskStatus(taskId, 'todo', null, 'workflow.executeSingleStep.execute_failed');
        }
      } finally {
        releaseLeases(taskId);
        console.log(`[Workflow] Released leases for task ${taskId} (executeSingleStep)`);
      }

      return { success: result.success, pid: process.pid };
    }
  }

  // Update task status (for brief and plan steps)
  await updateTaskStatus(taskId, status!, undefined, 'workflow.executeSingleStep.step_start');
  await updateWorkflowStep(taskId, step);

  let pidPromise: Promise<void> | undefined;
  const resultPromise = new Promise<{ success: boolean; pid: number }>((resolve) => {
    const { child, pidPersisted } = runWorkflowStep(taskId, step, prompt!, async (success) => {
      activeWorkflows.delete(taskId);

      if (success) {
        // Update workflow step to next
        const nextStep: WorkflowStep = step === 'brief' ? 'plan' : 'execute';
        await updateWorkflowStep(taskId, nextStep);

        // Return to todo for manual steps
        await updateTaskStatus(taskId, 'todo', null, 'workflow.executeSingleStep.step_success');
      } else {
        // On failure, return to todo
        await incrementRetryCount(taskId, 'workflow.executeSingleStep.step_failed');
        await updateTaskStatus(taskId, 'todo', null, 'workflow.executeSingleStep.step_failed');
      }

      resolve({ success, pid: child.pid || 0 });
    });
    pidPromise = pidPersisted;

    if (child.pid) {
      activeWorkflows.set(taskId, { process: child, currentStep: step });
    }
  });

  // Await PID persistence so board.json has the correct PID before the process completes
  if (pidPromise) await pidPromise;

  return resultPromise;
}

/**
 * Execute the full workflow: iterates over the active pipeline for standard tasks.
 * Built-in stages (brief, plan, declare, execute, verify) use specialized handlers;
 * plugin-contributed stages use the generic executeStage helper.
 */
export async function executeFullWorkflow(taskId: string): Promise<{ pid: number }> {
  const task = await getTask(taskId);
  if (!task) {
    throw new Error(`Task ${taskId} not found`);
  }
  await refreshEngineConfig();

  // Retrieve the active pipeline for standard tasks
  const pipeline = getActivePipeline('standard');
  console.warn(`[Workflow] Pipeline for standard task ${taskId}: ${pipeline.map((s: StageDescriptor) => s.name).join(' → ')}`);

  // Check if a workflow is already running
  if (activeWorkflows.has(taskId)) {
    throw new Error('A workflow is already running for this task');
  }
  stoppedWorkflows.delete(taskId); // Clear any stale stop flag from a previous workflow

  // Helper to run brief/plan steps sequentially
  const runStep = async (step: 'brief' | 'plan' | 'execute'): Promise<boolean> => {
    const currentTask = await getTask(taskId);
    if (!currentTask) return false;

    let prompt: string;
    let status: 'briefing' | 'planning' | 'running';

    // Build prompt - try skill file first, fallback to hardcoded
    switch (step) {
      case 'brief': {
        const skillResult = await loadSkillPrompt('brief', currentTask);
        if (skillResult.success) {
          prompt = skillResult.content;
          console.log('[Workflow] Full workflow: Using skill file for brief step');
        } else {
          const guidelines = await loadProjectGuidelines();
          prompt = buildBriefPromptFallback(currentTask, guidelines);
          console.log('[Workflow] Full workflow: Using fallback for brief step');
        }
        status = 'briefing';
        break;
      }
      case 'plan': {
        const skillResult = await loadSkillPrompt('plan', currentTask);
        if (skillResult.success) {
          prompt = skillResult.content;
          console.log('[Workflow] Full workflow: Using skill file for plan step');
        } else {
          const guidelines = await loadProjectGuidelines();
          prompt = buildPlanPromptFallback(currentTask, guidelines);
          console.log('[Workflow] Full workflow: Using fallback for plan step');
        }
        status = 'planning';
        break;
      }
      case 'execute': {
        const guidelines = await loadProjectGuidelines();
        prompt = buildExecutePrompt(currentTask, guidelines, `http://localhost:${getBoundPort()}`);
        status = 'running';
        break;
      }
    }

    await updateTaskStatus(taskId, status, undefined, 'workflow.executeFullWorkflow.step_start');
    await updateWorkflowStep(taskId, step);

    broadcastToTask(taskId, {
      type: 'stdout',
      data: `\n========== Starting ${step.toUpperCase()} step ==========\n`,
      timestamp: new Date().toISOString(),
    });

    let pidPromise: Promise<void> | undefined;
    const resultPromise = new Promise<boolean>((resolve) => {
      const { child, pidPersisted } = runWorkflowStep(taskId, step, prompt, (success) => {
        resolve(success);
      });
      pidPromise = pidPersisted;

      if (child.pid) {
        activeWorkflows.set(taskId, { process: child, currentStep: step });
      }
    });

    // Await PID persistence so board.json has the correct PID before the process completes
    if (pidPromise) await pidPromise;

    return resultPromise;
  };

  // Start the workflow
  const startPid = process.pid; // Return server PID as reference

  // Set status to first stage immediately to prevent queue processor re-dispatch
  // during the async setup window (createSafePoint + skill loading).
  const firstStage = pipeline[0];
  if (firstStage) {
    await updateTaskStatus(taskId, firstStage.taskStatus, undefined, 'workflow.executeFullWorkflow.init');
  }

  // Run stages sequentially from the pipeline
  (async () => {
    let leasesHeld = false;
    let leaseRenewalTimer: ReturnType<typeof setInterval> | null = null;
    const LEASE_RENEWAL_INTERVAL_MS = 2 * 60 * 1000;
    try {
      // Create a git safe-point commit before execution for rollback support.
      // Guard against duplicate commits on re-entry (e.g. if resumeFromStep was
      // not persisted and the task re-enters executeFullWorkflow on a retry).
      // Capture safePointCommit BEFORE creating a new safe-point.
      // A null value means this is a fresh run (e.g. re-run from review) — never skip stages.
      const taskBeforeSafePoint = await getTask(taskId);
      const isReEntry = !!taskBeforeSafePoint?.safePointCommit;
      if (!taskBeforeSafePoint?.safePointCommit) {
        await createSafePoint(taskId);
      }

      // Resolve task docs directory for artifact checks
      const docsDir = path.join(getWorkspacePath(), task.docsPath);

      // Iterate over pipeline stages
      for (const stage of pipeline) {
        // Abort if stop was requested between stages
        if (stoppedWorkflows.has(taskId)) {
          stoppedWorkflows.delete(taskId);
          return;
        }

        switch (stage.name) {
          // ---- BRIEF stage: run agent with skill prompt, skip if artifact exists on re-entry ----
          case 'brief': {
            const skipBrief = isReEntry && await artifactExists(docsDir, 'README.md');
            if (skipBrief) {
              console.warn('[Workflow] Skipping brief step — README.md already exists');
              broadcastToTask(taskId, {
                type: 'stdout',
                data: '\n========== Skipping BRIEF step (README.md exists) ==========\n',
                timestamp: new Date().toISOString(),
              });
              // Transition through briefing→next stage so the board UI shows progress
              const nextIdx = pipeline.indexOf(stage) + 1;
              if (nextIdx < pipeline.length) {
                await updateTaskStatus(taskId, pipeline[nextIdx].taskStatus, undefined, 'workflow.executeFullWorkflow.brief_skipped');
              }
            } else {
              const briefSuccess = await runStep('brief');
              if (!briefSuccess) {
                activeWorkflows.delete(taskId);
                await incrementRetryCount(taskId, 'workflow.executeFullWorkflow.brief_failed');
                await updateTaskStatus(taskId, 'todo', null, 'workflow.executeFullWorkflow.brief_failed');
                return;
              }
            }
            break;
          }

          // ---- PLAN stage: run agent with skill prompt, skip if artifacts exist on re-entry ----
          case 'plan': {
            const skipPlan = isReEntry
              && await artifactExists(docsDir, 'PLAN.md')
              && await artifactExists(docsDir, 'subtasks.json');
            if (skipPlan) {
              console.warn('[Workflow] Skipping plan step — PLAN.md + subtasks.json already exist');
              broadcastToTask(taskId, {
                type: 'stdout',
                data: '\n========== Skipping PLAN step (PLAN.md + subtasks.json exist) ==========\n',
                timestamp: new Date().toISOString(),
              });
              const nextIdx = pipeline.indexOf(stage) + 1;
              if (nextIdx < pipeline.length) {
                await updateTaskStatus(taskId, pipeline[nextIdx].taskStatus, undefined, 'workflow.executeFullWorkflow.plan_skipped');
              }
            } else {
              const planSuccess = await runStep('plan');
              if (!planSuccess) {
                activeWorkflows.delete(taskId);
                await incrementRetryCount(taskId, 'workflow.executeFullWorkflow.plan_failed');
                await updateTaskStatus(taskId, 'todo', null, 'workflow.executeFullWorkflow.plan_failed');
                return;
              }
            }
            break;
          }

          // ---- DECLARE stage: run declare skill, parse output, acquire file leases ----
          case 'declare': {
            const currentTaskForDeclare = await getTask(taskId);
            if (!currentTaskForDeclare) {
              activeWorkflows.delete(taskId);
              await updateTaskStatus(taskId, 'todo', null, 'workflow.executeFullWorkflow.task_not_found');
              return;
            }

            const leasesAcquired = await executeDeclareAndAcquireLeases(taskId, currentTaskForDeclare);
            if (!leasesAcquired) {
              // Task needs to yield - mark resumeFromStep so retry skips brief+plan
              activeWorkflows.delete(taskId);
              const board = await loadBoard();
              const yieldTask = board.tasks.find(t => t.id === taskId);
              if (yieldTask) {
                yieldTask.yieldCount = (yieldTask.yieldCount || 0) + 1;
                yieldTask.resumeFromStep = 'declare';
                await saveBoard(board);
                const verifyTask = await getTask(taskId);
                console.log(`[Workflow] Task ${taskId} yielded at declare — resumeFromStep persisted: ${verifyTask?.resumeFromStep}`);
              }
              await updateTaskStatus(taskId, 'queued', null, 'workflow.executeFullWorkflow.declare_yield');
              return;
            }
            leasesHeld = true;
            // Start periodic lease renewal timer — covers the full lease-holding
            // lifetime (execute iterations, verify step, critic retries, collision
            // detection). Previously this was only inside executeWithIterativeLoop
            // and did not protect verify/critic phases.
            leaseRenewalTimer = setInterval(() => {
              renewLeases(taskId);
              console.log(`[Workflow] Periodic lease renewal for task ${taskId}`);
            }, LEASE_RENEWAL_INTERVAL_MS);
            break;
          }

          // ---- EXECUTE stage: iterative execution with subtask completion checking ----
          case 'execute': {
            const currentTask = await getTask(taskId);
            if (!currentTask) {
              activeWorkflows.delete(taskId);
              await updateTaskStatus(taskId, 'todo', null, 'workflow.executeFullWorkflow.task_not_found_post_declare');
              return;
            }

            internalEvents.emit(BEFORE_EXECUTE, { taskId, task: structuredClone(currentTask) });
            await updateTaskStatus(taskId, 'running', undefined, 'workflow.executeFullWorkflow.execute_start');
            await updateWorkflowStep(taskId, 'execute');

            const executeResult = await executeWithIterativeLoop(taskId, currentTask);
            activeWorkflows.delete(taskId);

            // Detect collisions on shared files BEFORE releasing leases
            if (currentTask.declaredFiles?.shared && currentTask.declaredFiles.shared.length > 0) {
              const conflicts = await detectCollisions(taskId, getWorkspacePath());
              if (conflicts.length > 0) {
                const board = await loadBoard();
                const conflictTask = board.tasks.find(t => t.id === taskId);
                if (conflictTask) {
                  conflictTask.fileConflicts = conflicts;
                  await saveBoard(board);
                }
                console.log(`[Workflow] File conflicts detected for task ${taskId}: ${conflicts.map(c => c.filePath).join(', ')}`);
              }
            }

            if (!executeResult.success) {
              internalEvents.emit(AFTER_EXECUTE, { taskId, task: structuredClone(currentTask), success: false });
              internalEvents.emit(TASK_FAILED, { taskId, task: structuredClone(currentTask), error: 'Full workflow execution failed' });
              const latestTask = await getTask(taskId);
              if (latestTask && latestTask.status === 'running') {
                await incrementRetryCount(taskId, 'workflow.executeFullWorkflow.execute_failed');
                await updateTaskStatus(taskId, 'todo', null, 'workflow.executeFullWorkflow.execute_failed');
              } else {
                console.warn(`[Workflow] Skipping status update for task ${taskId}: expected 'running' but found '${latestTask?.status ?? 'deleted'}'`);
              }
              return;
            }

            internalEvents.emit(AFTER_EXECUTE, { taskId, task: structuredClone(currentTask), success: true });
            break;
          }

          // ---- VERIFY stage: run verify command, critic/retry on failure ----
          case 'verify': {
            // Guard against stale status: check if watchdog has already re-queued the task
            const latestTask = await getTask(taskId);
            if (!latestTask || latestTask.status !== 'running') {
              console.warn(`[Workflow] Skipping verify for task ${taskId}: expected 'running' but found '${latestTask?.status ?? 'deleted'}'`);
              return;
            }

            const verifyResult = await executeVerifyStep(taskId);
            if (!verifyResult.success) {
              await executeCriticAndRetry(taskId, verifyResult.stderrLines);
              return;
            }
            break;
          }

          // ---- Plugin or unknown stage: use generic executeStage helper ----
          default: {
            const stageSuccess = await executeStage(taskId, stage);
            if (!stageSuccess) {
              await incrementRetryCount(taskId, `workflow.executeFullWorkflow.${stage.name}_failed`);
              await updateTaskStatus(taskId, 'todo', null, `workflow.executeFullWorkflow.${stage.name}_failed`);
              return;
            }
            break;
          }
        }
      }

      // All pipeline stages completed successfully — move to review
      await updateWorkflowStep(taskId, 'complete');
      await updateTaskStatus(taskId, 'review', null, 'workflow.executeFullWorkflow.verified');
      broadcastTaskCompleted(taskId);
      { const completedTask = await getTask(taskId); internalEvents.emit(TASK_COMPLETED, { task: completedTask ? structuredClone(completedTask) : { id: taskId } }); }
      void runReflectionStep(taskId);
      void triggerToolForge(taskId);
    } finally {
      // Stop the periodic lease renewal timer before releasing leases.
      if (leaseRenewalTimer !== null) clearInterval(leaseRenewalTimer);
      // Ensure leases are always released, even on unexpected exceptions.
      // Safe to call even if leases were already released (no-op in that case).
      if (leasesHeld) releaseLeases(taskId);
      removeInFlightTask(taskId);
    }
  })();

  return { pid: startPid };
}

/**
 * Resume a task that previously yielded at the declare step due to a lease conflict.
 * Skips brief and plan steps, jumping directly to declare + acquire leases and then execute.
 */
export async function executeFromDeclare(taskId: string): Promise<void> {
  stoppedWorkflows.delete(taskId); // Clear any stale stop flag from a previous workflow
  // Change status to 'declaring' immediately so the queue processor cannot re-dispatch this task
  // before the async IIFE begins (mirrors the 'briefing' guard in executeFullWorkflow).
  await updateTaskStatus(taskId, 'declaring', undefined, 'workflow.executeFromDeclare.init');

  (async () => {
    let leaseRenewalTimer: ReturnType<typeof setInterval> | null = null;
    const LEASE_RENEWAL_INTERVAL_MS = 2 * 60 * 1000;
    try {
      const currentTask = await getTask(taskId);
      if (!currentTask) {
        activeWorkflows.delete(taskId);
        await updateTaskStatus(taskId, 'todo', null, 'workflow.executeFromDeclare.task_not_found');
        return;
      }

      const leasesAcquired = await executeDeclareAndAcquireLeases(taskId, currentTask);
      if (!leasesAcquired) {
        // Still conflicted — re-queue with resumeFromStep preserved for the next retry
        activeWorkflows.delete(taskId);
        const board = await loadBoard();
        const yieldTask = board.tasks.find(t => t.id === taskId);
        if (yieldTask) {
          const newYieldCount = (yieldTask.yieldCount || 0) + 1;
          yieldTask.yieldCount = newYieldCount;
          yieldTask.resumeFromStep = 'declare';

          // Zombie lease detection: if we've retried enough times, check whether
          // the blocking task is still active. If not, force-release its leases.
          const ZOMBIE_YIELD_THRESHOLD = Math.max(3, Math.floor(engineConfig.maxYieldCount / 2));
          if (newYieldCount >= ZOMBIE_YIELD_THRESHOLD) {
            const exclusiveFiles = currentTask.declaredFiles?.exclusive ?? [];
            const zombieHolders = new Set<string>();
            for (const filePath of exclusiveFiles) {
              const holder = getExclusiveLeaseHolder(filePath);
              if (holder && holder !== taskId) {
                zombieHolders.add(holder);
              }
            }
            for (const holderId of zombieHolders) {
              const holderTask = await getTask(holderId);
              const holderStatus = holderTask?.status ?? 'unknown';
              if (holderStatus !== 'running' && holderStatus !== 'declaring' && !isWorkflowRunning(holderId)) {
                console.warn(`[Workflow] Force-releasing zombie leases held by task ${holderId} (status: ${holderStatus}) to unblock task ${taskId}`);
                releaseLeases(holderId);
              }
            }
          }

          await saveBoard(board);
          const verifyRetryTask = await getTask(taskId);
          console.log(`[Workflow] Task ${taskId} re-queued from declare retry — resumeFromStep persisted: ${verifyRetryTask?.resumeFromStep}, yieldCount: ${verifyRetryTask?.yieldCount}`);
        }
        await updateTaskStatus(taskId, 'queued', null, 'workflow.executeFromDeclare.declare_yield');
        return;
      }

      // Leases acquired — clear the resume marker so future retries (if any) start fresh
      const boardAfterLease = await loadBoard();
      const boardTask = boardAfterLease.tasks.find(t => t.id === taskId);
      if (boardTask) {
        boardTask.resumeFromStep = undefined;
        await saveBoard(boardAfterLease);
      }

      // Start periodic lease renewal timer — covers the full lease-holding
      // lifetime (execute iterations, verify step, critic retries, collision
      // detection). Previously this was only inside executeWithIterativeLoop
      // and did not protect verify/critic phases.
      leaseRenewalTimer = setInterval(() => {
        renewLeases(taskId);
        console.log(`[Workflow] Periodic lease renewal for task ${taskId}`);
      }, LEASE_RENEWAL_INTERVAL_MS);

      // Abort if stop was requested between declare and execute
      if (stoppedWorkflows.has(taskId)) {
        stoppedWorkflows.delete(taskId);
        releaseLeases(taskId);
        return;
      }

      const taskForExecution = await getTask(taskId);
      if (!taskForExecution) {
        activeWorkflows.delete(taskId);
        releaseLeases(taskId);
        await updateTaskStatus(taskId, 'todo', null, 'workflow.executeFromDeclare.task_not_found_post_declare');
        return;
      }

      try {
        internalEvents.emit(BEFORE_EXECUTE, { taskId, task: structuredClone(taskForExecution) });
        await updateTaskStatus(taskId, 'running', undefined, 'workflow.executeFromDeclare.execute_start');
        await updateWorkflowStep(taskId, 'execute');

        const executeResult = await executeWithIterativeLoop(taskId, taskForExecution);
        activeWorkflows.delete(taskId);

        if (taskForExecution.declaredFiles?.shared && taskForExecution.declaredFiles.shared.length > 0) {
          const conflicts = await detectCollisions(taskId, getWorkspacePath());
          if (conflicts.length > 0) {
            const board = await loadBoard();
            const conflictTask = board.tasks.find(t => t.id === taskId);
            if (conflictTask) {
              conflictTask.fileConflicts = conflicts;
              await saveBoard(board);
            }
            console.log(`[Workflow] File conflicts detected for task ${taskId}: ${conflicts.map(c => c.filePath).join(', ')}`);
          }
        }

        if (executeResult.success) {
          internalEvents.emit(AFTER_EXECUTE, { taskId, task: structuredClone(taskForExecution), success: true });
          const latestTask = await getTask(taskId);
          if (latestTask && latestTask.status === 'running') {
            const verifyResult = await executeVerifyStep(taskId);
            if (!verifyResult.success) {
              await executeCriticAndRetry(taskId, verifyResult.stderrLines);
            } else {
              await updateWorkflowStep(taskId, 'complete');
              await updateTaskStatus(taskId, 'review', null, 'workflow.executeFromDeclare.verified');
              broadcastTaskCompleted(taskId);
              { const completedTask = await getTask(taskId); internalEvents.emit(TASK_COMPLETED, { task: completedTask ? structuredClone(completedTask) : { id: taskId } }); }
              void runReflectionStep(taskId);
              void triggerToolForge(taskId);
            }
          } else {
            console.warn(`[Workflow] Skipping status update for task ${taskId}: expected 'running' but found '${latestTask?.status ?? 'deleted'}'`);
          }
        } else {
          internalEvents.emit(AFTER_EXECUTE, { taskId, task: structuredClone(taskForExecution), success: false });
          internalEvents.emit(TASK_FAILED, { taskId, task: structuredClone(taskForExecution), error: 'Execution failed after declare' });
          const latestTask = await getTask(taskId);
          if (latestTask && latestTask.status === 'running') {
            await incrementRetryCount(taskId, 'workflow.executeFromDeclare.execute_failed');
            await updateTaskStatus(taskId, 'todo', null, 'workflow.executeFromDeclare.execute_failed');
          } else {
            console.warn(`[Workflow] Skipping status update for task ${taskId}: expected 'running' but found '${latestTask?.status ?? 'deleted'}'`);
          }
        }
      } finally {
        // Stop lease renewal timer before releasing leases
        if (leaseRenewalTimer !== null) clearInterval(leaseRenewalTimer);
        releaseLeases(taskId);
      }
    } finally {
      removeInFlightTask(taskId);
    }
  })();
}

/**
 * Build the prompt for the architect step (FALLBACK)
 * Used when skill file is not available or fails to load
 */
function buildArchitectPromptFallback(task: Task, guidelines: string): string {
  const docsPath = path.join(getWorkspacePath(), task.docsPath);

  return `${guidelines}
You are a senior Software Architect. Your task is to analyze a high-level goal and decompose it into multiple independent, actionable child tasks.

TASK_TITLE: ${task.title}
TASK_CONTEXT: ${task.context}
TASK_DOCS_PATH: ${docsPath}

IMPORTANT: You must NOT write any implementation code. Your only job is to analyze and decompose.

Instructions:
1. Explore the project codebase to understand the structure, tech stack, and patterns.
2. Decompose the goal into 3-8 independent tasks.
3. Write a JSON file to ${docsPath}/architect-output.json with this format:

[
  {
    "title": "Short verb-based title",
    "context": "Detailed self-contained description with requirements and acceptance criteria",
    "priority": "high|medium|low"
  }
]

Each task must be self-contained and not reference other child tasks.
Include a final task for integration testing/verification when appropriate.`;
}

/** Shape of a single task definition in architect-output.json */
interface ArchitectTaskDef {
  title: string;
  context: string;
  priority?: 'high' | 'medium' | 'low';
  /** Architect-assigned symbolic ID for dependency references (optional, DAG mode only) */
  task_id?: string;
  /** Symbolic IDs of tasks this task depends on (optional, DAG mode only) */
  depends_on?: string[];
}

/**
 * Detect cycles in the architect-output DAG using Kahn's BFS topological sort.
 * Returns true if a cycle is detected, false if the graph is acyclic.
 */
function detectDAGCycle(defs: ArchitectTaskDef[]): boolean {
  const inDegree = new Map<string, number>();
  const adjacency = new Map<string, string[]>();

  for (const def of defs) {
    if (typeof def.task_id !== 'string' || def.task_id.length === 0) continue;
    if (!inDegree.has(def.task_id)) inDegree.set(def.task_id, 0);
    if (!adjacency.has(def.task_id)) adjacency.set(def.task_id, []);
  }

  for (const def of defs) {
    if (typeof def.task_id !== 'string' || def.task_id.length === 0) continue;
    if (!Array.isArray(def.depends_on)) continue;

    for (const dep of def.depends_on) {
      if (!inDegree.has(dep)) continue; // unknown reference — skip
      inDegree.set(def.task_id, (inDegree.get(def.task_id) ?? 0) + 1);
      const neighbors = adjacency.get(dep) ?? [];
      neighbors.push(def.task_id);
      adjacency.set(dep, neighbors);
    }
  }

  const queue: string[] = [];
  for (const [id, degree] of inDegree) {
    if (degree === 0) queue.push(id);
  }

  let processed = 0;
  while (queue.length > 0) {
    const node = queue.shift()!;
    processed++;
    for (const neighbor of (adjacency.get(node) ?? [])) {
      const newDegree = (inDegree.get(neighbor) ?? 1) - 1;
      inDegree.set(neighbor, newDegree);
      if (newDegree === 0) queue.push(neighbor);
    }
  }

  return processed < inDegree.size;
}

/**
 * Execute a goal task workflow (architect step → create child tasks)
 */
/**
 * Execute a goal task workflow: iterates over the active pipeline for goal tasks.
 * The architect stage decomposes the goal into child tasks.
 */
export async function executeGoalWorkflow(taskId: string): Promise<{ pid: number }> {
  const task = await getTask(taskId);
  if (!task) {
    throw new Error(`Task ${taskId} not found`);
  }
  await refreshEngineConfig();

  // Retrieve the active pipeline for goal tasks
  const pipeline = getActivePipeline('goal');
  console.warn(`[Workflow] Pipeline for goal task ${taskId}: ${pipeline.map((s: StageDescriptor) => s.name).join(' → ')}`);

  if (activeWorkflows.has(taskId)) {
    throw new Error('A workflow is already running for this task');
  }

  console.log(`[Workflow] Starting goal workflow for ${taskId}`);

  // Create a git safe-point commit before execution for rollback support
  await createSafePoint(taskId);

  // Update status to first pipeline stage
  const firstStage = pipeline[0];
  if (firstStage) {
    await updateTaskStatus(taskId, firstStage.taskStatus, undefined, 'workflow.runArchitectStep.start');
    await updateWorkflowStep(taskId, firstStage.workflowStep as WorkflowStep);
  }

  const startPid = process.pid;

  // Iterate over pipeline stages
  (async () => {
    try {
      for (const stage of pipeline) {
        // Abort if stop was requested between stages
        if (stoppedWorkflows.has(taskId)) {
          stoppedWorkflows.delete(taskId);
          return;
        }

        switch (stage.name) {
          // ---- ARCHITECT stage: run agent, parse output, create child tasks ----
          case 'architect': {
            // Load skill prompt with fallback
            let prompt: string;
            const skillResult = await loadSkillPrompt('architect', task);
            if (skillResult.success) {
              prompt = skillResult.content;
              console.log('[Workflow] Using skill file for architect step');
            } else {
              const guidelines = await loadProjectGuidelines();
              prompt = buildArchitectPromptFallback(task, guidelines);
              console.log('[Workflow] Using fallback prompt for architect step');
            }

            // Broadcast start
            broadcastToTask(taskId, {
              type: 'stdout',
              data: `\n========== Starting ARCHITECT step (goal decomposition) ==========\n`,
              timestamp: new Date().toISOString(),
            });

            let pidPromise: Promise<void> | undefined;
            const resultPromise = new Promise<boolean>((resolve) => {
              const { child, pidPersisted } = runWorkflowStep(taskId, 'execute', prompt, (stepSuccess) => {
                resolve(stepSuccess);
              });
              pidPromise = pidPersisted;

              if (child.pid) {
                activeWorkflows.set(taskId, { process: child, currentStep: 'architect' });
              }
            });

            // Await PID persistence so board.json has the correct PID before the process completes
            if (pidPromise) await pidPromise;

            const success = await resultPromise;

            activeWorkflows.delete(taskId);

            if (!success) {
              await incrementRetryCount(taskId, 'workflow.runArchitectStep.failed');
              await updateTaskStatus(taskId, 'todo', null, 'workflow.runArchitectStep.failed');
              broadcastToTask(taskId, {
                type: 'error',
                data: `\n[FAILED] Architect step failed.\n`,
                timestamp: new Date().toISOString(),
              });
              return;
            }

            // Abort if stop was requested between architect and child task creation
            if (stoppedWorkflows.has(taskId)) {
              stoppedWorkflows.delete(taskId);
              return;
            }

            // Parse architect-output.json and create child tasks
            const outputPath = path.join(getWorkspacePath(), task.docsPath, 'architect-output.json');

            try {
              if (!existsSync(outputPath)) {
                console.warn(`[Workflow] architect-output.json not found at ${outputPath}`);
                broadcastToTask(taskId, {
                  type: 'error',
                  data: `\n[WARNING] architect-output.json not found. Goal moved to review.\n`,
                  timestamp: new Date().toISOString(),
                });
                await updateWorkflowStep(taskId, 'complete');
                await updateTaskStatus(taskId, 'review', null, 'workflow.runArchitectStep.no_output');
                broadcastTaskCompleted(taskId);
                { const completedTask = await getTask(taskId); internalEvents.emit(TASK_COMPLETED, { task: completedTask ? structuredClone(completedTask) : { id: taskId } }); }
                void runReflectionStep(taskId);
                void triggerToolForge(taskId);
                broadcastBoardUpdate();
                return;
              }

              const outputContent = await readFile(outputPath, 'utf-8');
              const childTaskDefs = JSON.parse(outputContent) as Array<ArchitectTaskDef>;

              if (!Array.isArray(childTaskDefs) || childTaskDefs.length === 0) {
                throw new Error('architect-output.json must be a non-empty array');
              }

              console.log(`[Workflow] Parsed ${childTaskDefs.length} child tasks from architect output`);

              // Determine if DAG mode is active: at least one def has a task_id and no cycle exists
              const hasDagFields = childTaskDefs.some(d => typeof d.task_id === 'string' && d.task_id.length > 0);
              let dagMode = false;
              if (hasDagFields) {
                if (detectDAGCycle(childTaskDefs)) {
                  console.warn('[Workflow] Cycle detected in architect DAG — falling back to flat queue mode');
                  broadcastToTask(taskId, {
                    type: 'stdout',
                    data: `\n[WARNING] Cycle detected in dependency graph. Falling back to flat queue mode.\n`,
                    timestamp: new Date().toISOString(),
                  });
                } else {
                  dagMode = true;
                }
              }

              broadcastToTask(taskId, {
                type: 'stdout',
                data: `\n[ARCHITECT] Creating ${childTaskDefs.length} child tasks...\n`,
                timestamp: new Date().toISOString(),
              });

              const childTaskIds: string[] = [];
              // Maps architect task_id → Formic task ID (populated in creation loop)
              const symbolicToFormicId = new Map<string, string>();

              for (const def of childTaskDefs) {
                if (!def.title || !def.context) {
                  console.warn('[Workflow] Skipping invalid child task definition (missing title or context)');
                  continue;
                }

                const childTask = await createTask({
                  title: def.title,
                  context: def.context,
                  priority: def.priority || 'medium',
                  type: 'standard',
                });

                // Set parentGoalId on the child task
                const board = await loadBoard();
                const childInBoard = board.tasks.find(t => t.id === childTask.id);
                if (childInBoard) {
                  childInBoard.parentGoalId = taskId;
                  await saveBoard(board);
                }

                if (dagMode && typeof def.task_id === 'string' && def.task_id.length > 0) {
                  symbolicToFormicId.set(def.task_id, childTask.id);
                }

                childTaskIds.push(childTask.id);

                broadcastToTask(taskId, {
                  type: 'stdout',
                  data: `  → Created: ${childTask.id} - ${childTask.title}\n`,
                  timestamp: new Date().toISOString(),
                });
              }

              // Update goal task with child task IDs
              const goalBoard = await loadBoard();
              const goalTask = goalBoard.tasks.find(t => t.id === taskId);
              if (goalTask) {
                goalTask.childTaskIds = childTaskIds;
                await saveBoard(goalBoard);
              }

              // In DAG mode: persist dependsOn / dependsOnResolved, then queue or block each child
              if (dagMode) {
                const depBoard = await loadBoard();
                for (let i = 0; i < childTaskDefs.length; i++) {
                  const def = childTaskDefs[i];
                  const childId = childTaskIds[i];
                  if (!childId) continue;

                  const childInBoard = depBoard.tasks.find(t => t.id === childId);
                  if (childInBoard && Array.isArray(def.depends_on) && def.depends_on.length > 0) {
                    childInBoard.dependsOn = def.depends_on;
                    childInBoard.dependsOnResolved = def.depends_on
                      .map(sym => symbolicToFormicId.get(sym))
                      .filter((id): id is string => typeof id === 'string');
                  }
                }
                await saveBoard(depBoard);

                let queuedCount = 0;
                let blockedCount = 0;

                for (let i = 0; i < childTaskDefs.length; i++) {
                  const def = childTaskDefs[i];
                  const childId = childTaskIds[i];
                  if (!childId) continue;

                  const hasDeps = Array.isArray(def.depends_on) && def.depends_on.length > 0;
                  if (hasDeps) {
                    await updateTaskStatus(childId, 'blocked', null, 'workflow.runArchitectStep.child_blocked');
                    blockedCount++;
                    broadcastToTask(taskId, {
                      type: 'stdout',
                      data: `  ⏸ Blocked (awaiting dependencies): ${childId}\n`,
                      timestamp: new Date().toISOString(),
                    });
                  } else {
                    await queueTask(childId);
                    queuedCount++;
                    broadcastToTask(taskId, {
                      type: 'stdout',
                      data: `  ✓ Queued: ${childId}\n`,
                      timestamp: new Date().toISOString(),
                    });
                  }
                }

                // Move goal to review
                await updateWorkflowStep(taskId, 'complete');
                await updateTaskStatus(taskId, 'review', null, 'workflow.runArchitectStep.dag_complete');
                broadcastTaskCompleted(taskId);
                { const completedTask = await getTask(taskId); internalEvents.emit(TASK_COMPLETED, { task: completedTask ? structuredClone(completedTask) : { id: taskId } }); }
                void runReflectionStep(taskId);
                void triggerToolForge(taskId);

                broadcastToTask(taskId, {
                  type: 'stdout',
                  data: `\n[SUCCESS] Goal decomposed into ${childTaskIds.length} tasks (${queuedCount} queued, ${blockedCount} blocked). Ready for review.\n`,
                  timestamp: new Date().toISOString(),
                });
              } else {
                // Flat mode: queue all children unconditionally
                for (const childId of childTaskIds) {
                  await queueTask(childId);
                  broadcastToTask(taskId, {
                    type: 'stdout',
                    data: `  ✓ Queued: ${childId}\n`,
                    timestamp: new Date().toISOString(),
                  });
                }

                // Move goal to review
                await updateWorkflowStep(taskId, 'complete');
                await updateTaskStatus(taskId, 'review', null, 'workflow.runArchitectStep.flat_complete');
                broadcastTaskCompleted(taskId);
                { const completedTask = await getTask(taskId); internalEvents.emit(TASK_COMPLETED, { task: completedTask ? structuredClone(completedTask) : { id: taskId } }); }
                void runReflectionStep(taskId);
                void triggerToolForge(taskId);

                broadcastToTask(taskId, {
                  type: 'stdout',
                  data: `\n[SUCCESS] Goal decomposed into ${childTaskIds.length} tasks. Ready for review.\n`,
                  timestamp: new Date().toISOString(),
                });
              }

              broadcastBoardUpdate();

            } catch (error) {
              const message = error instanceof Error ? error.message : 'Unknown error';
              console.warn('[Workflow] Failed to parse architect output:', message);

              broadcastToTask(taskId, {
                type: 'error',
                data: `\n[WARNING] Failed to parse architect-output.json: ${message}\nGoal moved to review for manual inspection.\n`,
                timestamp: new Date().toISOString(),
              });

              await updateWorkflowStep(taskId, 'complete');
              await updateTaskStatus(taskId, 'review', null, 'workflow.runArchitectStep.parse_error');
              broadcastTaskCompleted(taskId);
              { const completedTask = await getTask(taskId); internalEvents.emit(TASK_COMPLETED, { task: completedTask ? structuredClone(completedTask) : { id: taskId } }); }
              void runReflectionStep(taskId);
              void triggerToolForge(taskId);
              broadcastBoardUpdate();
            }
            break;
          }

          // ---- Plugin or unknown stage: use generic executeStage helper ----
          default: {
            const stageSuccess = await executeStage(taskId, stage);
            if (!stageSuccess) {
              await incrementRetryCount(taskId, `workflow.executeGoalWorkflow.${stage.name}_failed`);
              await updateTaskStatus(taskId, 'todo', null, `workflow.executeGoalWorkflow.${stage.name}_failed`);
              return;
            }
            break;
          }
        }
      }
    } finally {
      removeInFlightTask(taskId);
    }
  })();

  return { pid: startPid };
}

/**
 * Stop an active workflow
 */
export async function stopWorkflow(taskId: string): Promise<boolean> {
  const workflow = activeWorkflows.get(taskId);

  // Mark as stopped so workflow IIFEs abort at the next step boundary
  stoppedWorkflows.add(taskId);

  // Eagerly reset to todo so the UI updates immediately via WebSocket broadcast
  await updateTaskStatus(taskId, 'todo', null, 'workflow.stopWorkflow');

  // Remove from inFlightTasks so the task can be re-queued cleanly if needed.
  // Safe to call here even though the workflow IIFE's outer finally block also calls
  // removeInFlightTask — Set.delete is idempotent so double-calls are harmless.
  removeInFlightTask(taskId);

  // Immediately release any leases held by this task to unblock sibling tasks
  releaseLeases(taskId);
  activeWorkflows.delete(taskId);

  if (workflow) {
    workflow.process.kill('SIGTERM');
    setTimeout(() => {
      if (!workflow.process.killed) workflow.process.kill('SIGKILL');
      stoppedWorkflows.delete(taskId);
    }, 3000);
  } else {
    // No active process — clean up the abort flag after a brief delay to allow
    // any in-flight IIFE to observe it before it is removed
    setTimeout(() => stoppedWorkflows.delete(taskId), 3000);
  }

  return true;
}

import { spawn, type ChildProcess } from 'node:child_process';
import { readFile } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import type { WebSocket } from 'ws';
import { updateTaskStatus, appendTaskLogs, getTask } from './store.js';
import { getAgentCommand, buildAgentArgs, getAgentDisplayName } from './agentAdapter.js';
import { getWorkspacePath } from '../utils/paths.js';
import { releaseLeases } from './leaseManager.js';
import { createSafePoint } from '../utils/gitUtils.js';
import type { LogMessage, Task } from '../../types/index.js';
import path from 'node:path';
import { getRelevantMemories } from './memory.js';
import { listTools } from './tools.js';
import { engineConfig, refreshEngineConfig } from './engineConfig.js';

const GUIDELINE_FILENAME = 'kanban-development-guideline.md';

/**
 * Load the project development guidelines if they exist
 */
async function loadProjectGuidelines(): Promise<string> {
  const guidelinePath = path.join(getWorkspacePath(), GUIDELINE_FILENAME);

  if (!existsSync(guidelinePath)) {
    return '';
  }

  try {
    const content = await readFile(guidelinePath, 'utf-8');
    return `
## Project Development Guidelines
The following guidelines MUST be followed for all code changes in this project:

${content}

---
END OF GUIDELINES

`;
  } catch (error) {
    console.warn('[Runner] Failed to load project guidelines:', error);
    return '';
  }
}

// Store active processes
const activeProcesses = new Map<string, ChildProcess>();

// The actual port the server is listening on, set once at startup via setBoundPort().
let boundPort = 8000;

/**
 * Called by the server entry point after the HTTP server binds to register
 * the live port so agents always POST tool registrations to the correct address.
 */
export function setBoundPort(port: number): void {
  boundPort = port;
}

/**
 * Returns the current bound port for constructing API URLs.
 */
export function getBoundPort(): number {
  return boundPort;
}

// Store WebSocket connections per task
const taskConnections = new Map<string, Set<WebSocket>>();

export function isAgentRunning(): boolean {
  return activeProcesses.size > 0;
}

export function getRunningTaskId(): string | null {
  const entries = Array.from(activeProcesses.entries());
  return entries.length > 0 ? entries[0][0] : null;
}

export function registerConnection(taskId: string, ws: WebSocket): void {
  if (!taskConnections.has(taskId)) {
    taskConnections.set(taskId, new Set());
  }
  taskConnections.get(taskId)!.add(ws);
}

export function unregisterConnection(taskId: string, ws: WebSocket): void {
  const connections = taskConnections.get(taskId);
  if (connections) {
    connections.delete(ws);
    if (connections.size === 0) {
      taskConnections.delete(taskId);
    }
  }
}

function broadcastToTask(taskId: string, message: LogMessage): void {
  const connections = taskConnections.get(taskId);
  if (!connections) return;

  const data = JSON.stringify(message);
  for (const ws of connections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(data);
    }
  }
}

export async function runAgent(taskId: string, title: string, context: string, docsPath: string): Promise<{ pid: number }> {
  await refreshEngineConfig();
  // Check concurrency - allow multiple agents based on maxConcurrentTasks
  if (activeProcesses.size >= engineConfig.maxConcurrentTasks) {
    throw new Error(`Maximum concurrent agents reached (${engineConfig.maxConcurrentTasks}). Please wait for one to complete.`);
  }

  // Load project guidelines (injected into prompt)
  const guidelines = await loadProjectGuidelines();

  // Retrieve relevant memories for this task
  let pastExperienceSection = '';
  try {
    const task = await getTask(taskId);
    if (task !== undefined) {
      const memories = await getRelevantMemories(task);
      if (memories.length > 0) {
        console.log(`[Runner] Injecting ${memories.length} memories into agent context for task ${taskId}`);
        const entries = memories
          .map((m, i) => `${i + 1}. [${m.type.toUpperCase()}] ${m.content}`)
          .join('\n');
        pastExperienceSection = `\n\n## Past Experience\nThe following memories from previous tasks may be relevant:\n${entries}`;
      }
    }
  } catch (error) {
    console.warn('[Runner] Memory retrieval failed, proceeding without memories:', error);
  }

  // Retrieve registered tools for context injection
  let availableToolsSection = '';
  try {
    const tools = await listTools();
    if (tools.length > 0) {
      console.log(`[Runner] ${tools.length} tools available in agent context for task ${taskId}`);
      availableToolsSection = `\n## Available Tools (${tools.length} registered)\n${tools.map(t => `- **${t.manifest.name}**: ${t.manifest.description}\n  Command: \`${t.manifest.command}\``).join('\n')}\nUse these tools when they match the task requirements to avoid re-implementing existing functionality.\n`;
    }
  } catch (error) {
    console.warn('[Runner] Failed to load tools for agent context:', error);
  }

  // Build tool forging instructions with the live server port
  const toolForgingSection = `
## Tool Forging
If during this task you identify a shell command that would be reusable across future tasks (e.g. a test runner, linter, build script, or deploy command), register it as a tool by running:
  curl -s -X POST http://localhost:${boundPort}/api/tools \\
    -H 'Content-Type: application/json' \\
    -d '{"name":"slug-name","description":"What it does","command":"the shell command","created_by":"${title}"}'
Rules:
- Tool names must be lowercase alphanumeric with hyphens only (e.g. run-tests, lint-fix, build-dist).
- Only forge a tool if the command is generic and reusable — not task-specific.
- Skip forging if a similar tool already exists in the Available Tools section above.
`;

  // Build prompt - simple format for --print mode
  // Note: In --print mode, tools are limited. For complex tasks, the agent should read context from the prompt directly.
  const prompt = `${guidelines}Task: ${title}

Context: ${context}
${pastExperienceSection}${availableToolsSection}${toolForgingSection}
Task documentation is available at: ${docsPath}/

All code changes MUST comply with the project development guidelines provided above.`;

  // Spawn agent CLI process using the configured agent adapter
  // stdin is set to 'ignore' since non-interactive mode doesn't need input
  const agentCommand = getAgentCommand();
  const agentArgs = buildAgentArgs(prompt);

  // Create a git safe-point commit before spawning the agent for rollback support
  await createSafePoint(taskId);

  const child = spawn(agentCommand, agentArgs, {
    cwd: getWorkspacePath(),
    env: { ...process.env, FORMIC_API_URL: `http://localhost:${boundPort}`, FORMIC_TASK_ID: taskId },
    stdio: ['ignore', 'pipe', 'pipe'],
  });

  const logBuffer: string[] = [];

  // Set up error handler FIRST to catch spawn errors (e.g., command not found)
  child.on('error', async (err: NodeJS.ErrnoException) => {
    activeProcesses.delete(taskId);
    releaseLeases(taskId);
    console.log(`[Runner] Released leases for task ${taskId} (error handler)`);

    // Provide helpful error messages for common issues
    const agentName = getAgentDisplayName();
    let errorMessage = err.message;
    if (err.code === 'ENOENT') {
      errorMessage = `Command '${agentCommand}' not found. Please ensure ${agentName} is installed and available in PATH.`;
    } else if (err.code === 'EACCES') {
      errorMessage = `Permission denied when trying to execute '${agentCommand}'.`;
    }

    await updateTaskStatus(taskId, 'todo', null, 'runner.spawn_error');

    broadcastToTask(taskId, {
      type: 'error',
      data: errorMessage,
      timestamp: new Date().toISOString(),
    });
  });

  // Check if spawn succeeded (pid exists)
  if (!child.pid) {
    // Don't throw - let the error event handle it
    // Return a placeholder that will be updated when error fires
    activeProcesses.set(taskId, child);
    await updateTaskStatus(taskId, 'running', 0, 'runner.process_spawned_placeholder');
    return { pid: 0 };
  }

  activeProcesses.set(taskId, child);

  // Update task status
  await updateTaskStatus(taskId, 'running', child.pid, 'runner.process_spawned');

  // Handle stdout
  child.stdout?.on('data', (data: Buffer) => {
    const text = data.toString();
    const lines = text.split('\n').filter(line => line.length > 0);
    logBuffer.push(...lines);

    broadcastToTask(taskId, {
      type: 'stdout',
      data: text,
      timestamp: new Date().toISOString(),
    });
  });

  // Handle stderr
  child.stderr?.on('data', (data: Buffer) => {
    const text = data.toString();
    const lines = text.split('\n').filter(line => line.length > 0);
    logBuffer.push(...lines);

    broadcastToTask(taskId, {
      type: 'stderr',
      data: text,
      timestamp: new Date().toISOString(),
    });
  });

  // Handle process exit
  child.on('close', async (code) => {
    activeProcesses.delete(taskId);
    releaseLeases(taskId);
    console.log(`[Runner] Released leases for task ${taskId} (close handler)`);

    // Save logs to task
    await appendTaskLogs(taskId, logBuffer);

    // Update status based on exit code
    const newStatus = code === 0 ? 'review' : 'todo';
    const closeCallerTag = code === 0 ? 'runner.close_event.success' : 'runner.close_event.failed';
    await updateTaskStatus(taskId, newStatus, null, closeCallerTag);

    broadcastToTask(taskId, {
      type: 'exit',
      data: `Process exited with code ${code}`,
      timestamp: new Date().toISOString(),
    });
  });

  return { pid: child.pid };
}

export async function stopAgent(taskId: string): Promise<boolean> {
  const process = activeProcesses.get(taskId);

  if (!process) {
    return false;
  }

  process.kill('SIGTERM');

  // Eagerly reset to todo so the UI updates immediately
  await updateTaskStatus(taskId, 'todo', null, 'runner.stopAgent');

  // Give it a moment, then force kill if needed
  setTimeout(() => {
    if (activeProcesses.has(taskId)) {
      process.kill('SIGKILL');
    }
  }, 3000);

  return true;
}

// lease-test: verified
/**
 * Lease Manager Service
 * Provides atomic all-or-nothing file lease acquisition, renewal, and release
 * for lease-based concurrency control of parallel task execution.
 * Includes priority preemption, deadlock detection, and disk persistence.
 */

import { exec } from 'node:child_process';
import { promisify } from 'node:util';
import { writeFile, readFile } from 'node:fs/promises';
import path from 'node:path';
import type { FileLease, LeaseRequest, LeaseResult, FileConflict, LeaseStoreSnapshot } from '../../types/index.js';
import { getFormicDir, getWorkspacePath } from '../utils/paths.js';
import { getTask, updateTaskStatus } from './store.js';
import { broadcastLeaseReleased } from './boardNotifier.js';
import { internalEvents, LEASE_RELEASED, LEASE_ACQUIRED, requestTaskStop } from './internalEvents.js';

const execAsync = promisify(exec);

import { engineConfig } from './engineConfig.js';

/** Active-task predicate: returns true when a task has a live workflow process. */
let isTaskActive: ((taskId: string) => boolean) | null = null;

/**
 * Register the active-task predicate callback. Used by workflow.ts to expose
 * its activeWorkflows knowledge to leaseManager so expiry checks can protect
 * leases held by tasks with live child processes.
 */
export function registerActiveTaskPredicate(fn: (taskId: string) => boolean): void {
  isTaskActive = fn;
}

/** In-memory lease store: filePath → FileLease */
const leaseStore = new Map<string, FileLease>();

/** Recorded file hashes for collision detection: taskId → Map<filePath, hash> */
const fileHashStore = new Map<string, Map<string, string>>();

/** Wait-for map: taskId → filePath the task is waiting to acquire */
const waitForMap = new Map<string, string>();

/** Priority rank for comparison: higher number = higher priority */
const PRIORITY_RANK: Record<string, number> = { low: 0, medium: 1, high: 2 };

/**
 * Acquire file leases atomically (all-or-nothing).
 * If any exclusive file is already leased by another task, the entire request is denied.
 * Shared files are not exclusively locked.
 */
export function acquireLeases(request: LeaseRequest): LeaseResult {
  const { taskId, exclusiveFiles, sharedFiles } = request;
  const durationMs = request.leaseDurationMs ?? engineConfig.leaseDurationMs;
  const now = new Date();
  const expiresAt = new Date(now.getTime() + durationMs);

  // Clean expired leases before checking
  cleanExpiredLeases();

  // Check for conflicts on exclusive files
  const conflictingFiles: string[] = [];
  for (const filePath of exclusiveFiles) {
    const existing = leaseStore.get(filePath);
    if (existing && existing.taskId !== taskId) {
      conflictingFiles.push(filePath);
      continue;
    }
    // Also check for shared leases on this file held by other tasks
    for (const [key, lease] of leaseStore.entries()) {
      if (key.startsWith(`${filePath}::`) && lease.taskId !== taskId) {
        conflictingFiles.push(filePath);
        break;
      }
    }
  }

  // Check for conflicts on shared files against exclusive leases
  for (const filePath of sharedFiles) {
    const existing = leaseStore.get(filePath);
    if (existing && existing.taskId !== taskId && existing.leaseType === 'exclusive') {
      conflictingFiles.push(filePath);
    }
  }

  if (conflictingFiles.length > 0) {
    console.warn(`[LeaseManager] Lease denied for task ${taskId}: conflicts on ${conflictingFiles.join(', ')}`);
    return { granted: false, leases: [], conflictingFiles };
  }

  // Grant all leases atomically — all conflict checks passed
  const grantedLeases: FileLease[] = [];

  for (const filePath of exclusiveFiles) {
    const lease: FileLease = {
      filePath,
      taskId,
      acquiredAt: now.toISOString(),
      expiresAt: expiresAt.toISOString(),
      leaseType: 'exclusive',
    };
    leaseStore.set(filePath, lease);
    grantedLeases.push(lease);
  }

  for (const filePath of sharedFiles) {
    const lease: FileLease = {
      filePath,
      taskId,
      acquiredAt: now.toISOString(),
      expiresAt: expiresAt.toISOString(),
      leaseType: 'shared',
    };
    // Shared files don't block others - store with task-scoped key
    leaseStore.set(`${filePath}::${taskId}`, lease);
    grantedLeases.push(lease);
  }

  console.warn(`[LeaseManager] Leases granted for task ${taskId}: ${exclusiveFiles.length} exclusive, ${sharedFiles.length} shared`);
  internalEvents.emit(LEASE_ACQUIRED, { taskId, leases: grantedLeases });
  persistLeases().catch(e => console.warn('[LeaseManager] persist error:', e));
  return { granted: true, leases: grantedLeases, conflictingFiles: [] };
}

/**
 * Release all leases held by a task
 */
export function releaseLeases(taskId: string): void {
  let released = 0;
  const releasedFiles: string[] = [];
  for (const [key, lease] of leaseStore.entries()) {
    if (lease.taskId === taskId) {
      if (lease.leaseType === 'exclusive') {
        releasedFiles.push(lease.filePath);
      }
      leaseStore.delete(key);
      released++;
    }
  }
  if (released > 0) {
    console.warn(`[LeaseManager] Released ${released} lease(s) for task ${taskId}`);
    broadcastLeaseReleased(taskId, releasedFiles);
    internalEvents.emit(LEASE_RELEASED, taskId, releasedFiles);
  }

  // Clean up file hash records
  fileHashStore.delete(taskId);
  persistLeases().catch(e => console.warn('[LeaseManager] persist error:', e));
}

/**
 * Renew all leases for a task by extending their expiration.
 * No longer calls cleanExpiredLeases — expiry-driven cleanup is exclusively
 * handled by acquireLeases (the mutation entry point) and the watchdog.
 */
export function renewLeases(taskId: string, durationMs?: number): boolean {
  const extension = durationMs ?? engineConfig.leaseDurationMs;
  const newExpiresAt = new Date(Date.now() + extension).toISOString();
  let renewed = 0;

  for (const lease of leaseStore.values()) {
    if (lease.taskId === taskId) {
      lease.expiresAt = newExpiresAt;
      renewed++;
    }
  }

  if (renewed > 0) {
    console.warn(`[LeaseManager] Renewed ${renewed} lease(s) for task ${taskId}`);
    return true;
  }
  return false;
}

/**
 * Get all leases held by a specific task
 */
export function getLeasesByTask(taskId: string): FileLease[] {
  const leases: FileLease[] = [];
  for (const lease of leaseStore.values()) {
    if (lease.taskId === taskId) {
      leases.push(lease);
    }
  }
  return leases;
}

/**
 * Get all active leases, filtering out expired leases whose holder is not active.
 * This is a read-only operation — no mutation, no events, no persistence.
 */
export function getAllLeases(): FileLease[] {
  const now = Date.now();
  return Array.from(leaseStore.values()).filter(lease => {
    if (new Date(lease.expiresAt).getTime() > now) return true;
    // Expired but holder is active — still considered leased
    return isTaskActive ? isTaskActive(lease.taskId) : false;
  });
}

/**
 * Check if a file is currently leased (optionally excluding a specific task).
 * Expired leases whose holder is not active are treated as not leased.
 * This is a read-only operation — no mutation, no events, no persistence.
 */
export function isFileLeased(filePath: string, excludeTaskId?: string): boolean {
  const now = Date.now();
  const lease = leaseStore.get(filePath);
  if (!lease) return false;
  if (excludeTaskId && lease.taskId === excludeTaskId) return false;
  // Expired and holder not active — treat as free
  if (new Date(lease.expiresAt).getTime() <= now && !(isTaskActive && isTaskActive(lease.taskId))) {
    return false;
  }
  return true;
}

/**
 * Check whether a file would conflict if the given taskId intended to acquire it
 * exclusively. Mirrors the conflict logic in acquireLeases() so pre-dispatch
 * checks and actual lease grants are consistent.
 *
 * A conflict exists when:
 * 1. The file has an exclusive lease held by a different task, OR
 * 2. The file has one or more shared leases held by different tasks
 *
 * Expired leases are cleaned before checking, matching acquireLeases behaviour.
 * Returns true if there IS a conflict (i.e., the task would be denied).
 */
export function wouldConflict(filePath: string, taskId: string): boolean {
  // Clean expired leases before checking (consistent with acquireLeases)
  cleanExpiredLeases();

  // Check exclusive holder
  const exclusive = leaseStore.get(filePath);
  if (exclusive && exclusive.taskId !== taskId) {
    return true;
  }

  // Check shared holders — stored under filePath::taskId keys
  for (const [key, lease] of leaseStore.entries()) {
    if (key.startsWith(`${filePath}::`) && lease.taskId !== taskId) {
      return true;
    }
  }

  return false;
}

/**
 * Get the task ID that holds an exclusive lease on a file, or null if none.
 * Expired leases whose holder is not active are treated as not held.
 * Used to identify zombie lease holders.
 * This is a read-only operation — no mutation, no events, no persistence.
 */
export function getExclusiveLeaseHolder(filePath: string): string | null {
  const now = Date.now();
  const lease = leaseStore.get(filePath);
  if (!lease || lease.leaseType !== 'exclusive') return null;
  // Expired and holder not active — treat as not held
  if (new Date(lease.expiresAt).getTime() <= now && !(isTaskActive && isTaskActive(lease.taskId))) {
    return null;
  }
  return lease.taskId;
}

/**
 * Clean up expired leases from the store.
 *
 * Expired leases whose holder has a live workflow process are renewed in-place
 * (mirrors the watchdog's active-task guard). Leases whose holder is NOT active
 * are genuinely freed: deleted from the store, broadcast via boardNotifier,
 * emitted via internalEvents (LEASE_RELEASED), and persisted to leases.json.
 */
function cleanExpiredLeases(): void {
  const now = Date.now();
  const releasedExclusiveByTask = new Map<string, string[]>();

  for (const [key, lease] of leaseStore.entries()) {
    if (new Date(lease.expiresAt).getTime() <= now) {
      if (isTaskActive && isTaskActive(lease.taskId)) {
        // Active task: renew in-place instead of deleting
        const newExpiresAt = new Date(now + engineConfig.leaseDurationMs).toISOString();
        lease.expiresAt = newExpiresAt;
        console.warn(`[LeaseManager] Renewed expired lease for active task ${lease.taskId} on ${lease.filePath}`);
      } else {
        // Not active: genuinely free the lease
        if (lease.leaseType === 'exclusive') {
          const files = releasedExclusiveByTask.get(lease.taskId) || [];
          files.push(lease.filePath);
          releasedExclusiveByTask.set(lease.taskId, files);
        }
        leaseStore.delete(key);
      }
    }
  }

  // Emit LEASE_RELEASED and broadcast for genuinely freed leases
  for (const [taskId, files] of releasedExclusiveByTask) {
    console.warn(`[LeaseManager] Expired leases freed for inactive task ${taskId}: ${files.join(', ')}`);
    broadcastLeaseReleased(taskId, files);
    internalEvents.emit(LEASE_RELEASED, taskId, files);
  }

  if (releasedExclusiveByTask.size > 0) {
    persistLeases().catch(e => console.warn('[LeaseManager] persist error:', e));
  }
}

/**
 * Get all expired leases (used by watchdog)
 */
export function getExpiredLeases(): FileLease[] {
  const now = Date.now();
  const expired: FileLease[] = [];
  for (const lease of leaseStore.values()) {
    if (new Date(lease.expiresAt).getTime() <= now) {
      expired.push(lease);
    }
  }
  return expired;
}

/**
 * Record git hash-object hashes for shared files at task start
 * Used for optimistic concurrency collision detection
 */
export async function recordFileHashes(taskId: string, filePaths: string[], cwd: string): Promise<Map<string, string>> {
  const hashes = new Map<string, string>();

  for (const filePath of filePaths) {
    try {
      const { stdout } = await execAsync(`git hash-object "${filePath}"`, { cwd });
      const hash = stdout.trim();
      if (hash) {
        hashes.set(filePath, hash);
      }
    } catch {
      // File may not exist yet, skip it
      console.warn(`[LeaseManager] Could not hash file: ${filePath}`);
    }
  }

  fileHashStore.set(taskId, hashes);
  console.warn(`[LeaseManager] Recorded ${hashes.size} file hash(es) for task ${taskId}`);
  return hashes;
}

/**
 * Detect collisions on shared files by comparing current hashes to recorded ones
 */
export async function detectCollisions(taskId: string, cwd: string): Promise<FileConflict[]> {
  const baseHashes = fileHashStore.get(taskId);
  if (!baseHashes || baseHashes.size === 0) {
    return [];
  }

  const conflicts: FileConflict[] = [];

  for (const [filePath, expectedHash] of baseHashes.entries()) {
    try {
      const { stdout } = await execAsync(`git hash-object "${filePath}"`, { cwd });
      const actualHash = stdout.trim();
      if (actualHash && actualHash !== expectedHash) {
        conflicts.push({
          filePath,
          expectedHash,
          actualHash,
        });
      }
    } catch {
      // File may have been deleted, treat as conflict
      conflicts.push({
        filePath,
        expectedHash,
        actualHash: '<deleted>',
      });
    }
  }

  if (conflicts.length > 0) {
    console.warn(`[LeaseManager] Detected ${conflicts.length} collision(s) for task ${taskId}`);
  }

  return conflicts;
}

/**
 * Register that a task is waiting to acquire a lease on a file.
 * Used to build the wait-for graph for deadlock detection.
 */
export function recordWait(taskId: string, filePath: string): void {
  waitForMap.set(taskId, filePath);
}

/**
 * Unregister a task's wait record once it acquires or abandons the lease.
 */
export function clearWait(taskId: string): void {
  waitForMap.delete(taskId);
}

/**
 * Persist the current leaseStore to .formic/leases.json.
 * Fire-and-forget — callers should .catch() the returned promise.
 */
export async function persistLeases(): Promise<void> {
  try {
    const snapshot: LeaseStoreSnapshot = {
      version: '1.0',
      savedAt: new Date().toISOString(),
      leases: Array.from(leaseStore.entries()).map(([key, lease]) => ({ key, lease })),
    };
    const leasesPath = path.join(getFormicDir(), 'leases.json');
    await writeFile(leasesPath, JSON.stringify(snapshot, null, 2), 'utf-8');
  } catch (err) {
    console.warn('[LeaseManager] Failed to persist leases:', err instanceof Error ? err.message : 'Unknown error');
  }
}

/**
 * Restore non-expired leases from .formic/leases.json into leaseStore.
 * Called on server startup by the watchdog.
 */
export async function restoreLeases(): Promise<void> {
  try {
    const leasesPath = path.join(getFormicDir(), 'leases.json');
    const raw = await readFile(leasesPath, 'utf-8');
    const snapshot: LeaseStoreSnapshot = JSON.parse(raw) as LeaseStoreSnapshot;
    const now = Date.now();
    let restored = 0;
    for (const { key, lease } of snapshot.leases) {
      if (new Date(lease.expiresAt).getTime() > now) {
        leaseStore.set(key, lease);
        restored++;
      }
    }
    console.warn(`[LeaseManager] Restored ${restored} non-expired lease(s) from disk`);
  } catch (err) {
    // File not found on first startup is expected
    const message = err instanceof Error ? err.message : 'Unknown error';
    if (!message.includes('ENOENT')) {
      console.warn('[LeaseManager] Failed to restore leases:', message);
    } else {
      console.warn('[LeaseManager] No leases.json found — starting with empty lease store');
    }
  }
}

/**
 * Revert uncommitted changes on a task's exclusively-leased files after its
 * process has been stopped, so a half-written state is never handed to the
 * next lease holder (mirrors the watchdog's expired-lease path).
 */
async function revertExclusiveFiles(taskId: string, files: string[]): Promise<void> {
  if (files.length === 0) return;
  try {
    const fileList = files.map(f => `"${f}"`).join(' ');
    await execAsync(`git checkout -- ${fileList}`, { cwd: getWorkspacePath() });
    console.warn(`[LeaseManager] Reverted uncommitted changes on ${files.length} leased file(s) for task ${taskId}`);
  } catch (err) {
    console.warn(`[LeaseManager] Failed to revert leased files for task ${taskId}:`, err instanceof Error ? err.message : 'Unknown error');
  }
}

/**
 * Attempt to preempt an exclusive lease held by a lower-priority task.
 * The holder's process is stopped BEFORE its leases are released; if the
 * holder cannot be stopped, the preemption is refused — a lease must never
 * be handed to a new task while the previous holder may still be writing.
 * Returns true if the file was freed, false if preemption was not applicable
 * or was refused.
 */
export async function preemptLease(highPriorityTaskId: string, targetFilePath: string): Promise<boolean> {
  const holderLease = leaseStore.get(targetFilePath);
  if (!holderLease || holderLease.leaseType !== 'exclusive') {
    return false;
  }

  const holderId = holderLease.taskId;
  if (holderId === highPriorityTaskId) {
    return false;
  }

  const [holderTask, requesterTask] = await Promise.all([
    getTask(holderId),
    getTask(highPriorityTaskId),
  ]);

  const holderRank = PRIORITY_RANK[holderTask?.priority ?? 'medium'] ?? 1;
  const requesterRank = PRIORITY_RANK[requesterTask?.priority ?? 'medium'] ?? 1;

  if (holderRank >= requesterRank) {
    return false;
  }

  // The lease may have vanished while task lookups were awaited — distinguish
  // expiry from voluntary release rather than misattributing either.
  const leaseBeforeStop = leaseStore.get(targetFilePath);
  if (!leaseBeforeStop || leaseBeforeStop.taskId !== holderId) {
    if (new Date(holderLease.expiresAt).getTime() <= Date.now()) {
      console.warn(`[LeaseManager] Lease on ${targetFilePath} expired before preemption of task ${holderId} — no stop needed`);
    } else {
      console.warn(`[LeaseManager] Lease on ${targetFilePath} was released before preemption of task ${holderId} — no stop needed`);
    }
    return !leaseBeforeStop;
  }

  // Capture the holder's exclusive files before stopping so they can be reverted
  const holderExclusiveFiles = getLeasesByTask(holderId)
    .filter(l => l.leaseType === 'exclusive')
    .map(l => l.filePath);

  // Stop the holder's process BEFORE touching its leases
  const stopped = await requestTaskStop(holderId);
  if (!stopped) {
    console.warn(`[LeaseManager] Preemption of ${targetFilePath} refused: holder task ${holderId} could not be stopped`);
    return false;
  }

  // Holder is stopped: revert its half-written files, release, and re-queue.
  // The stop transition sets resumeFromStep for tasks past planning; the
  // 'queued' transition below preserves that marker.
  await revertExclusiveFiles(holderId, holderExclusiveFiles);
  releaseLeases(holderId);
  clearWait(holderId);
  await updateTaskStatus(holderId, 'queued', null, 'leaseManager.preemption');
  console.warn(`[LeaseManager] Preempted lease on ${targetFilePath}: stopped, reverted, and re-queued task ${holderId}`);

  return true;
}

/**
 * Detect and resolve deadlock cycles in the wait-for graph.
 * Resolves each cycle by stopping the lowest-priority task in the cycle,
 * reverting its leased files, releasing its leases, and re-queuing it.
 * If the victim cannot be stopped, resolution for that cycle is skipped this
 * tick (the watchdog re-runs detection every interval).
 * Returns the detected cycle arrays, or null if no cycles were found.
 */
export async function detectDeadlock(): Promise<string[][] | null> {
  if (waitForMap.size === 0) return null;

  // Build task-to-task wait-for graph: waiting task → holding task
  const waitGraph = new Map<string, string>();
  for (const [waitingTaskId, filePath] of waitForMap.entries()) {
    const holderLease = leaseStore.get(filePath);
    if (holderLease && holderLease.taskId !== waitingTaskId) {
      waitGraph.set(waitingTaskId, holderLease.taskId);
    }
  }

  if (waitGraph.size === 0) return null;

  // DFS-based cycle detection on a functional graph (each node has ≤1 outgoing edge)
  const cycles: string[][] = [];
  const visited = new Set<string>();

  for (const startNode of waitGraph.keys()) {
    if (visited.has(startNode)) continue;

    const path: string[] = [];
    const pathSet = new Set<string>();
    let current: string | undefined = startNode;

    while (current !== undefined && !visited.has(current)) {
      if (pathSet.has(current)) {
        const cycleStart = path.indexOf(current);
        cycles.push(path.slice(cycleStart));
        break;
      }
      path.push(current);
      pathSet.add(current);
      current = waitGraph.get(current);
    }

    for (const node of path) {
      visited.add(node);
    }
  }

  if (cycles.length === 0) return null;

  console.warn(`[LeaseManager] Detected ${cycles.length} deadlock cycle(s)`);

  // Resolve each cycle by aborting the lowest-priority task
  for (const cycle of cycles) {
    let victimId = cycle[0];
    let victimRank = PRIORITY_RANK[(await getTask(victimId))?.priority ?? 'medium'] ?? 1;

    for (const taskId of cycle.slice(1)) {
      const task = await getTask(taskId);
      const rank = PRIORITY_RANK[task?.priority ?? 'medium'] ?? 1;
      if (rank < victimRank) {
        victimId = taskId;
        victimRank = rank;
      }
    }

    // Capture the victim's exclusive files before stopping so they can be reverted
    const victimExclusiveFiles = getLeasesByTask(victimId)
      .filter(l => l.leaseType === 'exclusive')
      .map(l => l.filePath);

    // Stop the victim's process BEFORE releasing its leases; skip this cycle
    // if it cannot be stopped — never free files under a possibly-live writer
    const stopped = await requestTaskStop(victimId);
    if (!stopped) {
      console.warn(`[LeaseManager] Deadlock victim ${victimId} could not be stopped — skipping resolution this tick`);
      continue;
    }

    await revertExclusiveFiles(victimId, victimExclusiveFiles);
    releaseLeases(victimId);
    clearWait(victimId);
    await updateTaskStatus(victimId, 'queued', null, 'leaseManager.deadlock_resolution');
    console.warn(`[LeaseManager] Deadlock resolved: stopped, reverted, and re-queued task ${victimId}`);
  }

  return cycles;
}

