export const TASK_TYPE_REGISTERED = 'task-type-registered';

/** Shared internal event emitter instance */
export const internalEvents = new EventEmitter();

/**
 * Task stopper callback: stops the process(es) executing a task and resolves
 * true once the stop has been carried out, false if the task could not be stopped.
 */
export type TaskStopper = (taskId: string) => Promise<boolean>;

/** Injected task stopper — registered by workflow.ts at module init */
let taskStopper: TaskStopper | null = null;

/**
 * Register the task stopper callback. Used by workflow.ts to expose its
 * stop capability to lower-level services (e.g., leaseManager) without
 * creating a circular import.
 */
export function registerTaskStopper(fn: TaskStopper): void {
  taskStopper = fn;
}

/**
 * Request that a task's running process be stopped via the registered stopper.
 * Returns false when no stopper is registered or the stopper fails — callers
 * MUST treat false as "the task may still be running" and refuse any action
 * that assumes the process is dead (e.g., force-releasing its file leases).
 */
export async function requestTaskStop(taskId: string): Promise<boolean> {
  if (!taskStopper) {
    console.warn(`[InternalEvents] No task stopper registered — cannot stop task ${taskId}`);
    return false;
  }
  try {
    return await taskStopper(taskId);
  } catch (err) {
    console.error(`[InternalEvents] Task stopper failed for ${taskId}:`, err instanceof Error ? err.message : 'Unknown error');
    return false;
  }
}

/**
 * Automated queue re-prioritizer.
 * Scores and re-orders queued tasks based on dependency graph analysis.
 * Called inside processQueue() before task pickup to maximise DAG throughput.
 */
import type { Task, QueueAnalysisEntry } from '../../types/index.js';

// ==================== Scoring Constants ====================

const FIX_BONUS = 1000;
const UNBLOCK_BONUS = 100;
const PRIORITY_SCORES: Record<string, number> = { high: 30, medium: 20, low: 10 };
const MAX_AGE_BONUS = 10;

// ==================== Private Helpers ====================

/**
 * Build a reverse dependency graph from the full task list.
 * Maps each depId → array of taskIds that declare it in their dependsOnResolved.
 */
function buildReverseDepGraph(allTasks: Task[]): Map<string, string[]> {
  const reverseGraph = new Map<string, string[]>();
  for (const task of allTasks) {
    if (!task.dependsOnResolved || task.dependsOnResolved.length === 0) continue;
    for (const depId of task.dependsOnResolved) {
      const dependents = reverseGraph.get(depId) ?? [];
      dependents.push(task.id);
      reverseGraph.set(depId, dependents);
    }
  }
  return reverseGraph;
}

/**
 * BFS over the reverse dependency graph starting from taskId.
 * Counts the number of unique `blocked` tasks transitively reachable —
 * these are the tasks that would eventually become runnable once taskId completes.
 */
function countTransitivelyUnblocked(
  taskId: string,
  reverseGraph: Map<string, string[]>,
  allTasksMap: Map<string, Task>,
): number {
  const visited = new Set<string>();
  const queue: string[] = [taskId];
  let count = 0;

  while (queue.length > 0) {
    const current = queue.shift()!;
    if (visited.has(current)) continue;
    visited.add(current);

    const dependents = reverseGraph.get(current) ?? [];
    for (const dependentId of dependents) {
      if (visited.has(dependentId)) continue;
      const dependent = allTasksMap.get(dependentId);
      if (dependent?.status === 'blocked') {
        count++;
        // Continue BFS — this task may itself transitively unblock further tasks
        queue.push(dependentId);
      }
    }
  }

  return count;
}

/**
 * Compute a numeric score and human-readable reasoning for a single queued task.
 * Score components (higher = picked first):
 *   - Fix bonus:          +1000 if fixForTaskId is set
 *   - Unblocking:         +100 per transitively blocked task that becomes runnable
 *   - Manual priority:    high=+30, medium=+20, low=+10
 *   - FIFO age bonus:     +min(ageMs/1000, 10)
 *   - Fairness tiebreaker: +min(firstBlockedAgeMs/10000, 0.9) — tiny bonus for
 *     longest-blocked task at equal priority, ensuring deterministic lease acquisition
 *     order under contention without overriding priority or age.
 */
function scoreTask(
  task: Task,
  unblockingPotential: number,
): { score: number; reasoning: string } {
  const fixBonus = task.fixForTaskId ? FIX_BONUS : 0;
  const unblockScore = unblockingPotential * UNBLOCK_BONUS;
  const priorityScore = PRIORITY_SCORES[task.priority] ?? PRIORITY_SCORES['medium'];
  const ageMs = Date.now() - new Date(task.queuedAt ?? task.createdAt ?? new Date().toISOString()).getTime();
  const ageBonus = Math.min(ageMs / 1000, MAX_AGE_BONUS);

  // Fairness tiebreaker: tasks blocked longer on the same file should win at equal score.
  // Capped at 0.9 so it never overrides even a 1-second age difference.
  let fairnessBonus = 0;
  if (task.firstBlockedAt) {
    const blockedAgeMs = Date.now() - new Date(task.firstBlockedAt).getTime();
    fairnessBonus = Math.min(blockedAgeMs / 10000, 0.9);
  }

  const score = fixBonus + unblockScore + priorityScore + ageBonus + fairnessBonus;

  const parts: string[] = [];
  if (fixBonus > 0) parts.push(`fix-bonus(+${fixBonus})`);
  if (unblockScore > 0) parts.push(`unblocking(${unblockingPotential}×+${UNBLOCK_BONUS}=+${unblockScore})`);
  parts.push(`priority(${task.priority}=+${priorityScore})`);
  parts.push(`age(+${ageBonus.toFixed(1)})`);
  if (fairnessBonus > 0) parts.push(`fairness(+${fairnessBonus.toFixed(2)})`);
  const reasoning = `score=${score.toFixed(2)}: ${parts.join(', ')}`;

  return { score, reasoning };
}

// ==================== Exported Functions ====================

/**
 * Re-orders queued tasks by descending score using a 4-tier dependency-aware algorithm:
 *   1. Fix task bonus    (+1000 if fixForTaskId is set — preserves self-healing fast-path)
 *   2. Unblocking score  (+100 per transitively blocked task that becomes runnable)
 *   3. Manual priority   (high=+30, medium=+20, low=+10)
 *   4. FIFO age bonus    (+min(ageMs/1000, 10) — breaks ties, favours older tasks)
 *
 * When no dependency relationships exist, output order matches the pre-existing
 * getQueuedTasks() sort (fix → priority → FIFO).
 */
export function prioritizeQueue(tasks: Task[], allTasks: Task[]): Task[] {
  if (tasks.length <= 1) return tasks;

  const reverseGraph = buildReverseDepGraph(allTasks);
  const allTasksMap = new Map<string, Task>(allTasks.map(t => [t.id, t]));

  const scored = tasks.map(task => {
    const unblockingPotential = countTransitivelyUnblocked(task.id, reverseGraph, allTasksMap);
    const { score, reasoning } = scoreTask(task, unblockingPotential);
    return { task, score, reasoning };
  });

  scored.sort((a, b) => b.score - a.score);

  const originalOrder = tasks.map(t => t.id).join(', ');
  const newOrder = scored.map(e => e.task.id).join(', ');
  if (originalOrder !== newOrder) {
    console.log(`[Prioritizer] Reordered queue: [${newOrder}] (was [${originalOrder}])`);
  }

  return scored.map(e => e.task);
}

/**
 * Returns a QueueAnalysisEntry for each queued task with taskId, score,
 * unblockingPotential, and reasoning. Does not mutate or reorder the input list.
 * Useful for observability and debugging of queue ordering decisions.
 */
export function getQueueAnalysis(tasks: Task[], allTasks: Task[]): QueueAnalysisEntry[] {
  const reverseGraph = buildReverseDepGraph(allTasks);
  const allTasksMap = new Map<string, Task>(allTasks.map(t => [t.id, t]));

  return tasks.map(task => {
    const unblockingPotential = countTransitivelyUnblocked(task.id, reverseGraph, allTasksMap);
    const { score, reasoning } = scoreTask(task, unblockingPotential);
    return { taskId: task.id, score, unblockingPotential, reasoning };
  });
}

/**
 * Engine Config Singleton
 * Provides synchronous access to engine settings loaded from configStore.
 * Call refreshEngineConfig() at the start of each top-level operation
 * (workflow execution, queue poll tick, watchdog scan) to pick up config changes.
 */
import { loadConfig } from './configStore.js';

export interface EngineConfig {
  maxConcurrentTasks: number;
  verifyCommand: string;
  skipVerify: boolean;
  leaseDurationMs: number;
  watchdogIntervalMs: number;
  maxYieldCount: number;
  queuePollIntervalMs: number;
  maxExecuteIterations: number;
  stepTimeoutMs: number;
  maxExecutionRetries: number;
}

export const engineConfig: EngineConfig = {
  maxConcurrentTasks: 1,
  verifyCommand: '',
  skipVerify: false,
  leaseDurationMs: 300000,
  watchdogIntervalMs: 30000,
  maxYieldCount: 50,
  queuePollIntervalMs: 5000,
  maxExecuteIterations: 5,
  stepTimeoutMs: 6000000,
  maxExecutionRetries: 3,
};

export async function refreshEngineConfig(): Promise<void> {
  const config = await loadConfig();
  const s = config.settings;
  engineConfig.maxConcurrentTasks = s.maxConcurrentSessions ?? 1;
  engineConfig.verifyCommand = s.verifyCommand ?? '';
  engineConfig.skipVerify = s.skipVerify ?? false;
  engineConfig.leaseDurationMs = s.leaseDurationMs ?? 300000;
  engineConfig.watchdogIntervalMs = s.watchdogIntervalMs ?? 30000;
  engineConfig.maxYieldCount = s.maxYieldCount ?? 50;
  engineConfig.queuePollIntervalMs = s.queuePollIntervalMs ?? 5000;
  engineConfig.maxExecuteIterations = s.maxExecuteIterations ?? 5;
  engineConfig.stepTimeoutMs = s.stepTimeoutMs ?? 6000000;
  engineConfig.maxExecutionRetries = s.maxExecutionRetries ?? 3;
}

import path from 'node:path';
import os from 'node:os';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

/**
 * Get the package root directory.
 * This resolves correctly whether running from source (src/) or compiled (dist/),
 * and whether installed globally via npm or running locally.
 */
export function getPackageRoot(): string {
  // __dirname is either src/server/utils or dist/server/utils
  // Package root is 3 levels up
  return path.resolve(__dirname, '..', '..', '..');
}

/**
 * Get the path to bundled skills directory.
 * Works for both local development and global npm installs.
 */
export function getBundledSkillsPath(): string {
  return path.join(getPackageRoot(), 'skills');
}

/**
 * Get the path to bundled templates directory.
 * Works for both local development and global npm installs.
 */
export function getBundledTemplatesPath(): string {
  return path.join(getPackageRoot(), 'templates');
}

/**
 * Get the global ~/.formic/ directory path
 */
export function getGlobalFormicDir(): string {
  return path.join(os.homedir(), '.formic');
}

/**
 * Get the global config file path (~/.formic/config.json)
 */
export function getGlobalConfigPath(): string {
  return path.join(getGlobalFormicDir(), 'config.json');
}

/**
 * Module-level workspace path, initialized from environment variable.
 * Can be updated at runtime via setWorkspacePath().
 */
let currentWorkspacePath: string = process.env.WORKSPACE_PATH || './workspace';

/**
 * Get the current workspace path
 */
export function getWorkspacePath(): string {
  return currentWorkspacePath;
}

/**
