import { readFile, writeFile, mkdir, readdir, stat } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import { getFormicDir, getSkillsDir, getBundledSkillsPath } from '../utils/paths.js';

/**
 * Get the path to the workspace skills directory (.claude/skills/)
 */
export function getWorkspaceSkillsPath(): string {
  return getSkillsDir();
}

/**
 * Get the legacy skills path (.formic/skills/)
 */
export function getLegacySkillsPath(): string {
  return path.join(getFormicDir(), 'skills');
}

/**
 * Check if skills have already been copied to the workspace
 * Checks both new (.claude/skills/) and legacy (.formic/skills/) locations
 */
export function skillsExistInWorkspace(): boolean {
  const newPath = getWorkspaceSkillsPath();
  const legacyPath = getLegacySkillsPath();
  return existsSync(newPath) || existsSync(legacyPath);
}

/**
 * Recursively copy a directory
 */
async function copyDirectory(src: string, dest: string): Promise<void> {
  // Create destination directory if it doesn't exist
  if (!existsSync(dest)) {
    await mkdir(dest, { recursive: true });
  }

  const entries = await readdir(src, { withFileTypes: true });

  for (const entry of entries) {
    const srcPath = path.join(src, entry.name);
    const destPath = path.join(dest, entry.name);

    if (entry.isDirectory()) {
      await copyDirectory(srcPath, destPath);
    } else {
      const content = await readFile(srcPath, 'utf-8');
      await writeFile(destPath, content, 'utf-8');
    }
  }
}

/**
 * Copy bundled skills to the workspace .claude/skills/ directory
 * Only copies if skills don't already exist in the workspace (checks both new and legacy locations)
 */
export async function copySkillsToWorkspace(): Promise<{ copied: boolean; skills: string[] }> {
  // Skip if skills already exist in either location
  if (skillsExistInWorkspace()) {
    console.log('[Skills] Skills already exist in workspace, skipping copy');
    return { copied: false, skills: [] };
  }

  const bundledSkillsPath = getBundledSkillsPath();
  const workspaceSkillsPath = getWorkspaceSkillsPath(); // Points to .claude/skills/

  // Check if bundled skills exist
  if (!existsSync(bundledSkillsPath)) {
    console.warn('[Skills] Bundled skills directory not found at:', bundledSkillsPath);
    return { copied: false, skills: [] };
  }

  try {
    // Ensure .claude directory exists
    const claudeDir = path.dirname(workspaceSkillsPath);
    if (!existsSync(claudeDir)) {
      await mkdir(claudeDir, { recursive: true });
    }

    // Copy the entire skills directory to .claude/skills/
    await copyDirectory(bundledSkillsPath, workspaceSkillsPath);

    // Get list of copied skills
    const skillDirs = await readdir(workspaceSkillsPath);
    const skills = skillDirs.filter(async (dir) => {
      const skillPath = path.join(workspaceSkillsPath, dir);
      const stats = await stat(skillPath);
      return stats.isDirectory();
    });

    console.log('[Skills] Copied skills to workspace .claude/skills/:', skills);
    return { copied: true, skills };
  } catch (error) {
    console.error('[Skills] Error copying skills to workspace:', error);
    return { copied: false, skills: [] };
  }
}

/**
 * Get the path to a specific skill in the workspace
 * Checks new location (.claude/skills/) first, then falls back to legacy (.formic/skills/)
 */
export function getSkillPath(skillName: string): string {
  const newPath = path.join(getWorkspaceSkillsPath(), skillName, 'SKILL.md');
  const legacyPath = path.join(getLegacySkillsPath(), skillName, 'SKILL.md');

  // Prefer new location, fall back to legacy
  if (existsSync(newPath)) {
    return newPath;
  }
  if (existsSync(legacyPath)) {
    return legacyPath;
  }

  // Default to new location for new files
  return newPath;
}

/**
 * Check if a specific skill exists in the workspace (either location)
 */
export function skillExists(skillName: string): boolean {
  const newPath = path.join(getWorkspaceSkillsPath(), skillName, 'SKILL.md');
  const legacyPath = path.join(getLegacySkillsPath(), skillName, 'SKILL.md');
  return existsSync(newPath) || existsSync(legacyPath);
}

/**
 * Get the content of a skill file
 */
export async function getSkillContent(skillName: string): Promise<string | null> {
  const skillPath = getSkillPath(skillName);

  if (!existsSync(skillPath)) {
    return null;
  }

  return await readFile(skillPath, 'utf-8');
}

import { readFile, writeFile } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import type { SubtasksFile, Subtask, SubtaskStatus, Task, TaskStatus, WorkflowStep } from '../../types/index.js';
import { getWorkspacePath } from '../utils/paths.js';

const SUBTASKS_FILENAME = 'subtasks.json';

/**
 * Get the path to the subtasks.json file for a task
 */
export function getSubtasksPath(docsPath: string): string {
  return path.join(getWorkspacePath(), docsPath, SUBTASKS_FILENAME);
}

/**
 * Check if subtasks.json exists for a task
 */
export function subtasksExist(docsPath: string): boolean {
  return existsSync(getSubtasksPath(docsPath));
}

/**
 * Load and parse subtasks.json for a task
 * Returns null if file doesn't exist or is invalid
 */
export async function loadSubtasks(docsPath: string): Promise<SubtasksFile | null> {
  const subtasksPath = getSubtasksPath(docsPath);
  console.log(`[Subtasks] Loading subtasks from: ${subtasksPath}`);

  if (!existsSync(subtasksPath)) {
    console.log(`[Subtasks] File does not exist: ${subtasksPath}`);
    return null;
  }

  try {
    const content = await readFile(subtasksPath, 'utf-8');
    const data = JSON.parse(content) as SubtasksFile;

    // Basic validation
    if (!data.version || !data.subtasks || !Array.isArray(data.subtasks)) {
      console.warn('[Subtasks] Invalid subtasks.json structure');
      return null;
    }

    // Normalize invalid status values to prevent infinite execution loops
    const VALID_STATUSES: Set<string> = new Set(['pending', 'in_progress', 'completed', 'skipped']);
    const SYNONYM_MAP: Record<string, SubtaskStatus> = {
      'done': 'completed',
      'complete': 'completed',
      'finished': 'completed',
      'skip': 'skipped',
    };

    for (const subtask of data.subtasks) {
      if (!VALID_STATUSES.has(subtask.status)) {
        const normalized = SYNONYM_MAP[subtask.status] ?? 'pending';
        console.warn(`[Subtasks] Normalizing invalid status "${subtask.status}" → "${normalized}" for subtask ${subtask.id}`);
        subtask.status = normalized;
      }
    }

    console.warn(`[Subtasks] Loaded ${data.subtasks.length} subtasks`);
    return data;
  } catch (error) {
    console.error('[Subtasks] Failed to load subtasks.json:', error);
    return null;
  }
}

/**
 * Save subtasks.json for a task
 */
export async function saveSubtasks(docsPath: string, subtasks: SubtasksFile): Promise<boolean> {
  const subtasksPath = getSubtasksPath(docsPath);

  try {
    // Update the updatedAt timestamp
    subtasks.updatedAt = new Date().toISOString();

    await writeFile(subtasksPath, JSON.stringify(subtasks, null, 2), 'utf-8');
    return true;
  } catch (error) {
    console.error('[Subtasks] Failed to save subtasks.json:', error);
    return false;
  }
}

/**
 * Update the status of a single subtask
 */
export async function updateSubtaskStatus(
  docsPath: string,
  subtaskId: string,
  status: SubtaskStatus
): Promise<{ success: boolean; subtask?: Subtask }> {
  const subtasks = await loadSubtasks(docsPath);

  if (!subtasks) {
    return { success: false };
  }

  const subtask = subtasks.subtasks.find(s => s.id === subtaskId);
  if (!subtask) {
    return { success: false };
  }

  subtask.status = status;

  // Set completedAt timestamp when marking as completed
  if (status === 'completed') {
    subtask.completedAt = new Date().toISOString();
  } else {
    delete subtask.completedAt;
  }

  const saved = await saveSubtasks(docsPath, subtasks);
  return { success: saved, subtask };
}

/**
 * Get completion statistics for subtasks
 */
export function getCompletionStats(subtasks: SubtasksFile): {
  total: number;
  completed: number;
  skipped: number;
  inProgress: number;
  pending: number;
  percentage: number;
} {
  const total = subtasks.subtasks.length;
  const completed = subtasks.subtasks.filter(s => s.status === 'completed').length;
  const skipped = subtasks.subtasks.filter(s => s.status === 'skipped').length;
  const inProgress = subtasks.subtasks.filter(s => s.status === 'in_progress').length;
  const pending = subtasks.subtasks.filter(s => s.status === 'pending').length;
  // Both completed and skipped count toward progress
  const doneCount = completed + skipped;
  const percentage = total > 0 ? Math.round((doneCount / total) * 100) : 0;

  return { total, completed, skipped, inProgress, pending, percentage };
}

/**
 * Check if all subtasks are completed or skipped
 * Skipped subtasks are those that require manual verification and cannot be automated
 */
export function isAllComplete(subtasks: SubtasksFile): boolean {
  if (subtasks.subtasks.length === 0) {
    return true; // No subtasks means complete
  }
  // Both 'completed' and 'skipped' count as done for workflow purposes
  return subtasks.subtasks.every(s => s.status === 'completed' || s.status === 'skipped');
}

/**
 * Get all incomplete subtasks (pending or in_progress, not skipped)
 */
export function getIncompleteSubtasks(subtasks: SubtasksFile): Subtask[] {
  return subtasks.subtasks.filter(s => s.status !== 'completed' && s.status !== 'skipped');
}

/**
 * Format incomplete subtasks as a string for agent feedback
 */
export function formatIncompleteSubtasksForPrompt(subtasks: SubtasksFile): string {
  const incomplete = getIncompleteSubtasks(subtasks);

  if (incomplete.length === 0) {
    return 'All subtasks are complete.';
  }

  const lines = incomplete.map(s => {
    const statusLabel = s.status === 'in_progress' ? '[IN PROGRESS]' : '[PENDING]';
    return `- ${statusLabel} ${s.id}: ${s.content}`;
  });

  return `The following subtasks are NOT yet complete:\n${lines.join('\n')}`;
}

/**
 * Calculate task progress percentage (0-100) based on workflow stage and subtask completion.
 *
 * Progress model:
 * - Stage progress (0-25%): pending/todo=0%, briefing=5%, planning=18%, running=25%, review/done=100%
 * - Subtask progress (25-100%): During 'execute' stage, remaining 75% divided among subtasks
 *
 * @param task - The task to calculate progress for
 * @returns Progress percentage (0-100)
 */
export async function calculateTaskProgress(task: Task): Promise<number> {
  const { status, workflowStep, docsPath, id } = task;

  // Bootstrap task: 0% when pending/todo, 100% when done
  if (id === 't-bootstrap') {
    if (status === 'done' || status === 'review') {
      return 100;
    }
    if (status === 'todo') {
      return 0;
    }
    // If running, estimate based on status
    if (status === 'briefing') return 10;
    if (status === 'planning') return 30;
    if (status === 'running') return 60;
    return 0;
  }

  // Completed tasks
  if (status === 'done') {
    return 100;
  }

  // Review tasks (workflow complete, awaiting human review)
  if (status === 'review') {
    return 100;
  }

  // Todo tasks (not started)
  if (status === 'todo') {
    return 0;
  }

  // Stage-based progress for active workflow
  // briefing = 5%, planning = 18%, running = 25% (base for execute)
  const stageProgress: Record<TaskStatus, number> = {
    'todo': 0,
    'queued': 0,
    'briefing': 5,
    'planning': 18,
    'declaring': 20,
    'running': 25,
    'architecting': 50,
    'verifying': 80,
    'review': 100,
    'done': 100,
    'blocked': 0,
  };

  let progress = stageProgress[status] ?? 0;

  // Add subtask progress during execution phase
  if (status === 'running' && (workflowStep === 'execute' || workflowStep === 'complete')) {
    const subtasks = await loadSubtasks(docsPath);

    if (subtasks && subtasks.subtasks.length > 0) {
      const stats = getCompletionStats(subtasks);
      // Subtasks contribute 75% of total progress (25% to 100%)
      // Both completed and skipped count toward progress
      const doneCount = stats.completed + stats.skipped;
      const subtaskProgress = (doneCount / stats.total) * 75;
      progress = 25 + subtaskProgress;
    }
    // If no subtasks.json yet during execute, stay at 25%
  }

  return Math.min(100, Math.round(progress));
}

import type { WebSocket } from 'ws';
import type { LogMessage } from '../../types/index.js';

/**
 * Board Notifier Service
 *
 * Manages WebSocket connections subscribed to board update notifications.
 * Broadcasts `board-updated` events when the board state changes (e.g., task created).
 */

// Track connections that want board update notifications
const boardConnections = new Set<WebSocket>();

// Track per-task WebSocket connections for terminal log streaming
const taskConnections = new Map<string, Set<WebSocket>>();

export function registerTaskConnection(taskId: string, ws: WebSocket): void {
  if (!taskConnections.has(taskId)) {
    taskConnections.set(taskId, new Set());
  }
  taskConnections.get(taskId)!.add(ws);
}

export function unregisterTaskConnection(taskId: string, ws: WebSocket): void {
  const connections = taskConnections.get(taskId);
  if (connections) {
    connections.delete(ws);
    if (connections.size === 0) {
      taskConnections.delete(taskId);
    }
  }
}

export function broadcastToTask(taskId: string, message: LogMessage): void {
  const connections = taskConnections.get(taskId);
  if (!connections) return;

  const data = JSON.stringify(message);
  for (const ws of connections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(data);
    }
  }
}

/**
 * Register a WebSocket connection for board update notifications
 */
export function registerBoardConnection(ws: WebSocket): void {
  boardConnections.add(ws);
  console.log('[BoardNotifier] Connection registered, total:', boardConnections.size);
}

/**
 * Unregister a WebSocket connection from board update notifications
 */
export function unregisterBoardConnection(ws: WebSocket): void {
  boardConnections.delete(ws);
  console.log('[BoardNotifier] Connection unregistered, total:', boardConnections.size);
}

/**
 * Broadcast a board-updated event to all connected clients
 * Call this after any operation that modifies the board state
 */
export function broadcastBoardUpdate(): void {
  const message = JSON.stringify({ type: 'board-updated' });

  let sentCount = 0;
  for (const ws of boardConnections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(message);
      sentCount++;
    }
  }

  console.log('[BoardNotifier] Broadcast board-updated to', sentCount, 'clients');
}

/**
 * Broadcast a dependency-resolved event when a blocked task is automatically unblocked
 */
export function broadcastDependencyResolved(taskId: string, parentGoalId: string): void {
  const message = JSON.stringify({ type: 'dependency-resolved', taskId, parentGoalId });

  let sentCount = 0;
  for (const ws of boardConnections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(message);
      sentCount++;
    }
  }

  console.log(`[BoardNotifier] Broadcast dependency-resolved for task ${taskId} (goal ${parentGoalId}) to ${sentCount} clients`);
}

/**
 * Broadcast a kill-switch event when the self-healing loop exhausts retries
 */
export function broadcastKillSwitch(taskId: string): void {
  const message = JSON.stringify({ type: 'kill-switch', taskId });

  let sentCount = 0;
  for (const ws of boardConnections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(message);
      sentCount++;
    }
  }

  console.log(`[BoardNotifier] Broadcast kill-switch for task ${taskId} to ${sentCount} clients`);
}

/**
 * Broadcast that a task has completed (moved to review or done)
 */
export function broadcastTaskCompleted(taskId: string): void {
  const message = JSON.stringify({ type: 'task-completed', taskId });

  let sentCount = 0;
  for (const ws of boardConnections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(message);
      sentCount++;
    }
  }

  console.log(`[BoardNotifier] Broadcast task-completed for task ${taskId} to ${sentCount} clients`);
}

/**
 * Broadcast that exclusive leases for a task have been released
 */
export function broadcastLeaseReleased(taskId: string, releasedFiles: string[]): void {
  const message = JSON.stringify({ type: 'lease-released', taskId, releasedFiles });

  let sentCount = 0;
  for (const ws of boardConnections) {
