import { readFile } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import { getSkillPath, skillExists, getSkillContent } from './skills.js';
import { getWorkspacePath } from '../utils/paths.js';
import type { Task, SkillOverride, VerifierDefinition, VerifierResult } from '../../types/index.js';
import { internalEvents, SKILL_LOADED, BEFORE_SKILL_LOAD } from './internalEvents.js';

const GUIDELINE_FILENAME = 'kanban-development-guideline.md';

// ── Skill Override Registry ──────────────────────────────────────────────────

const skillOverrides = new Map<string, SkillOverride>();

// ── Verifier Registry ────────────────────────────────────────────────────────

const verifierRegistry = new Map<string, VerifierDefinition & { registeredByPlugin: string }>();

/**
 * Register a custom verifier contributed by a plugin.
 * Validates that the verifier ID is unique.
 */
export function registerVerifier(verifier: VerifierDefinition, pluginName: string): void {
  if (verifierRegistry.has(verifier.id)) {
    throw new Error(`[SkillReader] Verifier '${verifier.id}' is already registered`);
  }
  verifierRegistry.set(verifier.id, { ...verifier, registeredByPlugin: pluginName });
  console.warn(`[SkillReader] Verifier registered: ${verifier.id} by ${pluginName}`);
}

/**
 * Remove all verifiers registered by a given plugin.
 * Returns the count of removed verifiers.
 */
export function unregisterVerifiers(pluginName: string): number {
  let count = 0;
  for (const [id, entry] of verifierRegistry) {
    if (entry.registeredByPlugin === pluginName) {
      verifierRegistry.delete(id);
      count++;
    }
  }
  if (count > 0) {
    console.warn(`[SkillReader] Unregistered ${count} verifier(s) from plugin '${pluginName}'`);
  }
  return count;
}

/**
 * Return all currently registered verifier definitions.
 */
export function getVerifiers(): VerifierDefinition[] {
  return [...verifierRegistry.values()].map(({ registeredByPlugin: _reg, ...def }) => def);
}

/** Canonical alias for getVerifiers, as specified in the SkillApi requirements. */
export const getRegisteredVerifiers = getVerifiers;

/**
 * Execute all registered verifiers against the given task ID.
 * Errors are caught per-verifier so one failure doesn't block others.
 */
export async function runVerifiers(taskId: string): Promise<Array<{ verifierId: string; passed: boolean; message?: string }>> {
  const results: Array<{ verifierId: string; passed: boolean; message?: string }> = [];

  for (const [id, entry] of verifierRegistry) {
    try {
      const result: VerifierResult = await entry.verify(taskId);
      results.push({ verifierId: id, passed: result.passed, message: result.message });
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      console.error(`[SkillReader] Verifier '${id}' threw an error: ${message}`);
      results.push({ verifierId: id, passed: false, message: `Verifier error: ${message}` });
    }
  }

  return results;
}

/**
 * Register a plugin's skill content override for a given stage name.
 * Last-registered wins if multiple plugins override the same stage.
 */
export function registerSkillOverride(stageName: string, content: string, pluginName: string): void {
  const existing = skillOverrides.get(stageName);
  if (existing && existing.pluginName !== pluginName) {
    console.warn(
      `[SkillReader] Plugin '${pluginName}' is overriding skill '${stageName}' previously set by '${existing.pluginName}'`
    );
  }
  skillOverrides.set(stageName, { stageName, content, pluginName });
}

/**
 * Remove all skill overrides registered by a given plugin.
 */
export function unregisterSkillOverrides(pluginName: string): void {
  for (const [stage, override] of skillOverrides) {
    if (override.pluginName === pluginName) {
      skillOverrides.delete(stage);
    }
  }
}

/**
 * Return the override for a stage if one exists, or null.
 */
export function getSkillOverride(stageName: string): SkillOverride | null {
  return skillOverrides.get(stageName) ?? null;
}

/**
 * Parse SKILL.md frontmatter and extract content
 * Returns the markdown content without the YAML frontmatter
 */
function parseSkillFile(content: string): { frontmatter: Record<string, string>; body: string } {
  const frontmatterRegex = /^---\s*\n([\s\S]*?)\n---\s*\n([\s\S]*)$/;
  const match = content.match(frontmatterRegex);

  if (!match) {
    // No frontmatter, return entire content as body
    return { frontmatter: {}, body: content };
  }

  const [, frontmatterStr, body] = match;
  const frontmatter: Record<string, string> = {};

  // Parse simple YAML key: value pairs
  frontmatterStr.split('\n').forEach(line => {
    const colonIndex = line.indexOf(':');
    if (colonIndex > 0) {
      const key = line.slice(0, colonIndex).trim();
      const value = line.slice(colonIndex + 1).trim();
      frontmatter[key] = value;
    }
  });

  return { frontmatter, body };
}

/**
 * Substitute variables in skill content
 * Supports: $TASK_ID, $TASK_TITLE, $TASK_CONTEXT, $TASK_DOCS_PATH
 */
function substituteVariables(content: string, variables: Record<string, string>): string {
  let result = content;

  for (const [key, value] of Object.entries(variables)) {
    // Replace $VARIABLE_NAME with the value
    const regex = new RegExp(`\\$${key}`, 'g');
    result = result.replace(regex, value);
  }

  return result;
}

/**
 * Load project development guidelines if they exist
 */
export async function loadProjectGuidelines(): Promise<string> {
  const guidelinePath = path.join(getWorkspacePath(), GUIDELINE_FILENAME);

  if (!existsSync(guidelinePath)) {
    return '';
  }

  try {
    const content = await readFile(guidelinePath, 'utf-8');
    return `
## Project Development Guidelines
The following guidelines MUST be followed for all code changes in this project:

${content}

---
END OF GUIDELINES

`;
  } catch (error) {
    console.warn('[SkillReader] Failed to load project guidelines:', error);
    return '';
  }
}

/**
 * Load a skill file, substitute variables, and prepend guidelines
 * Returns the fully prepared prompt content
 */
export async function loadSkillPrompt(
  skillName: string,
  task: Task
): Promise<{ success: boolean; content: string; source: 'override' | 'filesystem' | 'fallback' }> {
  // Allow plugins to register just-in-time overrides
  internalEvents.emit(BEFORE_SKILL_LOAD, { skillName, taskId: task.id });

  // Build variables for substitution (shared by override and filesystem paths)
  const docsPath = path.join(getWorkspacePath(), task.docsPath);
  const variables: Record<string, string> = {
    TASK_ID: task.id,
    TASK_TITLE: task.title,
    TASK_CONTEXT: task.context,
    TASK_DOCS_PATH: docsPath,
  };

  // Check for plugin override before hitting the filesystem
  const override = getSkillOverride(skillName);
  if (override) {
    try {
      const substitutedContent = substituteVariables(override.content, variables);
      const guidelines = await loadProjectGuidelines();
      const finalContent = guidelines + substitutedContent;

      console.warn(`[SkillReader] Using override for skill '${skillName}' from plugin '${override.pluginName}'`);
      internalEvents.emit(SKILL_LOADED, { skillName, taskId: task.id, source: 'override' as const });
      return { success: true, content: finalContent, source: 'override' };
    } catch (error) {
      console.error(`[SkillReader] Error applying override for skill '${skillName}':`, error);
      return { success: false, content: '', source: 'fallback' };
    }
  }

  // Filesystem path — existing behavior
  if (!skillExists(skillName)) {
    console.warn(`[SkillReader] Skill '${skillName}' not found, using fallback`);
    return { success: false, content: '', source: 'fallback' };
  }

  try {
    const rawContent = await getSkillContent(skillName);
    if (!rawContent) {
      console.warn(`[SkillReader] Failed to read skill '${skillName}'`);
      return { success: false, content: '', source: 'fallback' };
    }

    const { body } = parseSkillFile(rawContent);
    const substitutedContent = substituteVariables(body, variables);
    const guidelines = await loadProjectGuidelines();
    const finalContent = guidelines + substitutedContent;

    console.warn(`[SkillReader] Loaded skill '${skillName}' with variables substituted`);
    internalEvents.emit(SKILL_LOADED, { skillName, taskId: task.id, source: 'filesystem' as const });
    return { success: true, content: finalContent, source: 'filesystem' };
  } catch (error) {
    console.error(`[SkillReader] Error loading skill '${skillName}':`, error);
    return { success: false, content: '', source: 'fallback' };
  }
}

/**
 * Get available skills in the workspace
 */
export function getAvailableSkills(): string[] {
  const skills: string[] = [];

  if (skillExists('brief')) {
    skills.push('brief');
  }
  if (skillExists('plan')) {
    skills.push('plan');
  }
  if (skillExists('architect')) {
    skills.push('architect');
  }

  return skills;
}

/**
 * Agent Adapter - Pluggable agent abstraction layer
 *
 * Supports multiple AI coding agents (Claude Code CLI, GitHub Copilot CLI)
 * through a unified interface. All agent-specific logic is contained here.
 */

export interface AgentConfig {
  /** CLI command (e.g., 'claude', 'copilot') */
  command: string;
  /** Build CLI arguments for execution */
  buildArgs: (prompt: string) => string[];
  /** Path to skills directory */
  skillsDir: string;
  /** Required environment variables */
  envVars: Record<string, string | undefined>;
}

export type AgentType = 'claude' | 'copilot';

/**
 * Assistant-specific configuration for read-only Task Manager mode
 */
export interface AssistantConfig {
  /** Output format flag (e.g., 'stream-json' for Claude) */
  outputFormat: string | null;
  /** List of read-only tools allowed for the assistant */
  readOnlyTools: string[];
  /** Whether the agent supports --continue for conversation context */
  supportsConversationContinue: boolean;
  /** Build CLI arguments for assistant (read-only) mode */
  buildAssistantArgs: (prompt: string, options?: { continue?: boolean }) => string[];
}

/**
 * Agent configurations for supported agents
 */
const AGENTS: Record<AgentType, AgentConfig> = {
  claude: {
    command: 'claude',
    buildArgs: (prompt: string) => ['--print', '--dangerously-skip-permissions', prompt],
    skillsDir: '.claude/skills',
    envVars: { ANTHROPIC_API_KEY: process.env.ANTHROPIC_API_KEY },
  },
  copilot: {
    command: 'copilot',
    buildArgs: (prompt: string) => ['--prompt', prompt, '--allow-all-tools', '--allow-all-paths'],
    skillsDir: '.claude/skills',
    envVars: {}, // Uses GitHub OAuth
  },
};

/**
 * Assistant-specific configurations for read-only Task Manager mode
 */
/**
 * Claude Code tool names (PascalCase)
 */
const CLAUDE_READONLY_TOOLS = ['Read', 'Glob', 'Grep', 'LS', 'WebSearch', 'WebFetch'];
const CLAUDE_MCP_PLAYWRIGHT_TOOLS = [
  'mcp__playwright__browser_navigate',
  'mcp__playwright__browser_snapshot',
  'mcp__playwright__browser_take_screenshot',
  'mcp__playwright__browser_close',
];
const CLAUDE_ASSISTANT_TOOLS = [...CLAUDE_READONLY_TOOLS, ...CLAUDE_MCP_PLAYWRIGHT_TOOLS];
const CLAUDE_MESSAGING_TOOLS = [...CLAUDE_READONLY_TOOLS];

/**
 * GitHub Copilot CLI tool names (snake_case)
 */
const COPILOT_READONLY_TOOLS = ['view', 'glob', 'grep', 'web_fetch'];
const COPILOT_ASSISTANT_TOOLS = [...COPILOT_READONLY_TOOLS];
const COPILOT_MESSAGING_TOOLS = [...COPILOT_READONLY_TOOLS];

const ASSISTANT_CONFIGS: Record<AgentType, AssistantConfig> = {
  claude: {
    outputFormat: 'stream-json',
    readOnlyTools: CLAUDE_ASSISTANT_TOOLS,
    supportsConversationContinue: true,
    buildAssistantArgs: (prompt: string, options?: { continue?: boolean }) => {
      // No --allowedTools flag: inherits ALL tools from host MCP configuration
      const args = [
        '--print',
        '--output-format', 'stream-json',
        '--verbose',
        '--dangerously-skip-permissions',
      ];
      if (options?.continue) {
        args.push('--continue');
      }
      args.push(prompt);
      return args;
    },
  },
  copilot: {
    outputFormat: null, // Copilot uses plain text output
    readOnlyTools: COPILOT_ASSISTANT_TOOLS,
    supportsConversationContinue: true, // Copilot supports --continue
    buildAssistantArgs: (prompt: string, options?: { continue?: boolean }) => {
      // Full MCP tool passthrough: --allow-all-tools inherits all host MCP tools
      // --no-color removes ANSI escape codes; --silent removed to preserve stderr status output
      const args = [
        '--prompt', prompt,
        '--allow-all-tools',
        '--allow-all-paths',
        '--no-color',
      ];
      if (options?.continue) {
        args.push('--continue');
      }
      return args;
    },
  },
};

/**
 * Get the configured agent type from environment
 * Defaults to 'claude' if not specified or invalid
 */
export function getAgentType(): AgentType {
  const envType = process.env.AGENT_TYPE?.toLowerCase();
  if (envType === 'copilot') {
    return 'copilot';
  }
  return 'claude';
}

/**
 * Get the agent configuration for the configured agent type
 */
export function getAgentConfig(): AgentConfig {
  const agentType = getAgentType();
  const config = AGENTS[agentType];

  // Override command if AGENT_COMMAND is set
  const command = process.env.AGENT_COMMAND || config.command;

  return {
    ...config,
    command,
  };
}

/**
 * Get the CLI command for the configured agent
 */
export function getAgentCommand(): string {
  return getAgentConfig().command;
}

/**
 * Build CLI arguments for the configured agent
 */
export function buildAgentArgs(prompt: string): string[] {
  return getAgentConfig().buildArgs(prompt);
}

/**
 * Get the skills directory path for the configured agent
 */
export function getAgentSkillsDir(): string {
  return getAgentConfig().skillsDir;
}

/**
 * Get a human-readable name for the configured agent
 */
export function getAgentDisplayName(): string {
  const agentType = getAgentType();
  switch (agentType) {
    case 'claude':
      return 'Claude Code CLI';
    case 'copilot':
      return 'GitHub Copilot CLI';
    default:
      return agentType;
  }
}

/**
 * Validate that required environment variables are set for the agent
 * Returns an array of missing variable names, or empty array if all set
 */
export function validateAgentEnv(): string[] {
  const config = getAgentConfig();
  const missing: string[] = [];

  for (const [key, value] of Object.entries(config.envVars)) {
    if (value === undefined && !process.env[key]) {
      missing.push(key);
    }
  }

  return missing;
}

/**
 * Get the assistant configuration for the configured agent type
 */
export function getAssistantConfig(): AssistantConfig {
  const agentType = getAgentType();
  return ASSISTANT_CONFIGS[agentType];
}

/**
 * Build CLI arguments for assistant (read-only) mode
 */
export function buildAssistantArgs(prompt: string, options?: { continue?: boolean }): string[] {
  return getAssistantConfig().buildAssistantArgs(prompt, options);
}

/**
 * Get the output format for the configured agent's assistant mode
 * Returns null if the agent uses plain text output
 */
export function getAssistantOutputFormat(): string | null {
  return getAssistantConfig().outputFormat;
}

/**
 * Check if the configured agent supports conversation continuation (--continue flag)
 */
export function supportsConversationContinue(): boolean {
  return getAssistantConfig().supportsConversationContinue;
}

/**
 * Get the list of read-only tools allowed for the assistant
 */
export function getAssistantReadOnlyTools(): string[] {
  return getAssistantConfig().readOnlyTools;
}

/**
 * Build CLI arguments for messaging assistant mode (no MCP Playwright tools).
 * The messaging subprocess cannot access MCP tools because no MCP server
 * configuration is injected into the spawned process.
 */
export function buildMessagingAssistantArgs(prompt: string, options?: { continue?: boolean }): string[] {
  const agentType = getAgentType();

  if (agentType === 'copilot') {
    const args = [
      '--prompt', prompt,
      '--available-tools', ...COPILOT_MESSAGING_TOOLS,
      '--allow-all-paths',
      '--no-color',
    ];
    if (options?.continue) {
      args.push('--continue');
    }
    return args;
  }

  // Default: claude
  const args = [
    '--print',
    '--output-format', 'stream-json',
    '--verbose',
    '--allowedTools', CLAUDE_MESSAGING_TOOLS.join(','),
    '--dangerously-skip-permissions',
  ];
  if (options?.continue) {
    args.push('--continue');
  }
  args.push(prompt);
  return args;
}

import { execFile } from 'node:child_process';
import { promisify } from 'node:util';
import { getWorkspacePath } from './paths.js';
import { updateTask } from '../services/store.js';

const execFileAsync = promisify(execFile);

/**
 * Create a git auto-save commit before task execution as a rollback safe point.
 * Runs `git add . && git commit --allow-empty` in the workspace and stores the
 * resulting SHA in `task.safePointCommit`. Returns the SHA on success, or null
 * if git is unavailable or the workspace is not a git repository (non-fatal).
 */
export async function createSafePoint(taskId: string): Promise<string | null> {
  const cwd = getWorkspacePath();
  try {
    await execFileAsync('git', ['add', '.'], { cwd });
    await execFileAsync('git', ['commit', '--allow-empty', '-m', `auto-save: before task ${taskId}`], { cwd });
    const { stdout } = await execFileAsync('git', ['rev-parse', 'HEAD'], { cwd });
    const sha = stdout.trim();
    await updateTask(taskId, { safePointCommit: sha });
    console.log(`[Workflow] Safe point commit created for task ${taskId}: ${sha}`);
    return sha;
  } catch (error) {
    console.warn('[Workflow] createSafePoint failed for', taskId + ':', error instanceof Error ? error.message : 'Unknown error');
    return null;
  }
}

import { getQueuedTasks, getAllTasks, getTask, getRunningTasksCount, updateTask } from './store.js';
import { executeFullWorkflow, executeQuickTask, executeGoalWorkflow, executeFromDeclare, isWorkflowRunning } from './workflow.js';
import { isAgentRunning } from './runner.js';
import { wouldConflict } from './leaseManager.js';
import { internalEvents, TASK_COMPLETED, LEASE_RELEASED } from './internalEvents.js';
import { prioritizeQueue } from './prioritizer.js';
import { engineConfig, refreshEngineConfig } from './engineConfig.js';
import type { Task } from '../../types/index.js';

const QUEUE_ENABLED = process.env.QUEUE_ENABLED !== 'false';

const YIELD_BACKOFF_INITIAL_MS = 2000;
const YIELD_BACKOFF_MULTIPLIER = 2;
const YIELD_BACKOFF_MAX_MS = 60_000;

/** Per-task exponential backoff delay (ms) for the next retry after a lease conflict */
const yieldBackoffMs = new Map<string, number>();
/** Per-task earliest timestamp (ms) at which the task may be retried */
const yieldUntil = new Map<string, number>();
/** Maps filePath → Set<taskId> of tasks currently in backoff waiting for that file.
 *  Populated when a task yields with `lease-conflict:<filePath>`. Cleared when the
 *  file is released (via handleLeaseReleased) or the task is dispatched. */
const fileBackoffTasks = new Map<string, Set<string>>();
/** Persistent set of task IDs dispatched in any poll cycle whose workflow has not yet
 * committed to a non-queued status. Prevents cross-cycle re-admission during the async
 * setup window between dispatch and the first status transition. */
const inFlightTasks = new Set<string>();

let pollTimeoutId: ReturnType<typeof setTimeout> | null = null;
let isProcessing = false;

/**
 * Check if we can process another task (concurrency limit check)
 */
async function canProcessTask(): Promise<boolean> {
  const runningCount = await getRunningTasksCount();
  return runningCount < engineConfig.maxConcurrentTasks;
}

/**
 * Process the queue - check for tasks and start execution if slots available.
 * Loops through queued tasks, skipping those that have exceeded maxYieldCount.
 */
async function processQueue(): Promise<void> {
  // Prevent concurrent processing
  if (isProcessing) {
    return;
  }

  isProcessing = true;

  try {
    await refreshEngineConfig();

    // Check if we can process more tasks
    if (!(await canProcessTask())) {
      return;
    }

    // Check if any agent is already running (legacy check for maxConcurrentTasks=1)
    if (engineConfig.maxConcurrentTasks <= 1 && isAgentRunning()) {
      return;
    }

    // Get all queued tasks
    const queuedTasks = await getQueuedTasks();
    if (queuedTasks.length === 0) {
      return;
    }

    // Dependency-aware re-prioritization: elevate tasks on the critical path
    const allTasks = await getAllTasks();
    const prioritizedTasks = prioritizeQueue(queuedTasks, allTasks);

    // Try each queued task until we find one we can start or run out of tasks
    for (const nextTask of prioritizedTasks) {
      // Re-check capacity before each task, including in-flight starts from this and prior cycles
      const runningCount = await getRunningTasksCount();
      if (runningCount + inFlightTasks.size >= engineConfig.maxConcurrentTasks) {
        break;
      }

      // Skip if workflow already running
      if (isWorkflowRunning(nextTask.id)) {
        continue;
      }

      // Skip if already dispatched in a prior poll cycle (cross-cycle re-admission guard)
      if (inFlightTasks.has(nextTask.id)) {
        continue;
      }

      // Skip tasks that are within their exponential backoff window
      if (Date.now() < (yieldUntil.get(nextTask.id) ?? 0)) {
        continue;
      }

      // Check yield count - transition tasks that have yielded too many times to todo
      // so they are visible on the board instead of silently starving in the queue.
      if (nextTask.yieldCount && nextTask.yieldCount >= engineConfig.maxYieldCount) {
        console.warn(`[QueueProcessor] Task ${nextTask.id} exceeded max yield count (${engineConfig.maxYieldCount}), transitioning to todo`);
        try {
          await updateTask(nextTask.id, {
            status: 'todo',
            yieldReason: 'cap-exceeded:max-yield-count',
          });
        } catch (err) {
          console.warn('[QueueProcessor] Failed to transition cap-exceeded task:', err instanceof Error ? err.message : 'Unknown error');
        }
        inFlightTasks.delete(nextTask.id);
        continue;
      }

      // Check retry count - transition tasks that have failed too many times to todo
      if ((nextTask.retryCount ?? 0) >= engineConfig.maxExecutionRetries) {
        console.warn(`[QueueProcessor] Task ${nextTask.id} exceeded max execution retries (${engineConfig.maxExecutionRetries}), transitioning to todo`);
        try {
          await updateTask(nextTask.id, {
            status: 'todo',
            yieldReason: 'cap-exceeded:max-execution-retries',
          });
        } catch (err) {
          console.warn('[QueueProcessor] Failed to transition cap-exceeded task:', err instanceof Error ? err.message : 'Unknown error');
        }
        inFlightTasks.delete(nextTask.id);
        continue;
      }

      // Detect the first exclusive file currently held by another task
      const exclusiveFiles = nextTask.declaredFiles?.exclusive ?? [];
      let conflictingFile: string | null = null;
      for (const filePath of exclusiveFiles) {
        if (wouldConflict(filePath, nextTask.id)) {
          conflictingFile = filePath;
          break;
        }
      }

      if (conflictingFile !== null) {
        // Compute and record exponential backoff
        const prevBackoff = yieldBackoffMs.get(nextTask.id) ?? (YIELD_BACKOFF_INITIAL_MS / YIELD_BACKOFF_MULTIPLIER);
        const nextBackoff = Math.min(prevBackoff * YIELD_BACKOFF_MULTIPLIER, YIELD_BACKOFF_MAX_MS);
        yieldBackoffMs.set(nextTask.id, nextBackoff);
        yieldUntil.set(nextTask.id, Date.now() + nextBackoff);

        // Track file→backoff mapping for targeted reset on LEASE_RELEASED
        const fileSet = fileBackoffTasks.get(conflictingFile) ?? new Set<string>();
        fileSet.add(nextTask.id);
        fileBackoffTasks.set(conflictingFile, fileSet);

        // Set firstBlockedAt fairness timestamp if not already set for this contention
        const now = new Date().toISOString();
        const updates: Record<string, unknown> = { yieldReason: `lease-conflict:${conflictingFile}` };
        if (!nextTask.firstBlockedAt) {
          updates.firstBlockedAt = now;
        }

        const reason = `lease-conflict:${conflictingFile}`;
        console.log(`[QueueProcessor] Task ${nextTask.id} yielding — ${reason} (backoff ${nextBackoff}ms)`);
        try {
          await updateTask(nextTask.id, updates);
        } catch (err) {
          console.warn('[QueueProcessor] Failed to persist yieldReason:', err instanceof Error ? err.message : 'Unknown error');
        }
        // Continue scanning — do not wait for next poll cycle
        continue;
      }

      console.log(`[QueueProcessor] Starting task ${nextTask.id}: ${nextTask.title}`);

      // Clear any stale backoff state for this task before dispatching
      clearTaskBackoff(nextTask.id);

      // Mark as in-flight synchronously before any await so the cross-cycle guard
      // is effective during the async setup window between dispatch and the first
      // non-queued status transition.
      inFlightTasks.add(nextTask.id);

      // Reload the task from the board immediately before routing so that
      // resumeFromStep reflects the persisted state, not the snapshot loaded
      // at the start of the poll cycle (which may be stale).
      const freshTask = await getTask(nextTask.id);

      // Check task type and execute appropriate workflow
      if (nextTask.type === 'quick') {
        console.log(`[QueueProcessor] Task ${nextTask.id} is a quick task - skipping brief/plan stages`);
        await executeQuickTask(nextTask.id);
      } else if (nextTask.type === 'goal') {
        console.log(`[QueueProcessor] Task ${nextTask.id} is a goal task - running architect decomposition`);
        await executeGoalWorkflow(nextTask.id);
      } else if (freshTask?.resumeFromStep === 'declare' || freshTask?.resumeFromStep === 'execute') {
        console.log(`[QueueProcessor] Task ${nextTask.id} resuming from ${freshTask.resumeFromStep} step (skipping brief/plan)`);
        await executeFromDeclare(nextTask.id);
      } else {
        await executeFullWorkflow(nextTask.id);
      }

      // For single-task mode, only start one task per poll cycle
      if (engineConfig.maxConcurrentTasks <= 1) {
        break;
      }
    }

  } catch (error) {
    const err = error as Error;
    console.error('[QueueProcessor] Error processing queue:', err.message);
  } finally {
    isProcessing = false;
  }
}

/**
 * Wake the queue processor immediately — bypasses the polling interval.
 * Called when a task completes or leases are released so queued tasks
 * can proceed without waiting for the next poll tick.
 */
export function wakeQueueProcessor(): void {
  if (!QUEUE_ENABLED || isProcessing) {
    return;
  }
  console.log('[QueueProcessor] Woken by event');
  void processQueue();
}

/**
 * Clear all in-memory backoff state for a single task. Called when the task
 * is dispatched (lease acquired) or when its backoff is reset via LEASE_RELEASED.
 */
function clearTaskBackoff(taskId: string): void {
  yieldBackoffMs.delete(taskId);
  yieldUntil.delete(taskId);

  // Remove from all fileBackoffTasks entries
  for (const [filePath, taskSet] of fileBackoffTasks.entries()) {
    taskSet.delete(taskId);
    if (taskSet.size === 0) {
      fileBackoffTasks.delete(filePath);
    }
  }

  // Clear firstBlockedAt on the persisted task so it doesn't carry over
  // to the next contention. Fire-and-forget — best-effort.
  updateTask(taskId, { firstBlockedAt: null }).catch(err =>
    console.warn('[QueueProcessor] Failed to clear firstBlockedAt:', err instanceof Error ? err.message : 'Unknown error')
  );
}

/**
 * Reset all backoff state for a task — exported for external callers (e.g.,
 * manual re-queue) that need to clear in-memory backoff in addition to the
 * persisted counters reset by store.queueTask().
 */
export function resetBackoff(taskId: string): void {
  clearTaskBackoff(taskId);
}

/**
 * Handle LEASE_RELEASED events: for each released file, clear the backoff
 * window of any task that was waiting on it, so the next poll/wake cycle
 * can immediately attempt re-dispatch instead of skipping the waiter due to
 * an unexpired yieldUntil.
 */
function handleLeaseReleased(_releasingTaskId: string, releasedFiles: string[]): void {
  if (!releasedFiles || releasedFiles.length === 0) return;

  let cleared = 0;
  for (const filePath of releasedFiles) {
    const waitingTasks = fileBackoffTasks.get(filePath);
    if (!waitingTasks || waitingTasks.size === 0) continue;

    for (const taskId of waitingTasks) {
      clearTaskBackoff(taskId);
      cleared++;
    }
    fileBackoffTasks.delete(filePath);
  }

  if (cleared > 0) {
    console.log(`[QueueProcessor] LEASE_RELEASED: cleared backoff for ${cleared} task(s) across ${releasedFiles.length} file(s)`);
  }

  // Wake the queue processor after clearing backoffs so blocked tasks get a chance
  wakeQueueProcessor();
}

function schedulePoll(): void {
  pollTimeoutId = setTimeout(async () => {
    await processQueue();
    if (pollTimeoutId !== null) {
      schedulePoll();
    }
  }, engineConfig.queuePollIntervalMs);
}

/**
 * Start the queue processor polling loop
 */
export function startQueueProcessor(): void {
  if (!QUEUE_ENABLED) {
    console.log('[QueueProcessor] Queue processing is disabled (QUEUE_ENABLED=false)');
    return;
  }

  if (pollTimeoutId !== null) {
    console.log('[QueueProcessor] Queue processor already running');
    return;
  }

  console.log(`[QueueProcessor] Starting queue processor (poll: ${engineConfig.queuePollIntervalMs}ms, max concurrent: ${engineConfig.maxConcurrentTasks})`);

  // Subscribe to internal wake events
  internalEvents.on(TASK_COMPLETED, wakeQueueProcessor);
  internalEvents.on(LEASE_RELEASED, handleLeaseReleased);

  // Run immediately on start
  processQueue();

  // Set up recursive polling
  schedulePoll();
}

/**
 * Stop the queue processor polling loop
 */
export function stopQueueProcessor(): void {
  if (pollTimeoutId !== null) {
    clearTimeout(pollTimeoutId);
    pollTimeoutId = null;

    // Unsubscribe internal wake event listeners
    internalEvents.off(TASK_COMPLETED, wakeQueueProcessor);
    internalEvents.off(LEASE_RELEASED, handleLeaseReleased);

    console.log('[QueueProcessor] Queue processor stopped');
  }
}

/**
 * Pause the queue processor (called by the kill switch after max retries).
 */
export function pauseQueueProcessor(): void {
  stopQueueProcessor();
  console.log('[QueueProcessor] Queue paused by kill switch');
}

/**
 * Check if queue processor is running
 */
export function isQueueProcessorRunning(): boolean {
  return pollTimeoutId !== null;
}

/**
 * Remove a task from the inFlightTasks set once its workflow has committed to a
 * non-queued status. Called by workflow.ts on every status-transition exit path
 * (including yield-back-to-queued, error, success, and stop) so no entries leak.
 */
export function removeInFlightTask(taskId: string): void {
  inFlightTasks.delete(taskId);
}

/**
 * Get queue processor configuration
 */
export function getQueueProcessorConfig(): {
  enabled: boolean;
  pollInterval: number;
  maxConcurrent: number;
  isRunning: boolean;
} {
  return {
    enabled: QUEUE_ENABLED,
    pollInterval: engineConfig.queuePollIntervalMs,
    maxConcurrent: engineConfig.maxConcurrentTasks,
    isRunning: isQueueProcessorRunning(),
  };
}

/**
 * Get the position of a task in the queue (1-indexed)
 * Returns 0 if the task is not in the queue
 */
export async function getQueuePosition(taskId: string): Promise<number> {
  const queuedTasks = await getQueuedTasks();
  const index = queuedTasks.findIndex(t => t.id === taskId);
  return index === -1 ? 0 : index + 1;
}

import type { Task, MessagingSession, OutgoingMessage } from '../../types/index.js';
import { getSessionsByWorkspace } from './messagingStore.js';
import { formatTaskNotification } from './messagingAdapter.js';
import { sendTelegramNotification, isTelegramConfigured } from './telegramAdapter.js';
import { sendLineNotification, isLineConfigured } from './lineAdapter.js';
import { getWorkspacePath } from '../utils/paths.js';

/**
 * Messaging Notifier Service
 *
 * Sends notifications to linked messaging sessions when task status changes.
 * Integrates with the boardNotifier system to receive task events.
 */

// Track previous task statuses to detect changes
const taskStatusCache = new Map<string, Task['status']>();

/**
 * Send a notification to a specific session
 */
async function sendNotificationToSession(
  session: MessagingSession,
  message: OutgoingMessage
): Promise<void> {
  const notificationMessage = { ...message, chatId: session.chatId };

  switch (session.platform) {
    case 'telegram':
      if (isTelegramConfigured()) {
        await sendTelegramNotification(session.chatId, notificationMessage);
      }
      break;
    case 'line':
      if (isLineConfigured()) {
        await sendLineNotification(session.chatId, notificationMessage);
      }
      break;
  }
}

/**
 * Notify all relevant sessions about a task event
 */
async function notifyTaskEvent(
  task: Task,
  event: 'completed' | 'failed' | 'review'
): Promise<void> {
  const workspacePath = getWorkspacePath();
  const sessions = await getSessionsByWorkspace(workspacePath);

  if (sessions.length === 0) {
    return;
  }

  const notification = formatTaskNotification(task, event);

  // Filter sessions based on notification preferences
  const eligibleSessions = sessions.filter((session) => {
    switch (event) {
      case 'completed':
        return session.notifications.onTaskComplete;
      case 'failed':
        return session.notifications.onTaskFailed;
      case 'review':
        return session.notifications.onReviewReady;
      default:
        return false;
    }
  });

  console.log(`[MessagingNotifier] Sending '${event}' notification for task ${task.id} to ${eligibleSessions.length} sessions`);

  // Send notifications to all eligible sessions
  await Promise.all(
    eligibleSessions.map((session) => sendNotificationToSession(session, notification))
  );
}

/**
 * Check if a task status changed and send appropriate notifications
 */
export async function checkTaskStatusChange(task: Task): Promise<void> {
  const previousStatus = taskStatusCache.get(task.id);
  const currentStatus = task.status;

  // Update cache
  taskStatusCache.set(task.id, currentStatus);

  // No previous status means this is a new task - no notification needed
  if (!previousStatus) {
    return;
  }

  // Status didn't change
  if (previousStatus === currentStatus) {
    return;
  }

  console.log(`[MessagingNotifier] Task ${task.id} status changed: ${previousStatus} -> ${currentStatus}`);

  // Determine notification type based on transition
  if (currentStatus === 'done') {
    // Task completed successfully
    await notifyTaskEvent(task, 'completed');
  } else if (currentStatus === 'review' && previousStatus !== 'done') {
    // Task moved to review (could be success or failure)
    // Check if it came from an active state (might indicate failure)
    const activeStates: Task['status'][] = ['briefing', 'planning', 'running'];
    if (activeStates.includes(previousStatus)) {
      // Check workflow step to determine if it completed normally
      if (task.workflowStep === 'complete') {
        await notifyTaskEvent(task, 'review');
      } else {
        // Task was stopped or failed mid-workflow
        await notifyTaskEvent(task, 'failed');
      }
    } else {
      await notifyTaskEvent(task, 'review');
    }
  }
}

/**
 * Initialize status cache with current tasks
 * Called at server startup to avoid false notifications
 */
export function initializeStatusCache(tasks: Task[]): void {
  taskStatusCache.clear();
  for (const task of tasks) {
    taskStatusCache.set(task.id, task.status);
  }
  console.log(`[MessagingNotifier] Initialized status cache with ${tasks.length} tasks`);
}

/**
 * Clear status cache (for testing)
 */
export function clearStatusCache(): void {
  taskStatusCache.clear();
}

/**
 * Get current cache size (for debugging)
 */
export function getStatusCacheSize(): number {
  return taskStatusCache.size;
}

/**
 * Check all tasks for status changes
 * This can be called periodically or after board updates
 */
export async function checkAllTasksForChanges(tasks: Task[]): Promise<void> {
  for (const task of tasks) {
    await checkTaskStatusChange(task);
  }
}

/**
 * Send a custom notification to all sessions for a workspace
 */
export async function broadcastToWorkspace(
  workspacePath: string,
  message: OutgoingMessage
): Promise<void> {
  const sessions = await getSessionsByWorkspace(workspacePath);

  if (sessions.length === 0) {
    return;
  }

  console.log(`[MessagingNotifier] Broadcasting to ${sessions.length} sessions`);

  await Promise.all(
    sessions.map((session) => sendNotificationToSession(session, message))
  );
}

/**
 * Send a test notification to verify messaging is working
 */
export async function sendTestNotification(
  workspacePath: string
): Promise<{ sent: number; failed: number }> {
  const sessions = await getSessionsByWorkspace(workspacePath);

  const results = { sent: 0, failed: 0 };

  const testMessage: OutgoingMessage = {
    chatId: '',
    text: '🧪 *Test Notification*\n\nThis is a test message from Formic. If you see this, notifications are working!',
    parseMode: 'markdown',
  };

  for (const session of sessions) {
    try {
      await sendNotificationToSession(session, testMessage);
      results.sent++;
    } catch (error) {
      results.failed++;
    }
  }

  return results;
}

/**
 * Memory Store Service
 * Persists structured memory entries to .formic/memory.json.
 * Used by the reflection step to record learnings and pitfalls after task completion.
 */
import { readFile, writeFile, mkdir } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import { randomUUID } from 'node:crypto';
import { getFormicDir } from '../utils/paths.js';
import type { MemoryEntry, MemoryStore, Task } from '../../types/index.js';

export const MAX_RELEVANT_MEMORIES = 5;

function getMemoryPath(): string {
  return path.join(getFormicDir(), 'memory.json');
}

/**
 * Load the memory store from disk.
 * Returns a default empty store if the file does not exist.
 */
export async function loadMemoryStore(): Promise<MemoryStore> {
  const memoryPath = getMemoryPath();

  if (!existsSync(memoryPath)) {
    return { version: '1.0', entries: [] };
  }

  try {
    const content = await readFile(memoryPath, 'utf-8');
    const parsed = JSON.parse(content) as unknown;
    if (
      typeof parsed === 'object' &&
      parsed !== null &&
      'version' in parsed &&
      'entries' in parsed &&
      Array.isArray((parsed as { entries: unknown }).entries)
    ) {
      return parsed as MemoryStore;
    }
    console.warn('[Memory] memory.json has unexpected structure, returning empty store');
    return { version: '1.0', entries: [] };
  } catch (error) {
    console.warn('[Memory] Failed to load memory store:', error);
    return { version: '1.0', entries: [] };
  }
}

/**
 * Persist the memory store to disk.
 * Creates the .formic/ directory if it does not exist.
 */
export async function saveMemoryStore(store: MemoryStore): Promise<void> {
  await mkdir(getFormicDir(), { recursive: true });
  await writeFile(getMemoryPath(), JSON.stringify(store, null, 2), 'utf-8');
}

/**
 * Append a new memory entry to the store and persist it.
 * Generates a unique id and created_at timestamp automatically.
 */
export async function addMemory(
  entry: Omit<MemoryEntry, 'id' | 'created_at'>
): Promise<MemoryEntry> {
  const newEntry: MemoryEntry = {
    id: 'mem-' + randomUUID(),
    created_at: new Date().toISOString(),
    ...entry,
  };
  const store = await loadMemoryStore();
  store.entries.push(newEntry);
  await saveMemoryStore(store);
  console.log(`[Memory] Added memory entry ${newEntry.id} (type: ${newEntry.type}) for task ${newEntry.source_task}`);
  return newEntry;
}

/**
 * Return all memory entries from the store.
 */
export async function getMemories(): Promise<MemoryEntry[]> {
  const store = await loadMemoryStore();
  return store.entries;
}

/**
 * Compute a relevance score for a single memory entry against a task.
 * - Tag overlap: +1 per relevance_tag (case-insensitive) matching a declared file path or title keyword
 * - Recency bonus: +2 if entry was created within the last 7 days
 */
function scoreMemory(entry: MemoryEntry, task: Task): number {
  const declaredPaths = [
    ...(task.declaredFiles?.exclusive ?? []),
    ...(task.declaredFiles?.shared ?? []),
  ].map(p => p.toLowerCase());

  const titleKeywords = task.title
    .split(/[\s\-_]+/)
    .map(w => w.toLowerCase())
    .filter(w => w.length > 0);

  let score = 0;
  for (const tag of entry.relevance_tags) {
    const lowerTag = tag.toLowerCase();
    if (declaredPaths.some(p => p === lowerTag) || titleKeywords.some(k => k === lowerTag)) {
      score += 1;
    }
  }

  const SEVEN_DAYS_MS = 7 * 24 * 60 * 60 * 1000;
  if (Date.now() - new Date(entry.created_at).getTime() < SEVEN_DAYS_MS) {
    score += 2;
  }

  return score;
}

/**
 * Return memory entries most relevant to the given task, scored and ranked.
 *
 * Scoring strategy:
 * - Tag overlap: +1 per relevance_tag matching a declared file path or title keyword (case-insensitive)
 * - Recency bonus: +2 if entry was created within the last 7 days
 *
 * Only entries with score > 0 are returned, sorted descending by score,
 * capped at MAX_RELEVANT_MEMORIES results.
 */
export async function getRelevantMemories(task: Task): Promise<MemoryEntry[]> {
  const entries = await getMemories();
  return entries
    .map(entry => ({ entry, score: scoreMemory(entry, task) }))
    .filter(({ score }) => score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, MAX_RELEVANT_MEMORIES)
    .map(({ entry }) => entry);
}

/**
 * Tool Catalog Service
 * Manages reusable agent-created tools stored as individual directories
 * in .formic/tools/<tool-name>/ with a manifest.json and script files.
 */
import { readFile, writeFile, mkdir, readdir } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import { getFormicDir } from '../utils/paths.js';
import type { Tool, ToolManifest } from '../../types/index.js';

/** Returns the absolute path to the .formic/tools/ directory. */
export function getToolsDir(): string {
  return path.join(getFormicDir(), 'tools');
}

/** Creates the .formic/tools/ directory if it does not exist. */
async function ensureToolsDir(): Promise<void> {
  await mkdir(getToolsDir(), { recursive: true });
}

/**
 * Type guard that validates an unknown value is a valid ToolManifest.
 * Checks that all required fields exist with correct types.
 */
export function validateToolManifest(manifest: unknown): manifest is ToolManifest {
  if (typeof manifest !== 'object' || manifest === null) return false;
  const m = manifest as Record<string, unknown>;
  return (
    typeof m.name === 'string' && m.name.length > 0 &&
    typeof m.description === 'string' &&
    typeof m.command === 'string' &&
    typeof m.created_by === 'string' &&
    typeof m.usage_count === 'number'
  );
}

/**
 * List all tools in .formic/tools/.
 * Reads each subdirectory's manifest.json, validates it, and returns resolved Tool objects.
 * Skips subdirectories with missing or malformed manifests.
 */
export async function listTools(): Promise<Tool[]> {
  const toolsDir = getToolsDir();
  if (!existsSync(toolsDir)) return [];

  const tools: Tool[] = [];
  let entries: string[];
  try {
    entries = await readdir(toolsDir);
  } catch {
    return [];
  }

  for (const entry of entries) {
    const manifestPath = path.join(toolsDir, entry, 'manifest.json');
    if (!existsSync(manifestPath)) continue;

    try {
      const content = await readFile(manifestPath, 'utf-8');
      const parsed: unknown = JSON.parse(content);
      if (!validateToolManifest(parsed)) {
        console.warn(`[Tools] Skipping tool '${entry}': malformed manifest`);
        continue;
      }
      tools.push({
        name: parsed.name,
        scriptPath: path.join(toolsDir, entry),
        manifestPath,
        manifest: parsed,
      });
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Unknown error';
      console.warn(`[Tools] Skipping tool '${entry}': ${msg}`);
    }
  }

  return tools;
}

/**
 * Get a single tool by name.
 * Returns null if the tool directory or manifest does not exist.
 */
export async function getTool(name: string): Promise<Tool | null> {
  const toolsDir = getToolsDir();
  const manifestPath = path.join(toolsDir, name, 'manifest.json');
  if (!existsSync(manifestPath)) return null;

  try {
    const content = await readFile(manifestPath, 'utf-8');
    const parsed: unknown = JSON.parse(content);
    if (!validateToolManifest(parsed)) {
      console.warn(`[Tools] Tool '${name}' has malformed manifest`);
      return null;
    }
    return {
      name: parsed.name,
      scriptPath: path.join(toolsDir, name),
      manifestPath,
      manifest: parsed,
    };
  } catch (err) {
    const msg = err instanceof Error ? err.message : 'Unknown error';
    console.warn(`[Tools] Failed to load tool '${name}': ${msg}`);
    return null;
  }
}

/**
 * Increment usage_count in a tool's manifest.json.
 * No-ops silently if the tool is not found.
 */
export async function recordToolUsage(name: string): Promise<void> {
  const toolsDir = getToolsDir();
  const manifestPath = path.join(toolsDir, name, 'manifest.json');
  if (!existsSync(manifestPath)) return;

  try {
    const content = await readFile(manifestPath, 'utf-8');
    const parsed: unknown = JSON.parse(content);
    if (!validateToolManifest(parsed)) return;

    const updated: ToolManifest = { ...parsed, usage_count: parsed.usage_count + 1 };
    await writeFile(manifestPath, JSON.stringify(updated, null, 2), 'utf-8');
    console.log(`[Tools] Incremented usage for ${name}`);
  } catch (err) {
    const msg = err instanceof Error ? err.message : 'Unknown error';
    console.warn(`[Tools] Failed to record usage for '${name}': ${msg}`);
  }
}

/**
 * Register a new tool by creating a subdirectory with manifest.json.
 * Throws if the tool already exists or input is invalid.
 */
export async function addTool(input: { name: string; description: string; command: string; created_by: string }): Promise<Tool> {
  if (!input.name || !/^[a-z0-9-]+$/.test(input.name)) {
    throw new Error('[Tools] name must be a non-empty slug containing only lowercase letters, digits, and hyphens');
  }
  if (!input.description || !input.command) {
    throw new Error('[Tools] description and command are required');
  }

  const toolsDir = getToolsDir();
  const toolDir = path.join(toolsDir, input.name);
  const manifestPath = path.join(toolDir, 'manifest.json');

  if (existsSync(toolDir)) {
    throw new Error(`[Tools] A tool named '${input.name}' already exists`);
  }

  await ensureToolsDir();
  await mkdir(toolDir, { recursive: true });

  const manifest: ToolManifest = {
    name: input.name,
    description: input.description,
    command: input.command,
    created_by: input.created_by,
    usage_count: 0,
  };

  await writeFile(manifestPath, JSON.stringify(manifest, null, 2), 'utf-8');
  console.log(`[Tools] Added tool ${manifest.name}`);

  return {
    name: manifest.name,
    scriptPath: toolDir,
    manifestPath,
    manifest,
  };
}

