  {
    name: 'verify',
    displayName: 'Verifying',
    skillName: 'verify',
    taskStatus: 'verifying',
    workflowStep: 'verify',
    source: 'builtin',
    order: 1,
  },
];

const GOAL_PIPELINE: WorkflowPipeline = [
  {
    name: 'architect',
    displayName: 'Architecting',
    skillName: 'architect',
    taskStatus: 'architecting',
    workflowStep: 'architect',
    source: 'builtin',
    order: 0,
  },
];

// ==================== Plugin Stage Registry ====================

/** Plugin-registered stages, keyed by plugin name */
const pluginStages = new Map<string, StageDescriptor[]>();

/** Plugin-provided custom handler functions, keyed by stage name */
const pluginHandlers = new Map<string, (taskId: string) => Promise<void>>();

// ==================== Custom Task Type Registry ====================

/** Plugin-registered custom task types, keyed by task type ID */
const customTaskTypes = new Map<string, TaskTypeDefinition & { pluginName: string }>();

/** Compiled pipelines for custom task types, keyed by task type ID */
const customPipelines = new Map<string, WorkflowPipeline>();

// ==================== Public API ====================

/**
 * Returns a deep copy of the default pipeline for a given task type.
 */
export function getDefaultPipeline(taskType: TaskType | string): WorkflowPipeline {
  switch (taskType) {
    case 'standard':
      return structuredClone(STANDARD_PIPELINE);
    case 'quick':
      return structuredClone(QUICK_PIPELINE);
    case 'goal':
      return structuredClone(GOAL_PIPELINE);
    default: {
      const custom = customPipelines.get(taskType);
      if (custom) {
        return structuredClone(custom);
      }
      console.warn(`[Pipeline] Unknown task type '${taskType}', returning standard pipeline`);
      return structuredClone(STANDARD_PIPELINE);
    }
  }
}

/**
 * Returns the default pipeline merged with any plugin-registered stages,
 * sorted by order.
 */
export function getActivePipeline(taskType: TaskType | string): WorkflowPipeline {
  const pipeline = getDefaultPipeline(taskType);

  // For custom task types, return their pipeline as-is (they define their own stages)
  if (customPipelines.has(taskType)) {
    return pipeline;
  }

  // Collect all plugin stages
  const allPluginStages: StageDescriptor[] = [];
  for (const stages of pluginStages.values()) {
    allPluginStages.push(...stages);
  }

  if (allPluginStages.length === 0) {
    return pipeline;
  }

  // Insert each plugin stage after its declared anchor
  for (const pluginStage of allPluginStages) {
    // Find the anchor stage in the current pipeline by matching the 'after' position
    // Plugin stages store their anchor in the handler field during registration
    // We need to find where to insert based on order
    pipeline.push(pluginStage);
  }

  // Re-sort by order and re-number
  pipeline.sort((a, b) => a.order - b.order);
  for (let i = 0; i < pipeline.length; i++) {
    pipeline[i].order = i;
  }

  return pipeline;
}

const BUILTIN_TASK_TYPES = new Set(['standard', 'quick', 'goal']);

/**
 * Registers a custom pipeline for a task type.
 * Lower-level function; stores stages directly into the custom pipeline map.
 * Rejects built-in task types to prevent overriding core workflows.
 */
export function registerCustomPipeline(taskType: string, stages: StageDescriptor[]): void {
  if (BUILTIN_TASK_TYPES.has(taskType)) {
    throw new Error(`[Pipeline] Cannot override built-in task type '${taskType}'`);
  }
  const pipeline: WorkflowPipeline = stages.map((stage, index) => ({
    ...stage,
    source: 'plugin' as const,
    order: index,
  }));
  customPipelines.set(taskType, pipeline);
  console.warn(`[Pipeline] Registered custom pipeline for task type '${taskType}'`);
}

/**
 * Removes the custom pipeline for a specific task type.
 * Returns true if a pipeline existed and was removed.
 */
export function unregisterCustomPipeline(taskType: string): boolean {
  const existed = customPipelines.has(taskType);
  if (existed) {
    customPipelines.delete(taskType);
    console.warn(`[Pipeline] Unregistered custom pipeline for task type '${taskType}'`);
  }
  return existed;
}

/**
 * Registers a custom task type contributed by a plugin.
 * Validates uniqueness against built-in types and previously registered types.
 */
export function registerTaskType(definition: TaskTypeDefinition, pluginName: string): void {
  if (BUILTIN_TASK_TYPES.has(definition.id)) {
    throw new Error(`[Pipeline] Cannot override built-in task type '${definition.id}'`);
  }
  if (customTaskTypes.has(definition.id)) {
    throw new Error(`[Pipeline] Task type '${definition.id}' is already registered`);
  }

  registerCustomPipeline(definition.id, definition.workflow);
  // Annotate the pipeline entries with the plugin name
  const pipeline = customPipelines.get(definition.id)!;
  customPipelines.set(definition.id, pipeline.map(stage => ({ ...stage, pluginName })));

  customTaskTypes.set(definition.id, { ...definition, pluginName });

  console.warn(`[Pipeline] Registered custom task type '${definition.id}' from plugin '${pluginName}'`);
  internalEvents.emit(TASK_TYPE_REGISTERED, { taskTypeId: definition.id, pluginName });
}

/**
 * Removes all custom task types registered by a given plugin.
 * Returns the count of removed task types.
 */
export function unregisterTaskTypes(pluginName: string): number {
  let count = 0;
  for (const [id, entry] of customTaskTypes) {
    if (entry.pluginName === pluginName) {
      customTaskTypes.delete(id);
      customPipelines.delete(id);
      count++;
    }
  }
  if (count > 0) {
    console.warn(`[Pipeline] Unregistered ${count} task type(s) from plugin '${pluginName}'`);
  }
  return count;
}

/** Canonical alias for registerTaskType, as specified in the requirements. */
export const registerCustomTaskType = registerTaskType;

/** Canonical alias for unregisterTaskTypes, as specified in the requirements. */
export const unregisterCustomTaskTypes = unregisterTaskTypes;

/**
 * Returns all registered custom task types.
 */
export function getCustomTaskTypes(): TaskTypeDefinition[] {
  return [...customTaskTypes.values()].map(({ pluginName: _pluginName, ...def }) => def);
}

/**
 * Registers a plugin stage into the pipeline, inserted after the named anchor stage.
 * Validates uniqueness and anchor existence.
 */
export function registerStage(registration: StageRegistration, pluginName: string): StageDescriptor {
  // Check for duplicate stage name across all pipelines
  const allStageNames = new Set<string>();
  for (const stage of STANDARD_PIPELINE) allStageNames.add(stage.name);
  for (const stage of QUICK_PIPELINE) allStageNames.add(stage.name);
  for (const stage of GOAL_PIPELINE) allStageNames.add(stage.name);
  for (const stages of pluginStages.values()) {
    for (const stage of stages) allStageNames.add(stage.name);
  }

  if (allStageNames.has(registration.name)) {
    throw new Error(`[Pipeline] Stage name '${registration.name}' is already registered`);
  }

  // Validate the anchor stage exists in at least one default pipeline
  const allDefaultStages = [...STANDARD_PIPELINE, ...QUICK_PIPELINE, ...GOAL_PIPELINE];
  const allExistingStages = [...allDefaultStages];
  for (const stages of pluginStages.values()) {
    allExistingStages.push(...stages);
  }

  const anchorStage = allExistingStages.find(s => s.name === registration.after);
  if (!anchorStage) {
    throw new Error(`[Pipeline] Anchor stage '${registration.after}' does not exist`);
  }

  // Create the stage descriptor
  const descriptor: StageDescriptor = {
    name: registration.name,
    displayName: registration.displayName,
    skillName: registration.name,
    taskStatus: registration.name,
    workflowStep: registration.name,
    source: 'plugin',
    pluginName,
    order: anchorStage.order + 0.5, // Insert after anchor; will be re-numbered on getActivePipeline
  };

  // Store custom handler function if provided
  if (registration.handler) {
    pluginHandlers.set(registration.name, registration.handler);
  }

  // Store under plugin name
  if (!pluginStages.has(pluginName)) {
    pluginStages.set(pluginName, []);
  }
  pluginStages.get(pluginName)!.push(descriptor);

  // Allow the custom taskStatus to pass board validation
  if (!VALID_TASK_STATUSES.includes(descriptor.taskStatus)) {
    VALID_TASK_STATUSES.push(descriptor.taskStatus);
  }

  console.warn(`[Pipeline] Registered stage '${registration.name}' from plugin '${pluginName}' after '${registration.after}'`);
  internalEvents.emit(STAGE_REGISTERED, { stageName: registration.name, pluginName });

  return descriptor;
}

/**
 * Removes all stages registered by a given plugin.
 * Returns the count of removed stages.
 */
export function unregisterStages(pluginName: string): number {
  const stages = pluginStages.get(pluginName);
  if (!stages) return 0;

  const count = stages.length;
  // Clean up handler functions for removed stages
  for (const stage of stages) {
    pluginHandlers.delete(stage.name);
  }
  pluginStages.delete(pluginName);

  // Remove plugin-contributed statuses that are no longer referenced by any remaining stage
  const remainingStatuses = new Set<string>(
    [...pluginStages.values()].flatMap(ss => ss.map(s => s.taskStatus))
  );
  for (const stage of stages) {
    if (!remainingStatuses.has(stage.taskStatus)) {
      const idx = VALID_TASK_STATUSES.indexOf(stage.taskStatus);
      if (idx !== -1) VALID_TASK_STATUSES.splice(idx, 1);
    }
  }

  console.warn(`[Pipeline] Unregistered ${count} stage(s) from plugin '${pluginName}'`);
  return count;
}

/**
 * Returns all currently registered stages (built-in + plugin).
 */
export function getRegisteredStages(): StageDescriptor[] {
  const allStages: StageDescriptor[] = [
    ...structuredClone(STANDARD_PIPELINE),
    ...structuredClone(QUICK_PIPELINE),
    ...structuredClone(GOAL_PIPELINE),
  ];

  // Deduplicate built-in stages (execute/verify appear in multiple pipelines)
  const seen = new Set<string>();
  const deduped: StageDescriptor[] = [];
  for (const stage of allStages) {
    if (!seen.has(stage.name)) {
      seen.add(stage.name);
      deduped.push(stage);
    }
  }

  // Add plugin stages
  for (const stages of pluginStages.values()) {
    deduped.push(...structuredClone(stages));
  }

  return deduped;
}

/**
 * Returns the custom handler function for a plugin stage, if one was registered.
 */
export function getStageHandler(stageName: string): ((taskId: string) => Promise<void>) | undefined {
  return pluginHandlers.get(stageName);
}

import { readFile, writeFile, mkdir, rename } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import crypto from 'node:crypto';
import type { FormicConfig, ConfigWorkspace, ConfigSettings, PluginConfig } from '../../types/index.js';
import { getGlobalFormicDir, getGlobalConfigPath } from '../utils/paths.js';

/**
 * Config Store Service
 *
 * Manages persistent global configuration at ~/.formic/config.json.
 * Provides CRUD operations for workspaces, active workspace, and settings.
 * Uses atomic writes (temp file + fs.rename) to prevent corruption.
 */

/** Preset color palette for workspace differentiation */
const COLOR_PALETTE = [
  '#8b5cf6', // Purple
  '#10b981', // Green
  '#3b82f6', // Blue
  '#f59e0b', // Orange
  '#ec4899', // Pink
  '#06b6d4', // Cyan
];

/**
 * Create a default config structure
 */
function createDefaultConfig(): FormicConfig {
  return {
    version: 1,
    workspaces: [],
    activeWorkspaceId: null,
    settings: {
      maxConcurrentSessions: 1,
      theme: 'dark',
      notificationsEnabled: true,
      projectBriefCollapsed: false,
      verifyCommand: '',
      skipVerify: false,
      maxExecuteIterations: 5,
      stepTimeoutMs: 6000000,
      queuePollIntervalMs: 5000,
      maxYieldCount: 50,
      leaseDurationMs: 300000,
      watchdogIntervalMs: 30000,
    },
    plugins: {},
  };
}

/**
 * Ensure the global ~/.formic/ directory exists
 */
async function ensureGlobalFormicDir(): Promise<void> {
  const dir = getGlobalFormicDir();
  if (!existsSync(dir)) {
    await mkdir(dir, { recursive: true });
    console.log('[ConfigStore] Created global config directory:', dir);
  }
}

/**
 * Determines the next available color from the palette
 */
function getNextColor(workspaces: ConfigWorkspace[]): string {
  const usedColors = new Set(workspaces.map(ws => ws.color));
  for (const color of COLOR_PALETTE) {
    if (!usedColors.has(color)) {
      return color;
    }
  }
  return COLOR_PALETTE[workspaces.length % COLOR_PALETTE.length];
}

/**
 * Extract the basename from a path for workspace naming
 */
function getBasename(filePath: string): string {
  return path.basename(filePath) || 'Unknown';
}

/**
 * Load the global config from ~/.formic/config.json.
 * Returns default config if the file doesn't exist or is invalid.
 */
export async function loadConfig(): Promise<FormicConfig> {
  await ensureGlobalFormicDir();

  const configPath = getGlobalConfigPath();

  if (!existsSync(configPath)) {
    console.log('[ConfigStore] No config file found, using defaults');
    return createDefaultConfig();
  }

  try {
    const data = await readFile(configPath, 'utf-8');
    const parsed = JSON.parse(data) as FormicConfig;
    // Merge with defaults to ensure all fields exist
    return {
      ...createDefaultConfig(),
      ...parsed,
      settings: {
        ...createDefaultConfig().settings,
        ...parsed.settings,
      },
      plugins: {
        ...createDefaultConfig().plugins,
        ...parsed.plugins,
      },
    };
  } catch (error) {
    const err = error as Error;
    console.error('[ConfigStore] Failed to load config:', err.message);
    return createDefaultConfig();
  }
}

/**
 * Save the config to ~/.formic/config.json using atomic writes.
 * Writes to a temp file first, then renames to avoid corruption.
 */
export async function saveConfig(config: FormicConfig): Promise<void> {
  await ensureGlobalFormicDir();

  const configPath = getGlobalConfigPath();
  const tmpPath = path.join(getGlobalFormicDir(), '.config.json.tmp');

  try {
    await writeFile(tmpPath, JSON.stringify(config, null, 2), 'utf-8');
    await rename(tmpPath, configPath);
  } catch (error) {
    const err = error as Error;
    console.error('[ConfigStore] Failed to save config:', err.message);
    throw new Error(`Failed to save config: ${err.message}`);
  }
}

/**
 * Add a new workspace to the config.
 * If a workspace with the same path already exists, returns it.
 * Auto-activates if this is the first workspace.
 */
export async function addWorkspace(input: {
  path: string;
  name?: string;
  color?: string;
}): Promise<ConfigWorkspace> {
  const config = await loadConfig();

  // Check if workspace with same path already exists
  const existing = config.workspaces.find(ws => ws.path === input.path);
  if (existing) {
    return existing;
  }

  const workspace: ConfigWorkspace = {
    id: `ws-${crypto.randomUUID()}`,
    path: input.path,
    name: input.name || getBasename(input.path),
    color: input.color || getNextColor(config.workspaces),
    lastAccessed: new Date().toISOString(),
  };

  config.workspaces.push(workspace);

  // Auto-activate if this is the first workspace
  if (config.workspaces.length === 1) {
    config.activeWorkspaceId = workspace.id;
  }

  await saveConfig(config);
  console.log('[ConfigStore] Added workspace:', workspace.name, workspace.path);
  return workspace;
}

/**
 * Remove a workspace by ID.
 * Clears activeWorkspaceId if the removed workspace was active.
 */
export async function removeWorkspace(workspaceId: string): Promise<boolean> {
  const config = await loadConfig();
  const index = config.workspaces.findIndex(ws => ws.id === workspaceId);

  if (index === -1) {
    return false;
  }

  config.workspaces.splice(index, 1);

  // Clear activeWorkspaceId if we removed the active workspace
  if (config.activeWorkspaceId === workspaceId) {
    config.activeWorkspaceId = config.workspaces.length > 0
      ? config.workspaces[0].id
      : null;
  }

  await saveConfig(config);
  console.log('[ConfigStore] Removed workspace:', workspaceId);
  return true;
}

/**
 * Set the active workspace by ID and update its lastAccessed timestamp.
 */
export async function setActiveWorkspace(workspaceId: string): Promise<boolean> {
  const config = await loadConfig();
  const workspace = config.workspaces.find(ws => ws.id === workspaceId);

  if (!workspace) {
    return false;
  }

  config.activeWorkspaceId = workspaceId;
  workspace.lastAccessed = new Date().toISOString();

  await saveConfig(config);
  console.log('[ConfigStore] Active workspace set to:', workspace.name);
  return true;
}

/**
 * Get the currently active workspace, or null if none.
 */
export async function getActiveWorkspace(): Promise<ConfigWorkspace | null> {
  const config = await loadConfig();
  if (!config.activeWorkspaceId) {
    return null;
  }
  return config.workspaces.find(ws => ws.id === config.activeWorkspaceId) || null;
}

/**
 * Get a single setting value by key.
 */
export async function getSetting<K extends keyof ConfigSettings>(
  key: K
): Promise<ConfigSettings[K]> {
  const config = await loadConfig();
  return config.settings[key];
}

/**
 * Update a single setting value by key.
 */
export async function setSetting<K extends keyof ConfigSettings>(
  key: K,
  value: ConfigSettings[K]
): Promise<void> {
  const config = await loadConfig();
  config.settings[key] = value;
  await saveConfig(config);
  console.log('[ConfigStore] Setting updated:', key, '=', value);
}

// ==================== Plugin Config Helpers ====================

/**
 * Get the persisted config for a specific plugin.
 * Returns undefined if the plugin has no config entry.
 */
export async function getPluginConfig(name: string): Promise<PluginConfig | undefined> {
  const config = await loadConfig();
  return config.plugins?.[name];
}

/**
 * Set the full config for a specific plugin (enabled state + settings).
 * Creates the plugins map if it doesn't exist.
 */
export async function setPluginConfig(name: string, pluginConfig: PluginConfig): Promise<void> {
  const config = await loadConfig();
  if (!config.plugins) {
    config.plugins = {};
  }
  config.plugins[name] = pluginConfig;
  await saveConfig(config);
  console.warn('[ConfigStore] Plugin config updated:', name);
}

/**
 * Get a single setting value for a plugin.
 * Returns undefined if the plugin has no config or the key doesn't exist.
 */
export async function getPluginSetting(name: string, key: string): Promise<unknown> {
  const config = await loadConfig();
  return config.plugins?.[name]?.settings?.[key];
}

/**
 * Set a single setting value for a plugin.
 * Creates the plugin config entry if it doesn't exist.
 */
/**
 * Remove the config entry for a specific plugin.
 * No-op if the plugin has no config entry.
 */
export async function removePluginConfig(name: string): Promise<void> {
  const config = await loadConfig();
  if (config.plugins && config.plugins[name]) {
    delete config.plugins[name];
    await saveConfig(config);
    console.warn('[ConfigStore] Plugin config removed:', name);
  }
}

export async function setPluginSetting(name: string, key: string, value: unknown): Promise<void> {
  const config = await loadConfig();
  if (!config.plugins) {
    config.plugins = {};
  }
  if (!config.plugins[name]) {
    config.plugins[name] = { enabled: false, settings: {} };
  }
  config.plugins[name].settings[key] = value;
  await saveConfig(config);
  console.warn('[ConfigStore] Plugin setting updated:', name, key);
}

export { generateTaskReadme } from './task-readme.js';
export { generateTaskPlan } from './task-plan.js';
// Note: generateTaskChecklist removed in Phase 9 - subtasks.json is now generated by /plan skill

import { readFile, writeFile, mkdir } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import type {
  MessagingStore,
  MessagingSession,
  MessagingPlatform,
  NotificationPreferences,
  AIConversationMessage,
  AIConversationHistory,
  MessagingSessionAI,
} from '../../types/index.js';
import { getFormicDir } from '../utils/paths.js';

/**
 * Messaging Store Service
 *
 * Manages persistent storage of messaging sessions in .formic/messaging.json.
 * Sessions link platform chat IDs to workspaces for command handling and notifications.
 */

const MESSAGING_FILE = 'messaging.json';
const STORE_VERSION = '1.0';

/**
 * Get the path to the messaging.json file
 */
function getMessagingPath(): string {
  return path.join(getFormicDir(), MESSAGING_FILE);
}

/**
 * Create a default messaging store structure
 */
function createDefaultStore(): MessagingStore {
  return {
    version: STORE_VERSION,
    sessions: [],
  };
}

/**
 * Ensure the .formic directory exists
 */
async function ensureFormicDir(): Promise<void> {
  const formicDir = getFormicDir();
  if (!existsSync(formicDir)) {
    await mkdir(formicDir, { recursive: true });
  }
}

/**
 * Load the messaging store from disk
 */
export async function loadMessagingStore(): Promise<MessagingStore> {
  await ensureFormicDir();

  const messagingPath = getMessagingPath();

  if (!existsSync(messagingPath)) {
    const defaultStore = createDefaultStore();
    await saveMessagingStore(defaultStore);
    return defaultStore;
  }

  try {
    const data = await readFile(messagingPath, 'utf-8');
    return JSON.parse(data) as MessagingStore;
  } catch (error) {
    const err = error as Error;
    console.error('[MessagingStore] Failed to load messaging.json:', err.message);
    return createDefaultStore();
  }
}

/**
 * Save the messaging store to disk
 */
export async function saveMessagingStore(store: MessagingStore): Promise<void> {
  await ensureFormicDir();
  const messagingPath = getMessagingPath();
  await writeFile(messagingPath, JSON.stringify(store, null, 2), 'utf-8');
}

/**
 * Generate a unique session ID from platform and chat ID
 */
export function generateSessionId(platform: MessagingPlatform, chatId: string): string {
  return `${platform}:${chatId}`;
}

/**
 * Get a session by platform and chat ID
 */
export async function getSession(
  platform: MessagingPlatform,
  chatId: string
): Promise<MessagingSession | undefined> {
  const store = await loadMessagingStore();
  const sessionId = generateSessionId(platform, chatId);
  return store.sessions.find((s) => s.id === sessionId);
}

/**
 * Get all sessions for a specific workspace
 */
export async function getSessionsByWorkspace(workspacePath: string): Promise<MessagingSession[]> {
  const store = await loadMessagingStore();
  return store.sessions.filter((s) => s.workspacePath === workspacePath);
}

/**
 * Get all sessions for a specific platform
 */
export async function getSessionsByPlatform(
  platform: MessagingPlatform
): Promise<MessagingSession[]> {
  const store = await loadMessagingStore();
  return store.sessions.filter((s) => s.platform === platform);
}

/**
 * Create or update a messaging session
 */
export async function upsertSession(
  platform: MessagingPlatform,
  chatId: string,
  userId: string,
  workspacePath: string,
  userName?: string
): Promise<MessagingSession> {
  const store = await loadMessagingStore();
  const sessionId = generateSessionId(platform, chatId);

  const existingIndex = store.sessions.findIndex((s) => s.id === sessionId);
  const now = new Date().toISOString();

  if (existingIndex >= 0) {
    // Update existing session
    store.sessions[existingIndex] = {
      ...store.sessions[existingIndex],
      userId,
      userName,
      workspacePath,
      lastActiveAt: now,
    };
    await saveMessagingStore(store);
    console.log(`[MessagingStore] Updated session ${sessionId}`);
    return store.sessions[existingIndex];
  }

  // Create new session with default notification preferences
  const newSession: MessagingSession = {
    id: sessionId,
    platform,
    chatId,
    userId,
    userName,
    workspacePath,
    notifications: {
      onTaskComplete: true,
      onTaskFailed: true,
      onReviewReady: true,
    },
    createdAt: now,
    lastActiveAt: now,
  };

  store.sessions.push(newSession);
  await saveMessagingStore(store);
  console.log(`[MessagingStore] Created new session ${sessionId}`);
  return newSession;
}

/**
 * Update a session's last active timestamp
 */
export async function touchSession(
  platform: MessagingPlatform,
  chatId: string
): Promise<void> {
  const store = await loadMessagingStore();
  const sessionId = generateSessionId(platform, chatId);

  const session = store.sessions.find((s) => s.id === sessionId);
  if (session) {
    session.lastActiveAt = new Date().toISOString();
    await saveMessagingStore(store);
  }
}

/**
 * Update notification preferences for a session
 */
export async function updateNotificationPreferences(
  platform: MessagingPlatform,
  chatId: string,
  preferences: Partial<NotificationPreferences>
): Promise<MessagingSession | null> {
  const store = await loadMessagingStore();
  const sessionId = generateSessionId(platform, chatId);

  const session = store.sessions.find((s) => s.id === sessionId);
  if (!session) {
    return null;
  }

  session.notifications = {
    ...session.notifications,
    ...preferences,
  };
  session.lastActiveAt = new Date().toISOString();

  await saveMessagingStore(store);
  console.log(`[MessagingStore] Updated notifications for ${sessionId}`);
  return session;
}

/**
 * Delete a session
 */
export async function deleteSession(
  platform: MessagingPlatform,
  chatId: string
): Promise<boolean> {
  const store = await loadMessagingStore();
  const sessionId = generateSessionId(platform, chatId);

  const initialLength = store.sessions.length;
  store.sessions = store.sessions.filter((s) => s.id !== sessionId);

  if (store.sessions.length < initialLength) {
    await saveMessagingStore(store);
    console.log(`[MessagingStore] Deleted session ${sessionId}`);
    return true;
  }

  return false;
}

