/**
 * MCP Screenshot Service
 *
 * Captures screenshots of web pages using Playwright MCP tools.
 * This service is designed to be called from messaging adapters (Telegram, LINE)
 * and relies on MCP Playwright tools being available in the execution environment.
 *
 * Note: MCP tools are available when this code runs within an AI agent context
 * (e.g., Claude Code with MCP configured). For direct API usage without MCP,
 * consider using Puppeteer or Playwright directly.
 */

import { spawn } from 'node:child_process';
import { writeFile, unlink, mkdir } from 'node:fs/promises';
import { join } from 'node:path';
import { randomBytes } from 'node:crypto';

// Screenshot timeout: 30 seconds default (configurable via environment)
const SCREENSHOT_TIMEOUT_MS = parseInt(process.env.SCREENSHOT_TIMEOUT_MS || '30000', 10);

// Temporary directory for screenshots
const TEMP_DIR = process.env.TEMP_DIR || '/tmp/formic-screenshots';

/**
 * Screenshot capture result
 */
export interface ScreenshotResult {
  success: boolean;
  /** Base64-encoded PNG data (on success) */
  data?: string;
  /** Source type (always 'buffer' for MCP screenshots) */
  source?: 'buffer';
  /** Error message (on failure) */
  error?: string;
}

/**
 * Check if Playwright is available by attempting to run a simple command
 * This is a lightweight check that doesn't require a full browser launch
 */
export async function isPlaywrightAvailable(): Promise<boolean> {
  try {
    // Try to import playwright to check if it's installed
    const result = await new Promise<boolean>((resolve) => {
      const proc = spawn('npx', ['playwright', '--version'], {
        stdio: 'pipe',
        timeout: 5000,
      });

      let resolved = false;

      proc.on('close', (code) => {
        if (!resolved) {
          resolved = true;
          resolve(code === 0);
        }
      });

      proc.on('error', () => {
        if (!resolved) {
          resolved = true;
          resolve(false);
        }
      });

      // Timeout fallback
      setTimeout(() => {
        if (!resolved) {
          resolved = true;
          proc.kill();
          resolve(false);
        }
      }, 5000);
    });

    if (result) {
      console.log('[McpScreenshot] Playwright is available');
    } else {
      console.log('[McpScreenshot] Playwright is not available');
    }

    return result;
  } catch (error) {
    const err = error as Error;
    console.log('[McpScreenshot] Playwright availability check failed:', err.message);
    return false;
  }
}

/**
 * Validate and normalize a URL for screenshot capture
 */
function validateUrl(url: string): { valid: boolean; url?: string; error?: string } {
  let normalizedUrl = url.trim();

  // Add https:// if no protocol specified
  if (!normalizedUrl.startsWith('http://') && !normalizedUrl.startsWith('https://')) {
    normalizedUrl = 'https://' + normalizedUrl;
  }

  try {
    const parsed = new URL(normalizedUrl);

    // Only allow http and https protocols
    if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
      return { valid: false, error: 'Only HTTP and HTTPS URLs are supported' };
    }

    return { valid: true, url: normalizedUrl };
  } catch {
    return { valid: false, error: 'Invalid URL format' };
  }
}

/**
 * Ensure the temporary directory exists
 */
async function ensureTempDir(): Promise<void> {
  try {
    await mkdir(TEMP_DIR, { recursive: true });
  } catch (error) {
    const err = error as Error;
    console.error('[McpScreenshot] Failed to create temp directory:', err.message);
    throw new Error(`Failed to create temp directory: ${err.message}`);
  }
}

/**
 * Generate a unique filename for the screenshot
 */
function generateTempFilename(): string {
  const id = randomBytes(8).toString('hex');
  return join(TEMP_DIR, `screenshot-${id}.png`);
}

/**
 * Take a screenshot using Playwright
 * Uses a headless browser to navigate to the URL and capture a screenshot
 *
 * @param url - The URL to capture
 * @returns ScreenshotResult with base64-encoded PNG data or error
 */
export async function takeScreenshot(url: string): Promise<ScreenshotResult> {
  console.log(`[McpScreenshot] Taking screenshot of: ${url}`);

  // Validate URL
  const validation = validateUrl(url);
  if (!validation.valid) {
    console.log(`[McpScreenshot] Invalid URL: ${validation.error}`);
    return { success: false, error: validation.error };
  }

  const normalizedUrl = validation.url!;
  console.log(`[McpScreenshot] Normalized URL: ${normalizedUrl}`);

  // Check if Playwright is available
  const playwrightAvailable = await isPlaywrightAvailable();
  if (!playwrightAvailable) {
    return {
      success: false,
      error: 'Playwright is not installed. Please run: npm install playwright && npx playwright install chromium',
    };
  }

  // Ensure temp directory exists
  await ensureTempDir();

  // Generate temp filename for screenshot
  const tempFile = generateTempFilename();

  try {
    // Use a Node.js script to take the screenshot with Playwright
    const screenshotScript = `
const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();

  try {
    await page.goto('${normalizedUrl.replace(/'/g, "\\'")}', {
      waitUntil: 'networkidle',
      timeout: ${SCREENSHOT_TIMEOUT_MS - 5000} // Leave 5s buffer for browser startup
    });

    await page.screenshot({
      path: '${tempFile.replace(/'/g, "\\'")}',
      type: 'png'
    });

    console.log('SCREENSHOT_SUCCESS');
  } catch (err) {
    console.error('SCREENSHOT_ERROR:', err.message);
    process.exit(1);
  } finally {
    await browser.close();
  }
})();
`;

    // Execute the screenshot script
    const result = await new Promise<{ success: boolean; error?: string }>((resolve) => {
      const proc = spawn('node', ['-e', screenshotScript], {
        stdio: ['ignore', 'pipe', 'pipe'],
        timeout: SCREENSHOT_TIMEOUT_MS,
      });

      let stdout = '';
      let stderr = '';
      let resolved = false;

      proc.stdout.on('data', (data) => {
        stdout += data.toString();
      });

      proc.stderr.on('data', (data) => {
        stderr += data.toString();
      });

      proc.on('close', (code) => {
        if (resolved) return;
        resolved = true;

        if (code === 0 && stdout.includes('SCREENSHOT_SUCCESS')) {
          resolve({ success: true });
        } else {
          // Extract error message
          const errorMatch = stderr.match(/SCREENSHOT_ERROR:\s*(.+)/);
          const errorMsg = errorMatch ? errorMatch[1] : stderr || 'Screenshot capture failed';
          resolve({ success: false, error: errorMsg.trim() });
        }
      });

      proc.on('error', (err) => {
        if (resolved) return;
        resolved = true;
        resolve({ success: false, error: `Process error: ${err.message}` });
      });

      // Timeout fallback
      setTimeout(() => {
        if (resolved) return;
        resolved = true;
        proc.kill('SIGKILL');
        resolve({ success: false, error: `Screenshot timed out after ${SCREENSHOT_TIMEOUT_MS / 1000}s` });
      }, SCREENSHOT_TIMEOUT_MS);
    });

    if (!result.success) {
      console.log(`[McpScreenshot] Screenshot failed: ${result.error}`);
      return { success: false, error: result.error };
    }

    // Read the screenshot file and convert to base64
    const { readFile } = await import('node:fs/promises');
    const screenshotBuffer = await readFile(tempFile);
    const base64Data = screenshotBuffer.toString('base64');

    console.log(`[McpScreenshot] Screenshot captured successfully (${Math.round(screenshotBuffer.length / 1024)}KB)`);

    // Clean up temp file
    try {
      await unlink(tempFile);
    } catch {
      // Ignore cleanup errors
    }

    return {
      success: true,
      data: base64Data,
      source: 'buffer',
    };
  } catch (error) {
    const err = error as Error;
    console.error('[McpScreenshot] Screenshot error:', err.message);

    // Clean up temp file on error
    try {
      await unlink(tempFile);
    } catch {
      // Ignore cleanup errors
    }

    return {
      success: false,
      error: `Screenshot failed: ${err.message}`,
    };
  }
}

/**
 * Take a screenshot with MCP Playwright tools
 * This is a wrapper that attempts to use MCP tools if available,
 * falling back to direct Playwright usage
 *
 * @param url - The URL to capture
 * @returns ScreenshotResult with base64-encoded PNG data or error
 */
export async function takeScreenshotWithMCP(url: string): Promise<ScreenshotResult> {
  // For now, we use direct Playwright since MCP tools are only available
  // in the AI agent execution context (Claude Code, etc.)
  // The MCP integration would require being inside an AI session
  return takeScreenshot(url);
}

/**
 * Plugin Bot Commands Registry Service
 *
 * In-memory registry mapping command names to plugin-registered bot command handlers.
 * Allows plugins to register custom slash commands (e.g. /deploy, /metrics) that
 * Telegram and LINE users can invoke directly in chat.
 */

import type { BotCommandDefinition } from '../../types/index.js';

/** Backing store: command name -> { pluginName, command } */
const registry = new Map<string, { pluginName: string; command: BotCommandDefinition }>();

/**
 * Register a bot command for a plugin.
 * Stores the command keyed by its name (without leading slash).
 */
export function registerBotCommand(pluginName: string, command: BotCommandDefinition): void {
  if (!command.name || typeof command.name !== 'string' || command.name.trim().length === 0) {
    throw new Error('[BotCommands] Bot command name must be a non-empty string');
  }
  if (typeof command.handler !== 'function') {
    throw new Error('[BotCommands] Bot command handler must be a function');
  }

  // Normalize name by stripping leading slash if present
  const normalizedName = command.name.replace(/^\/+/, '');

  registry.set(normalizedName, { pluginName, command });

  console.warn(`[BotCommands] Plugin '${pluginName}' registered command /${normalizedName}`);
}

/**
 * Unregister all bot commands for a plugin.
 * Returns the count of removed commands.
 */
export function unregisterBotCommands(pluginName: string): number {
  let count = 0;

  for (const [name, entry] of registry) {
    if (entry.pluginName === pluginName) {
      registry.delete(name);
      count++;
    }
  }

  if (count > 0) {
    console.warn(`[BotCommands] Unregistered ${count} command(s) for plugin: ${pluginName}`);
  }

  return count;
}

/**
 * Dispatch an incoming bot command to the registered handler.
 * Strips leading `/` from the command name if present.
 * Returns the handler's response string, or null if no matching command is found.
 */
export async function dispatchBotCommand(
  commandName: string,
  args: string,
  chatId: string,
): Promise<string | null> {
  // Normalize by stripping leading slash
  const normalizedName = commandName.replace(/^\/+/, '');

  const entry = registry.get(normalizedName);
  if (!entry) {
    return null;
  }

  try {
    return await entry.command.handler(args, chatId);
  } catch (err) {
    console.error(
      `[BotCommands] Error dispatching command /${normalizedName}:`,
      err instanceof Error ? err.message : 'Unknown error',
    );
    return null;
  }
}

import { spawn, type ChildProcess } from 'node:child_process';
import { writeFile, mkdir } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import type { WebSocket } from 'ws';
import type { AssistantSession, AssistantMessage } from '../../types/index.js';
import { getWorkspacePath, getFormicDir } from '../utils/paths.js';
import { loadBoard } from './store.js';
import { broadcastBoardUpdate } from './boardNotifier.js';
import {
  getAgentCommand,
  getAgentType,
  getAgentDisplayName,
  buildAssistantArgs,
  supportsConversationContinue,
} from './agentAdapter.js';
import { parseAgentOutput, usesJsonOutput, cleanAgentOutput } from './outputParser.js';
import { loadProjectGuidelines } from './skillReader.js';

// Session state
let session: AssistantSession = {
  status: 'idle',
  pid: null,
  startedAt: null,
  lastError: null,
};

// Track if a message is currently being processed
let isProcessing = false;

// WebSocket connections for the assistant
const assistantConnections = new Set<WebSocket>();

// Message history (kept in memory for session duration)
const messageHistory: AssistantMessage[] = [];
const MAX_HISTORY = 100;

// Flag to track if this is the first message (don't use --continue)
let isFirstMessage = true;

// Pattern to detect task creation in assistant responses.
// Closing ``` must be preceded by a real newline so triple-backticks
// embedded inside a JSON string value (encoded as \n, not a real newline)
// never accidentally terminate the match early.
const TASK_CREATE_PATTERN = /```task-create\r?\n([\s\S]*?)\r?\n```/g;

// Get the server port for API calls
const getServerPort = () => parseInt(process.env.PORT || '8000', 10);

/**
 * Create a task via the Formic API
 */
async function createTaskViaAPI(taskData: { title: string; context: string; priority?: string }): Promise<{ success: boolean; taskId?: string; error?: string }> {
  try {
    const port = getServerPort();
    const response = await fetch(`http://localhost:${port}/api/tasks`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(taskData),
    });

    if (!response.ok) {
      const errorText = await response.text();
      console.error('[AssistantManager] Task creation failed:', errorText);
      return { success: false, error: errorText };
    }

    const result = await response.json() as { id: string };
    console.log('[AssistantManager] Task created:', result.id);
    return { success: true, taskId: result.id };
  } catch (error) {
    const err = error as Error;
    console.error('[AssistantManager] Task creation error:', err.message);
    return { success: false, error: err.message };
  }
}

/**
 * Process assistant response content for task creation commands
 * Supports multiple task-create blocks in a single response
 */
async function processTaskCreation(content: string): Promise<void> {
  const matches = [...content.matchAll(TASK_CREATE_PATTERN)];
  if (matches.length === 0) return;

  console.log(`[AssistantManager] Found ${matches.length} task creation request(s)`);

  const results: Array<{ success: boolean; title: string; taskId?: string; error?: string }> = [];

  for (const match of matches) {
    try {
      const taskData = JSON.parse(match[1]) as { title: string; context: string; priority?: string };
      console.log('[AssistantManager] Creating task:', taskData.title);

      const result = await createTaskViaAPI(taskData);
      results.push({
        success: result.success,
        title: taskData.title,
        taskId: result.taskId,
        error: result.error,
      });
    } catch (error) {
      const err = error as Error;
      console.error('[AssistantManager] Failed to parse task data:', err.message);
      console.warn('[AssistantManager] Raw JSON (first 200 chars):', match[1].slice(0, 200));
      results.push({
        success: false,
        title: 'Unknown',
        error: `Parse error: ${err.message}`,
      });
    }
  }

  // Broadcast board update if any tasks were created
  if (results.some(r => r.success)) {
    broadcastBoardUpdate();
  }

  // Broadcast summary message
  const successCount = results.filter(r => r.success).length;
  const failCount = results.filter(r => !r.success).length;

  let summaryContent: string;
  if (results.length === 1) {
    // Single task - show detailed message
    const r = results[0];
    summaryContent = r.success
      ? `Task created: "${r.title}" [${r.taskId}]`
      : `Failed to create task: ${r.error}`;
  } else {
    // Multiple tasks - show summary
    const successList = results
      .filter(r => r.success)
      .map(r => `"${r.title}" [${r.taskId}]`)
      .join(', ');
    const failList = results
      .filter(r => !r.success)
      .map(r => `"${r.title}": ${r.error}`)
      .join('; ');

    if (failCount === 0) {
      summaryContent = `Created ${successCount} tasks: ${successList}`;
    } else if (successCount === 0) {
      summaryContent = `Failed to create ${failCount} task(s): ${failList}`;
    } else {
      summaryContent = `Created ${successCount} task(s): ${successList}. Failed: ${failList}`;
    }
  }

  const confirmMessage: AssistantMessage = {
    type: 'system',
    content: summaryContent,
    timestamp: new Date().toISOString(),
  };
  broadcastMessage(confirmMessage);
}

/**
 * Register a WebSocket connection for assistant messages
 */
export function registerAssistantConnection(ws: WebSocket): void {
  assistantConnections.add(ws);
  console.log('[AssistantManager] Connection registered, total:', assistantConnections.size);
}

/**
 * Unregister a WebSocket connection
 */
export function unregisterAssistantConnection(ws: WebSocket): void {
  assistantConnections.delete(ws);
  console.log('[AssistantManager] Connection unregistered, total:', assistantConnections.size);
}

/**
 * Broadcast a message to all connected WebSocket clients
 */
function broadcastMessage(message: AssistantMessage): void {
  // Add to history
  messageHistory.push(message);
  while (messageHistory.length > MAX_HISTORY) {
    messageHistory.shift();
  }

  const data = JSON.stringify({ type: 'message', message });
  for (const ws of assistantConnections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(data);
    }
  }
}

/**
 * Broadcast streaming content delta to all connected clients
 */
function broadcastStreamDelta(delta: string): void {
  const data = JSON.stringify({ type: 'stream_delta', delta });
  for (const ws of assistantConnections) {
    if (ws.readyState === 1) {
      ws.send(data);
    }
  }
}

/**
 * Broadcast agent stream status (thinking, tool use) to all connected clients
 */
function broadcastStreamStatus(status: string): void {
  const data = JSON.stringify({ type: 'stream_status', status });
  for (const ws of assistantConnections) {
    if (ws.readyState === 1) {
      ws.send(data);
    }
  }
}

/**
 * Broadcast status update to all connected clients
 */
function broadcastStatus(): void {
  const data = JSON.stringify({ type: 'status', session });
  for (const ws of assistantConnections) {
    if (ws.readyState === 1) {
      ws.send(data);
    }
  }
}

/**
 * Get current session status
 */
export function getAssistantSession(): AssistantSession {
  return { ...session };
}

/**
 * Get message history
 */
export function getMessageHistory(): AssistantMessage[] {
