/**
 * Send a user message - spawns a Claude process for this message
 */
export function sendUserMessage(content: string): boolean {
  if (session.status !== 'running') {
    console.log('[AssistantManager] Cannot send message: assistant not running');
    return false;
  }

  if (isProcessing) {
    console.log('[AssistantManager] Cannot send message: already processing');
    return false;
  }

  // Add user message to history
  const userMessage: AssistantMessage = {
    type: 'user',
    content,
    timestamp: new Date().toISOString(),
  };
  broadcastMessage(userMessage);

  // Spawn Claude process for this message
  processMessage(content);
  return true;
}

/**
 * Process a message by spawning the configured agent CLI
 */
function processMessage(content: string): void {
  isProcessing = true;

  const workspacePath = getWorkspacePath();
  const agentType = getAgentType();
  const agentCommand = getAgentCommand();
  const agentDisplayName = getAgentDisplayName();

  // Determine if we should use --continue based on agent support and message history
  const useContinue = !isFirstMessage && supportsConversationContinue();

  // Build agent-specific args using the adapter
  const args = buildAssistantArgs(content, { continue: useContinue });

  console.log('[AssistantManager] Processing message in:', workspacePath);
  console.log('[AssistantManager] Agent:', agentType, '| Command:', agentCommand);
  console.log('[AssistantManager] Args:', args.join(' ').substring(0, 100));

  const child = spawn(agentCommand, args, {
    cwd: workspacePath,
    env: { ...process.env },
    stdio: ['pipe', 'pipe', 'pipe'],
  });

  // Close stdin immediately - agents may wait for stdin to close before processing
  child.stdin?.end();

  console.log('[AssistantManager] Spawned with PID:', child.pid);

  // Track streaming content
  let streamingContent = '';

  // Deduplication guard: track the last broadcast status to avoid duplicate
  // broadcasts when the same status line appears on both stdout and stderr
  let lastBroadcastStatus = '';

  // Emit initial "Thinking…" status for Copilot (analogous to Claude's system/init event)
  if (agentType === 'copilot') {
    broadcastStreamStatus('Thinking…');
    lastBroadcastStatus = 'Thinking…';
  }

  // Handle spawn error
  child.on('error', (err: NodeJS.ErrnoException) => {
    console.error('[AssistantManager] Spawn error:', err.message);
    isProcessing = false;

    const errorMessage: AssistantMessage = {
      type: 'error',
      content: err.code === 'ENOENT'
        ? `${agentDisplayName} not found. Please install it.`
        : err.message,
      timestamp: new Date().toISOString(),
    };
    broadcastMessage(errorMessage);
  });

  // Handle stdout - parse output using agent-specific parser
  let outputBuffer = '';
  const isJsonOutput = usesJsonOutput(agentType);

  child.stdout?.on('data', (data: Buffer) => {
    const chunk = data.toString();
    console.log('[AssistantManager] STDOUT chunk received, length:', chunk.length);
    outputBuffer += chunk;

    // Split by newlines and process complete lines
    const lines = outputBuffer.split('\n');
    outputBuffer = lines.pop() || '';

    for (const line of lines) {
      if (!line.trim()) continue;

      // Use the agent-agnostic output parser
      const result = parseAgentOutput(line, agentType);

      if (result.type === 'text' && result.content) {
        streamingContent += result.content;
        broadcastStreamDelta(result.content);
      } else if (result.type === 'status' && result.content) {
        if (result.content !== lastBroadcastStatus) {
          lastBroadcastStatus = result.content;
          broadcastStreamStatus(result.content);
        }
      } else if (result.type === 'result') {
        // Final result
        const finalContent = streamingContent.trim() || result.content || '';

        if (finalContent) {
          const message: AssistantMessage = {
            type: 'assistant',
            content: finalContent,
            timestamp: new Date().toISOString(),
          };
          broadcastMessage(message);
          console.log('[AssistantManager] Response:', finalContent.substring(0, 100));

          // Check for task creation commands in the response
          processTaskCreation(finalContent).catch(err => {
            console.error('[AssistantManager] Task creation processing error:', err);
          });
        }
      } else if (result.type === 'system') {
        console.log('[AssistantManager] System event:', result.content);
      } else if (!isJsonOutput && result.type === 'unknown' && line.trim()) {
        // For non-JSON agents, treat unknown lines as potential text content
        streamingContent += line + '\n';
        broadcastStreamDelta(line + '\n');
      }
    }
  });

  // Handle stderr
  child.stderr?.on('data', (data: Buffer) => {
    const text = data.toString().trim();
    if (!text) return;

    // Capture Copilot status messages and broadcast as stream_status (with dedup)
    if (text.includes('● Calling')) {
      const match = text.match(/● Calling\s+(.+)/);
      const toolName = match ? match[1].replace(/\.{3}$/, '').trim() : 'tool';
      const status = `Using tool: ${toolName}…`;
      if (status !== lastBroadcastStatus) {
        lastBroadcastStatus = status;
        broadcastStreamStatus(status);
      }
      return;
    }
    if (text.includes('● Reading')) {
      const status = 'Reading files…';
      if (status !== lastBroadcastStatus) {
        lastBroadcastStatus = status;
        broadcastStreamStatus(status);
      }
      return;
    }

    // Detect other "● <action>" patterns from stderr
    const genericMatch = text.match(/●\s+(\w[\w\s]*)/);
    if (genericMatch) {
      const action = genericMatch[1].trim();
      const status = `${action}…`;
      if (status !== lastBroadcastStatus) {
        lastBroadcastStatus = status;
        broadcastStreamStatus(status);
      }
      return;
    }

    // Filter out spinner characters (Braille patterns) and other noise
    const isNoise = /[⠋⠙⠹⠸⠼⠴⠦⠧⠇⠏⣾⣽⣻⢿⡿⣟⣯⣷]/.test(text) ||
      text.includes('Disabled tools:') ||
      text.includes('Unknown tool name');

    if (!isNoise) {
      console.log('[AssistantManager] stderr:', text);
    }
  });

  // Handle process exit
  child.on('close', (code) => {
    console.log('[AssistantManager] Process exited with code:', code);
    isProcessing = false;

    // Only set isFirstMessage to false if agent supports continuation
    if (supportsConversationContinue()) {
      isFirstMessage = false;
    }

    // Flush any remaining content
    if (outputBuffer.trim()) {
      if (isJsonOutput) {
        // Try to parse remaining JSON
        const result = parseAgentOutput(outputBuffer, agentType);
        if (result.type === 'result' && result.content) {
          const content = streamingContent.trim() || result.content;
          if (content && !messageHistory.some(m => m.content === content && m.type === 'assistant')) {
            const message: AssistantMessage = {
              type: 'assistant',
              content,
              timestamp: new Date().toISOString(),
            };
            broadcastMessage(message);

            processTaskCreation(content).catch(err => {
              console.error('[AssistantManager] Task creation processing error:', err);
            });
          }
        }
      } else {
        // For non-JSON output, treat remaining buffer as text
        streamingContent += outputBuffer;
      }
    }

    // For non-JSON agents, broadcast the final accumulated content
    if (!isJsonOutput && streamingContent.trim()) {
      // Clean up function call XML blocks that may appear in Copilot output
      const finalContent = cleanAgentOutput(streamingContent);
      if (finalContent && !messageHistory.some(m => m.content === finalContent && m.type === 'assistant')) {
        const message: AssistantMessage = {
          type: 'assistant',
          content: finalContent,
          timestamp: new Date().toISOString(),
        };
        broadcastMessage(message);

        processTaskCreation(finalContent).catch(err => {
          console.error('[AssistantManager] Task creation processing error:', err);
        });
      }
    }

    if (code !== 0 && code !== null) {
      const errorMessage: AssistantMessage = {
        type: 'system',
        content: `Process exited with code ${code}`,
        timestamp: new Date().toISOString(),
      };
      broadcastMessage(errorMessage);
    }
  });
}

/**
 * Start the Claude Code assistant session
 */
export async function startAssistant(): Promise<AssistantSession> {
  if (session.status === 'running') {
    console.log('[AssistantManager] Assistant already running');
    return session;
  }

  try {
    // Generate context file
    await generateContextFile();

    // Set session as running (we spawn processes per message)
    session = {
      status: 'running',
      pid: null,  // No persistent process
      startedAt: new Date().toISOString(),
      lastError: null,
    };

    isFirstMessage = true;  // Reset for new session
    isProcessing = false;

    broadcastStatus();

    // Send welcome message with agent info
    const agentDisplayName = getAgentDisplayName();
    const welcomeMessage: AssistantMessage = {
      type: 'system',
      content: `Formic Task Manager ready (using ${agentDisplayName}). I can help you brainstorm ideas, explore the codebase, and create well-crafted tasks.`,
      timestamp: new Date().toISOString(),
    };
    broadcastMessage(welcomeMessage);

    console.log('[AssistantManager] Session started with agent:', getAgentType());
    return session;

  } catch (error) {
    const err = error as Error;
    console.error('[AssistantManager] Failed to start:', err.message);
    session = {
      status: 'error',
      pid: null,
      startedAt: null,
      lastError: err.message,
    };
    broadcastStatus();
    return session;
  }
}

/**
 * Stop the Claude Code assistant session
 */
export async function stopAssistant(): Promise<AssistantSession> {
  if (session.status !== 'running') {
    console.log('[AssistantManager] No active session to stop');
    return session;
  }

  console.log('[AssistantManager] Stopping assistant...');

  session = {
    status: 'idle',
    pid: null,
    startedAt: null,
    lastError: null,
  };

  isProcessing = false;
  broadcastStatus();

  const message: AssistantMessage = {
    type: 'system',
    content: 'Session ended',
    timestamp: new Date().toISOString(),
  };
  broadcastMessage(message);

  return session;
}

/**
 * Restart the Claude Code assistant session
 */
export async function restartAssistant(): Promise<AssistantSession> {
  console.log('[AssistantManager] Restarting assistant...');

  // Stop if running
  if (session.status === 'running') {
    await stopAssistant();
    await new Promise(resolve => setTimeout(resolve, 500));
  }

  // Clear message history on restart
  messageHistory.length = 0;
  isFirstMessage = true;
  isProcessing = false;

  // Start fresh
  return startAssistant();
}

/**
 * Output Parser - Agent-agnostic CLI output parsing
 *
 * Handles different output formats from supported AI coding agents:
 * - Claude Code CLI: stream-json format with line-delimited JSON events
 * - GitHub Copilot CLI: Plain text output
 */

import type { OutputParseResult, OutputEventType } from '../../types/index.js';
import { getAgentType, type AgentType } from './agentAdapter.js';

/**
 * Format a tool_use content block into a human-readable status label.
 * Truncates long file paths to the last 2 segments for readability.
 */
function formatToolStatus(name: string, input?: Record<string, unknown>): string {
  switch (name) {
    case 'Read': {
      const filePath = input?.file_path as string | undefined;
      if (filePath) {
        const segments = filePath.split('/');
        const short = segments.length > 2 ? segments.slice(-2).join('/') : filePath;
        return `Reading ${short}`;
      }
      return 'Reading file…';
    }
    case 'Grep': {
      const pattern = input?.pattern as string | undefined;
      return pattern ? `Searching for ${pattern}` : 'Searching…';
    }
    case 'Glob': {
      const pattern = input?.pattern as string | undefined;
      return pattern ? `Finding files ${pattern}` : 'Finding files…';
    }
    case 'WebSearch':
      return 'Searching web…';
    case 'WebFetch': {
      const url = input?.url as string | undefined;
      return url ? `Fetching ${url}` : 'Fetching URL…';
    }
    case 'Bash':
      return 'Running command…';
    case 'Agent':
      return 'Launching agent…';
    case 'Edit':
      return 'Editing file…';
    case 'Write':
      return 'Writing file…';
    default:
      // MCP tools have names like mcp__server__toolName
      if (name.startsWith('mcp__')) {
        const parts = name.split('__');
        const toolLabel = parts.length >= 3 ? parts.slice(2).join('__') : name;
        return `Using ${toolLabel}…`;
      }
      return `Using ${name}…`;
  }
}

/**
 * Parse Claude Code CLI stream-json output line
 * Format: Line-delimited JSON with event types: 'assistant', 'result', 'system'
 *
 * Claude Code CLI emits these high-level events (NOT raw Anthropic SSE events):
 *   type=system   (subtypes: hook_started, hook_response, init)
 *   type=assistant (content blocks: text, tool_use)
 *   type=user     (tool results)
 *   type=result   (final response)
 */
export function parseClaudeStreamJson(line: string): OutputParseResult {
  if (!line.trim()) {
    return { type: 'unknown' };
  }

  try {
    const event = JSON.parse(line) as {
      type?: string;
      subtype?: string;
      message?: {
        content?: Array<{
          type: string;
          text?: string;
          name?: string;
          input?: Record<string, unknown>;
        }>;
      };
      result?: string;
    };

    const eventType = event.type;

    if (eventType === 'assistant') {
      // An assistant event can contain both text AND tool_use blocks.
      // We extract text for streaming display and tool_use for status indicators.
      const textContent: string[] = [];
      let lastToolStatus: string | null = null;

      if (event.message?.content) {
        for (const block of event.message.content) {
          if (block.type === 'text' && block.text) {
            textContent.push(block.text);
          } else if (block.type === 'tool_use' && block.name) {
            lastToolStatus = formatToolStatus(block.name, block.input);
          }
        }
      }

      // If we have text content, return it (text takes priority for display)
      if (textContent.length > 0) {
        return {
          type: 'text',
          content: textContent.join(''),
          raw: event,
        };
      }

      // Otherwise, if we found tool_use blocks, return a status update
      if (lastToolStatus) {
        return {
          type: 'status',
          content: lastToolStatus,
          raw: event,
        };
      }

      return { type: 'unknown', raw: event };
    }

    if (eventType === 'result') {
      return {
        type: 'result',
        content: event.result || '',
        isFinal: true,
        raw: event,
      };
    }

    if (eventType === 'system') {
      // The 'init' subtype fires when the CLI boots — use it as the first
      // status indicator so users see 'Thinking…' before any tool calls.
      if (event.subtype === 'init') {
        return {
          type: 'status',
          content: 'Thinking…',
          raw: event,
        };
      }
      return {
        type: 'system',
        content: event.subtype || 'system',
        raw: event,
      };
    }

    return { type: 'unknown', raw: event };
  } catch {
    // Not valid JSON - could be plain text or error output
    return {
      type: 'unknown',
      content: line,
    };
  }
}

// Braille spinner characters emitted by Copilot CLI progress indicators
const SPINNER_CHARS = /^[\s⠋⠙⠹⠸⠼⠴⠦⠧⠇⠏⣾⣽⣻⢿⡿⣟⣯⣷⠁⠂⠄⡀⢀⠠⠐⠈|\\/-]+$/;

// ANSI escape codes (colors, cursor movement, etc.)
const ANSI_ESCAPE = /\x1B\[[0-9;]*[A-Za-z]/g;

/**
 * Parse GitHub Copilot CLI output line
 * Detects status patterns (tool use, file reads, thinking) and returns
 * appropriate event types. Plain text lines are returned as 'text'.
 */
export function parseCopilotOutput(line: string): OutputParseResult {
  // Strip any residual ANSI escape codes
  const cleaned = line.replace(ANSI_ESCAPE, '');
  const trimmed = cleaned.trim();

  if (!trimmed) {
    return { type: 'unknown' };
  }

  // Filter out pure spinner / progress indicator lines
  if (SPINNER_CHARS.test(trimmed)) {
    return { type: 'unknown' };
  }

  // Detect "● Calling <tool>" status pattern
  const callingMatch = trimmed.match(/●\s*Calling\s+(.+)/);
  if (callingMatch) {
    const toolName = callingMatch[1].replace(/\.{3}$/, '').trim();
    return { type: 'status', content: `Using tool: ${toolName}…` };
  }

  // Detect "● Reading <file>" status pattern
  if (/●\s*Reading/.test(trimmed)) {
    return { type: 'status', content: 'Reading files…' };
  }

  // Detect other "● <action>" status patterns (e.g., ● Searching, ● Writing)
  const genericStatusMatch = trimmed.match(/●\s+(\w[\w\s]*)/);
  if (genericStatusMatch) {
    const action = genericStatusMatch[1].trim();
    return { type: 'status', content: `${action}…` };
  }

  // Plain text content — append newline to preserve formatting
  return {
    type: 'text',
    content: line + '\n',
  };
}

/**
 * Clean up agent output by removing function call XML blocks
 * This is useful for Copilot which may include raw XML in its text output
 */
export function cleanAgentOutput(content: string): string {
  // List of known tool call XML tag patterns to remove
  const toolCallPatterns = [
    // Generic function calls
    /<function_calls>[\s\S]*?<\/function_calls>/g,
    /<function_calls>[\s\S]*?<\/antml:function_calls>/g,
    /<tool_call>[\s\S]*?<\/tool_call>/g,
    // Invoke patterns
    /<invoke[^>]*>[\s\S]*?<\/invoke>/g,
    /<invoke[^>]*>[\s\S]*?<\/antml:invoke>/g,
    // Copilot-specific tool patterns
    /<read_file>[\s\S]*?<\/read_file>/g,
    /<write_file>[\s\S]*?<\/write_file>/g,
    /<root_command_execution>[\s\S]*?<\/root_command_execution>/g,
    /<command_execution>[\s\S]*?<\/command_execution>/g,
    /<search_files>[\s\S]*?<\/search_files>/g,
    /<list_directory>[\s\S]*?<\/list_directory>/g,
    // Generic XML blocks with path/command children
    /<[a-z_]+><path>[^<]*<\/path><\/[a-z_]+>/g,
    /<[a-z_]+><command>[^<]*<\/command>[\s\S]*?<\/[a-z_]+>/g,
    // Parameter blocks
    /<parameter[^>]*>[\s\S]*?<\/parameter>/g,
  ];

  let cleaned = content;
  for (const pattern of toolCallPatterns) {
    cleaned = cleaned.replace(pattern, '');
  }

  // Clean up any resulting multiple spaces or newlines
  return cleaned
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();
}

/**
 * Parse agent output line based on agent type
 * Delegates to agent-specific parsers
 */
export function parseAgentOutput(line: string, agentType?: AgentType): OutputParseResult {
  const type = agentType ?? getAgentType();

  switch (type) {
    case 'claude':
      return parseClaudeStreamJson(line);
    case 'copilot':
      return parseCopilotOutput(line);
    default:
      // Fallback to treating as plain text
      return {
        type: 'text',
        content: line,
      };
  }
}

/**
 * Check if the output format uses JSON (for streaming parsers)
 */
export function usesJsonOutput(agentType?: AgentType): boolean {
  const type = agentType ?? getAgentType();
  return type === 'claude';
}

import { getQueuedTasks, getAllTasks, getTask, getRunningTasksCount, updateTask } from './store.js';
import { executeFullWorkflow, executeQuickTask, executeGoalWorkflow, executeFromDeclare, isWorkflowRunning } from './workflow.js';
import { isAgentRunning } from './runner.js';
import { wouldConflict } from './leaseManager.js';
import { internalEvents, TASK_COMPLETED, LEASE_RELEASED } from './internalEvents.js';
import { prioritizeQueue } from './prioritizer.js';
import { engineConfig, refreshEngineConfig } from './engineConfig.js';
import type { Task } from '../../types/index.js';

const QUEUE_ENABLED = process.env.QUEUE_ENABLED !== 'false';

const YIELD_BACKOFF_INITIAL_MS = 2000;
const YIELD_BACKOFF_MULTIPLIER = 2;
const YIELD_BACKOFF_MAX_MS = 60_000;

/** Per-task exponential backoff delay (ms) for the next retry after a lease conflict */
const yieldBackoffMs = new Map<string, number>();
/** Per-task earliest timestamp (ms) at which the task may be retried */
const yieldUntil = new Map<string, number>();
/** Maps filePath → Set<taskId> of tasks currently in backoff waiting for that file.
 *  Populated when a task yields with `lease-conflict:<filePath>`. Cleared when the
 *  file is released (via handleLeaseReleased) or the task is dispatched. */
const fileBackoffTasks = new Map<string, Set<string>>();
/** Persistent set of task IDs dispatched in any poll cycle whose workflow has not yet
 * committed to a non-queued status. Prevents cross-cycle re-admission during the async
 * setup window between dispatch and the first status transition. */
const inFlightTasks = new Set<string>();

let pollTimeoutId: ReturnType<typeof setTimeout> | null = null;
let isProcessing = false;

/**
 * Check if we can process another task (concurrency limit check)
 */
async function canProcessTask(): Promise<boolean> {
  const runningCount = await getRunningTasksCount();
  return runningCount < engineConfig.maxConcurrentTasks;
}

/**
 * Process the queue - check for tasks and start execution if slots available.
 * Loops through queued tasks, skipping those that have exceeded maxYieldCount.
 */
async function processQueue(): Promise<void> {
  // Prevent concurrent processing
  if (isProcessing) {
    return;
  }

  isProcessing = true;

  try {
    await refreshEngineConfig();

    // Check if we can process more tasks
    if (!(await canProcessTask())) {
      return;
    }

    // Check if any agent is already running (legacy check for maxConcurrentTasks=1)
    if (engineConfig.maxConcurrentTasks <= 1 && isAgentRunning()) {
      return;
    }

    // Get all queued tasks
    const queuedTasks = await getQueuedTasks();
    if (queuedTasks.length === 0) {
      return;
    }

    // Dependency-aware re-prioritization: elevate tasks on the critical path
    const allTasks = await getAllTasks();
    const prioritizedTasks = prioritizeQueue(queuedTasks, allTasks);

    // Try each queued task until we find one we can start or run out of tasks
    for (const nextTask of prioritizedTasks) {
      // Re-check capacity before each task, including in-flight starts from this and prior cycles
      const runningCount = await getRunningTasksCount();
      if (runningCount + inFlightTasks.size >= engineConfig.maxConcurrentTasks) {
        break;
      }

      // Skip if workflow already running
      if (isWorkflowRunning(nextTask.id)) {
        continue;
      }

      // Skip if already dispatched in a prior poll cycle (cross-cycle re-admission guard)
      if (inFlightTasks.has(nextTask.id)) {
        continue;
      }

      // Skip tasks that are within their exponential backoff window
      if (Date.now() < (yieldUntil.get(nextTask.id) ?? 0)) {
        continue;
      }

      // Check yield count - transition tasks that have yielded too many times to todo
      // so they are visible on the board instead of silently starving in the queue.
      if (nextTask.yieldCount && nextTask.yieldCount >= engineConfig.maxYieldCount) {
        console.warn(`[QueueProcessor] Task ${nextTask.id} exceeded max yield count (${engineConfig.maxYieldCount}), transitioning to todo`);
        try {
          await updateTask(nextTask.id, {
            status: 'todo',
            yieldReason: 'cap-exceeded:max-yield-count',
          });
        } catch (err) {
          console.warn('[QueueProcessor] Failed to transition cap-exceeded task:', err instanceof Error ? err.message : 'Unknown error');
        }
        inFlightTasks.delete(nextTask.id);
        continue;
      }

      // Check retry count - transition tasks that have failed too many times to todo
      if ((nextTask.retryCount ?? 0) >= engineConfig.maxExecutionRetries) {
        console.warn(`[QueueProcessor] Task ${nextTask.id} exceeded max execution retries (${engineConfig.maxExecutionRetries}), transitioning to todo`);
        try {
          await updateTask(nextTask.id, {
            status: 'todo',
            yieldReason: 'cap-exceeded:max-execution-retries',
          });
        } catch (err) {
          console.warn('[QueueProcessor] Failed to transition cap-exceeded task:', err instanceof Error ? err.message : 'Unknown error');
        }
        inFlightTasks.delete(nextTask.id);
        continue;
      }

      // Detect the first exclusive file currently held by another task
      const exclusiveFiles = nextTask.declaredFiles?.exclusive ?? [];
      let conflictingFile: string | null = null;
      for (const filePath of exclusiveFiles) {
        if (wouldConflict(filePath, nextTask.id)) {
          conflictingFile = filePath;
          break;
        }
      }

      if (conflictingFile !== null) {
        // Compute and record exponential backoff
        const prevBackoff = yieldBackoffMs.get(nextTask.id) ?? (YIELD_BACKOFF_INITIAL_MS / YIELD_BACKOFF_MULTIPLIER);
        const nextBackoff = Math.min(prevBackoff * YIELD_BACKOFF_MULTIPLIER, YIELD_BACKOFF_MAX_MS);
        yieldBackoffMs.set(nextTask.id, nextBackoff);
        yieldUntil.set(nextTask.id, Date.now() + nextBackoff);

        // Track file→backoff mapping for targeted reset on LEASE_RELEASED
        const fileSet = fileBackoffTasks.get(conflictingFile) ?? new Set<string>();
        fileSet.add(nextTask.id);
        fileBackoffTasks.set(conflictingFile, fileSet);

        // Set firstBlockedAt fairness timestamp if not already set for this contention
        const now = new Date().toISOString();
        const updates: Record<string, unknown> = { yieldReason: `lease-conflict:${conflictingFile}` };
        if (!nextTask.firstBlockedAt) {
          updates.firstBlockedAt = now;
        }

        const reason = `lease-conflict:${conflictingFile}`;
        console.log(`[QueueProcessor] Task ${nextTask.id} yielding — ${reason} (backoff ${nextBackoff}ms)`);
        try {
          await updateTask(nextTask.id, updates);
        } catch (err) {
          console.warn('[QueueProcessor] Failed to persist yieldReason:', err instanceof Error ? err.message : 'Unknown error');
        }
        // Continue scanning — do not wait for next poll cycle
        continue;
      }

      console.log(`[QueueProcessor] Starting task ${nextTask.id}: ${nextTask.title}`);

      // Clear any stale backoff state for this task before dispatching
      clearTaskBackoff(nextTask.id);

      // Mark as in-flight synchronously before any await so the cross-cycle guard
      // is effective during the async setup window between dispatch and the first
      // non-queued status transition.
      inFlightTasks.add(nextTask.id);

      // Reload the task from the board immediately before routing so that
      // resumeFromStep reflects the persisted state, not the snapshot loaded
      // at the start of the poll cycle (which may be stale).
      const freshTask = await getTask(nextTask.id);

      // Check task type and execute appropriate workflow
      if (nextTask.type === 'quick') {
        console.log(`[QueueProcessor] Task ${nextTask.id} is a quick task - skipping brief/plan stages`);
        await executeQuickTask(nextTask.id);
      } else if (nextTask.type === 'goal') {
        console.log(`[QueueProcessor] Task ${nextTask.id} is a goal task - running architect decomposition`);
        await executeGoalWorkflow(nextTask.id);
      } else if (freshTask?.resumeFromStep === 'declare' || freshTask?.resumeFromStep === 'execute') {
        console.log(`[QueueProcessor] Task ${nextTask.id} resuming from ${freshTask.resumeFromStep} step (skipping brief/plan)`);
        await executeFromDeclare(nextTask.id);
      } else {
        await executeFullWorkflow(nextTask.id);
      }

      // For single-task mode, only start one task per poll cycle
      if (engineConfig.maxConcurrentTasks <= 1) {
        break;
      }
    }

  } catch (error) {
    const err = error as Error;
    console.error('[QueueProcessor] Error processing queue:', err.message);
  } finally {
    isProcessing = false;
  }
}

/**
 * Wake the queue processor immediately — bypasses the polling interval.
 * Called when a task completes or leases are released so queued tasks
 * can proceed without waiting for the next poll tick.
 */
export function wakeQueueProcessor(): void {
  if (!QUEUE_ENABLED || isProcessing) {
    return;
  }
  console.log('[QueueProcessor] Woken by event');
  void processQueue();
}

/**
 * Clear all in-memory backoff state for a single task. Called when the task
 * is dispatched (lease acquired) or when its backoff is reset via LEASE_RELEASED.
 */
function clearTaskBackoff(taskId: string): void {
  yieldBackoffMs.delete(taskId);
  yieldUntil.delete(taskId);

  // Remove from all fileBackoffTasks entries
  for (const [filePath, taskSet] of fileBackoffTasks.entries()) {
    taskSet.delete(taskId);
    if (taskSet.size === 0) {
      fileBackoffTasks.delete(filePath);
    }
  }

  // Clear firstBlockedAt on the persisted task so it doesn't carry over
  // to the next contention. Fire-and-forget — best-effort.
  updateTask(taskId, { firstBlockedAt: null }).catch(err =>
    console.warn('[QueueProcessor] Failed to clear firstBlockedAt:', err instanceof Error ? err.message : 'Unknown error')
  );
}

/**
 * Reset all backoff state for a task — exported for external callers (e.g.,
 * manual re-queue) that need to clear in-memory backoff in addition to the
 * persisted counters reset by store.queueTask().
 */
export function resetBackoff(taskId: string): void {
  clearTaskBackoff(taskId);
}

/**
 * Handle LEASE_RELEASED events: for each released file, clear the backoff
 * window of any task that was waiting on it, so the next poll/wake cycle
 * can immediately attempt re-dispatch instead of skipping the waiter due to
 * an unexpired yieldUntil.
 */
function handleLeaseReleased(_releasingTaskId: string, releasedFiles: string[]): void {
  if (!releasedFiles || releasedFiles.length === 0) return;

  let cleared = 0;
  for (const filePath of releasedFiles) {
    const waitingTasks = fileBackoffTasks.get(filePath);
    if (!waitingTasks || waitingTasks.size === 0) continue;

    for (const taskId of waitingTasks) {
      clearTaskBackoff(taskId);
      cleared++;
    }
    fileBackoffTasks.delete(filePath);
  }

  if (cleared > 0) {
    console.log(`[QueueProcessor] LEASE_RELEASED: cleared backoff for ${cleared} task(s) across ${releasedFiles.length} file(s)`);
  }

  // Wake the queue processor after clearing backoffs so blocked tasks get a chance
  wakeQueueProcessor();
}

function schedulePoll(): void {
  pollTimeoutId = setTimeout(async () => {
    await processQueue();
    if (pollTimeoutId !== null) {
      schedulePoll();
    }
  }, engineConfig.queuePollIntervalMs);
}

/**
 * Start the queue processor polling loop
 */
export function startQueueProcessor(): void {
  if (!QUEUE_ENABLED) {
    console.log('[QueueProcessor] Queue processing is disabled (QUEUE_ENABLED=false)');
    return;
  }

  if (pollTimeoutId !== null) {
    console.log('[QueueProcessor] Queue processor already running');
    return;
  }

  console.log(`[QueueProcessor] Starting queue processor (poll: ${engineConfig.queuePollIntervalMs}ms, max concurrent: ${engineConfig.maxConcurrentTasks})`);

  // Subscribe to internal wake events
  internalEvents.on(TASK_COMPLETED, wakeQueueProcessor);
  internalEvents.on(LEASE_RELEASED, handleLeaseReleased);

  // Run immediately on start
  processQueue();

  // Set up recursive polling
  schedulePoll();
}

/**
 * Stop the queue processor polling loop
 */
export function stopQueueProcessor(): void {
  if (pollTimeoutId !== null) {
    clearTimeout(pollTimeoutId);
    pollTimeoutId = null;

    // Unsubscribe internal wake event listeners
    internalEvents.off(TASK_COMPLETED, wakeQueueProcessor);
    internalEvents.off(LEASE_RELEASED, handleLeaseReleased);

    console.log('[QueueProcessor] Queue processor stopped');
  }
}

/**
 * Pause the queue processor (called by the kill switch after max retries).
 */
export function pauseQueueProcessor(): void {
  stopQueueProcessor();
  console.log('[QueueProcessor] Queue paused by kill switch');
}

/**
 * Check if queue processor is running
 */
export function isQueueProcessorRunning(): boolean {
  return pollTimeoutId !== null;
}

/**
 * Remove a task from the inFlightTasks set once its workflow has committed to a
 * non-queued status. Called by workflow.ts on every status-transition exit path
 * (including yield-back-to-queued, error, success, and stop) so no entries leak.
 */
export function removeInFlightTask(taskId: string): void {
  inFlightTasks.delete(taskId);
}

/**
 * Get queue processor configuration
 */
export function getQueueProcessorConfig(): {
  enabled: boolean;
  pollInterval: number;
  maxConcurrent: number;
  isRunning: boolean;
} {
  return {
    enabled: QUEUE_ENABLED,
    pollInterval: engineConfig.queuePollIntervalMs,
    maxConcurrent: engineConfig.maxConcurrentTasks,
    isRunning: isQueueProcessorRunning(),
  };
}

/**
 * Get the position of a task in the queue (1-indexed)
 * Returns 0 if the task is not in the queue
 */
export async function getQueuePosition(taskId: string): Promise<number> {
  const queuedTasks = await getQueuedTasks();
  const index = queuedTasks.findIndex(t => t.id === taskId);
  return index === -1 ? 0 : index + 1;
}

import { getQueuedTasks, getAllTasks, getTask, getRunningTasksCount, updateTask } from './store.js';
import { executeFullWorkflow, executeQuickTask, executeGoalWorkflow, executeFromDeclare, isWorkflowRunning } from './workflow.js';
import { isAgentRunning } from './runner.js';
import { wouldConflict } from './leaseManager.js';
import { internalEvents, TASK_COMPLETED, LEASE_RELEASED } from './internalEvents.js';
import { prioritizeQueue } from './prioritizer.js';
import { engineConfig, refreshEngineConfig } from './engineConfig.js';
import type { Task } from '../../types/index.js';

const QUEUE_ENABLED = process.env.QUEUE_ENABLED !== 'false';

const YIELD_BACKOFF_INITIAL_MS = 2000;
const YIELD_BACKOFF_MULTIPLIER = 2;
const YIELD_BACKOFF_MAX_MS = 60_000;

/** Per-task exponential backoff delay (ms) for the next retry after a lease conflict */
const yieldBackoffMs = new Map<string, number>();
/** Per-task earliest timestamp (ms) at which the task may be retried */
const yieldUntil = new Map<string, number>();
/** Maps filePath → Set<taskId> of tasks currently in backoff waiting for that file.
 *  Populated when a task yields with `lease-conflict:<filePath>`. Cleared when the
