        const prevBackoff = yieldBackoffMs.get(nextTask.id) ?? (YIELD_BACKOFF_INITIAL_MS / YIELD_BACKOFF_MULTIPLIER);
        const nextBackoff = Math.min(prevBackoff * YIELD_BACKOFF_MULTIPLIER, YIELD_BACKOFF_MAX_MS);
