        fileSet.add(nextTask.id);
        fileBackoffTasks.set(conflictingFile, fileSet);

        // Set firstBlockedAt fairness timestamp if not already set for this contention
        const now = new Date().toISOString();
        const updates: Record<string, unknown> = { yieldReason: `lease-conflict:${conflictingFile}` };
        if (!nextTask.firstBlockedAt) {
          updates.firstBlockedAt = now;
        }

        const reason = `lease-conflict:${conflictingFile}`;
        console.log(`[QueueProcessor] Task ${nextTask.id} yielding — ${reason} (backoff ${nextBackoff}ms)`);
        try {
          await updateTask(nextTask.id, updates);
        } catch (err) {
          console.warn('[QueueProcessor] Failed to persist yieldReason:', err instanceof Error ? err.message : 'Unknown error');
        }
        // Continue scanning — do not wait for next poll cycle
        continue;
      }

      console.log(`[QueueProcessor] Starting task ${nextTask.id}: ${nextTask.title}`);

      // Clear any stale backoff state for this task before dispatching
      clearTaskBackoff(nextTask.id);

      // Mark as in-flight synchronously before any await so the cross-cycle guard
      // is effective during the async setup window between dispatch and the first
      // non-queued status transition.
      inFlightTasks.add(nextTask.id);

      // Reload the task from the board immediately before routing so that
      // resumeFromStep reflects the persisted state, not the snapshot loaded
      // at the start of the poll cycle (which may be stale).
      const freshTask = await getTask(nextTask.id);

      // Check task type and execute appropriate workflow
      if (nextTask.type === 'quick') {
        console.log(`[QueueProcessor] Task ${nextTask.id} is a quick task - skipping brief/plan stages`);
        await executeQuickTask(nextTask.id);
      } else if (nextTask.type === 'goal') {
        console.log(`[QueueProcessor] Task ${nextTask.id} is a goal task - running architect decomposition`);
        await executeGoalWorkflow(nextTask.id);
      } else if (freshTask?.resumeFromStep === 'declare' || freshTask?.resumeFromStep === 'execute') {
        console.log(`[QueueProcessor] Task ${nextTask.id} resuming from ${freshTask.resumeFromStep} step (skipping brief/plan)`);
        await executeFromDeclare(nextTask.id);
      } else {
        await executeFullWorkflow(nextTask.id);
      }

      // For single-task mode, only start one task per poll cycle
      if (engineConfig.maxConcurrentTasks <= 1) {
        break;
      }
    }

  } catch (error) {
    const err = error as Error;
    console.error('[QueueProcessor] Error processing queue:', err.message);
  } finally {
    isProcessing = false;
  }
}

